    @staticmethod
    def alpha_factorminer_vn_003_wf(df, window=10, winsor_pct=0.1):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        mid = close.rolling(window).mean()
        std = close.rolling(window).std()
        bol_range = (close - mid) / (2 * std + 1e-9)
        ts_mad = (volume - volume.rolling(window).mean()).abs().rolling(window).mean()
        raw = bol_range / (ts_mad + 1e-9)
        # Winsorized Fisher normalization
        low = raw.rolling(window).quantile(winsor_pct)
        high = raw.rolling(window).quantile(1 - winsor_pct)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        signal = normalized.fillna(0).replace([np.inf, -np.inf], 0)
        return signal

    @staticmethod
    def alpha_factorminer_vn_004_rank(df, window_1=3, window_2=30):
        close = df['close']
        volume = df['matchingVolume']
        ret = close.pct_change()
        # Co-skewness: third central moment of ret scaled by volume
        # Simplified: ret^3 * volume, then rolling mean and normalize
        ret_cube_vol = (ret ** 3) * volume
        raw = ret_cube_vol.rolling(window_1).sum()
        # Neutralize by subtracting rolling mean (Neutralize via cross-sectional? use rolling mean as proxy)
        neutral = raw - raw.rolling(window_2).mean()
        # Negate
        result = -neutral
        # Normalize: Rolling Rank (A)
        norm = (result.rolling(window_2).rank(pct=True) * 2) - 1
        return -norm.ffill().fillna(0)

    @staticmethod
    def alpha_factorminer_vn_004_tanh(df, window_1=1, window_2=10):
        close = df['close']
        volume = df['matchingVolume']
        ret = close.pct_change()
        ret_cube_vol = (ret ** 3) * volume
        raw = ret_cube_vol.rolling(window_1).sum()
        neutral = raw - raw.rolling(window_2).mean()
        result = -neutral
        # Normalize: Dynamic Tanh (B)
        std = result.rolling(window_2).std().replace(0, np.nan)
        norm = np.tanh(result / std)
        return -norm.ffill().fillna(0)

    @staticmethod
    def alpha_factorminer_vn_004_zscore(df, window_1=1, window_2=100):
        close = df['close']
        volume = df['matchingVolume']
        ret = close.pct_change()
        ret_cube_vol = (ret ** 3) * volume
        raw = ret_cube_vol.rolling(window_1).sum()
        neutral = raw - raw.rolling(window_2).mean()
        result = -neutral
        # Normalize: Rolling Z-Score/Clip (C)
        mean = result.rolling(window_2).mean()
        std = result.rolling(window_2).std().replace(0, np.nan)
        norm = ((result - mean) / std).clip(-1, 1)
        return -norm.ffill().fillna(0)

    @staticmethod
    def alpha_factorminer_vn_004_sign(df, window_1=3, window_2=10):
        close = df['close']
        volume = df['matchingVolume']
        ret = close.pct_change()
        ret_cube_vol = (ret ** 3) * volume
        raw = ret_cube_vol.rolling(window_1).sum()
        neutral = raw - raw.rolling(window_2).mean()
        result = -neutral
        # Normalize: Sign/Binary Soft (D)
        norm = np.sign(result)
        return -pd.Series(norm, index=df.index).ffill().fillna(0)

    @staticmethod
    def alpha_factorminer_vn_004_wf(df, window_1=3, window_2=70, percentile=0.05):
        close = df['close']
        volume = df['matchingVolume']
        ret = close.pct_change()
        ret_cube_vol = (ret ** 3) * volume
        raw = ret_cube_vol.rolling(window_1).sum()
        neutral = raw - raw.rolling(window_2).mean()
        result = -neutral
        # Normalize: Winsorized Fisher (E)
        p1 = percentile
        p2 = window_2
        low = result.rolling(p2).quantile(p1)
        high = result.rolling(p2).quantile(1 - p1)
        winsorized = result.clip(lower=low, upper=high, axis=0)
        fisher_input = ((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99
        fisher_input = fisher_input.clip(-0.99, 0.99)
        norm = np.arctanh(fisher_input)
        return -norm.ffill().fillna(0)

    @staticmethod
    def alpha_factorminer_vn_005_rank(df, window=80):
        ret = df['close'].pct_change()
        raw = -(ret.mul(ret.ge(0).map({True: 1, False: -1}), axis=0).rolling(window).mean() - ret.mul(ret.ge(0).map({True: 1, False: -1}), axis=0).rolling(window).mean().rolling(window).mean()) / ret.mul(ret.ge(0).map({True: 1, False: -1}), axis=0).rolling(window).std()
        raw = raw.fillna(0).replace([np.inf, -np.inf], 0)
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        return signal

