    @staticmethod
    def alpha_factorminer_vn_006_6(df, window=80, delta_period=2):
        delta = df['close'].diff(delta_period)
        quantile = delta.rolling(window).rank(pct=True)
        raw = -(quantile - 0.5)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_006_rank(df, window=70, delta=2):
        close_price = df['close']
        delta_close = close_price.diff(delta)
        rolling_rank = delta_close.rolling(window).rank(pct=True, ascending=False)
        raw = 0.5 - rolling_rank
        normalized = (raw * 2) - 1
        return normalized.fillna(0)

