    @staticmethod
    def alpha_factorminer_vn_007_rank(df, window=90, sub_window=10):
        # Step 1: Calculate residual of close vs vwap using rolling linear regression (window=23)
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        x = pd.Series(np.arange(len(df)), index=df.index)
        # Calculate slopes and intercepts directly via vectorized rolling cov/var
        # Regression: close ~ vwap
        # Use rolling covariance and variance
        cov = df['close'].rolling(window).cov(vwap) 
        var = vwap.rolling(window).var().replace(0, np.nan)
        slope = cov / var
        intercept = df['close'].rolling(window).mean() - slope * vwap.rolling(window).mean()
        resid = df['close'] - (intercept + slope * vwap)
        # Step 2: Calculate slope of resid over sub_window days
        x2 = pd.Series(np.arange(len(df)), index=df.index)
        cov_resid = resid.rolling(sub_window).cov(x2)
        var_x2 = x2.rolling(sub_window).var().replace(0, np.nan)
        slope_resid = cov_resid / var_x2
        # Original formula applies negation: Neg(...)
        raw = -slope_resid
        # Normalize using Rolling Rank (Case A) - suitable for residual-based signals
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_007_tanh(df, window=90, sub_window=7):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        cov = df['close'].rolling(window).cov(vwap)
        var = vwap.rolling(window).var().replace(0, np.nan)
        slope = cov / var
        intercept = df['close'].rolling(window).mean() - slope * vwap.rolling(window).mean()
        resid = df['close'] - (intercept + slope * vwap)
        x2 = pd.Series(np.arange(len(df)), index=df.index)
        cov_resid = resid.rolling(sub_window).cov(x2)
        var_x2 = x2.rolling(sub_window).var().replace(0, np.nan)
        slope_resid = cov_resid / var_x2
        raw = -slope_resid
        # Normalize using Dynamic Tanh (Case B) - keep magnitude
        normalized = np.tanh(raw / raw.rolling(window).std().replace(0, np.nan))
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_007_zscore(df, window=90, sub_window=7):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        cov = df['close'].rolling(window).cov(vwap)
        var = vwap.rolling(window).var().replace(0, np.nan)
        slope = cov / var
        intercept = df['close'].rolling(window).mean() - slope * vwap.rolling(window).mean()
        resid = df['close'] - (intercept + slope * vwap)
        x2 = pd.Series(np.arange(len(df)), index=df.index)
        cov_resid = resid.rolling(sub_window).cov(x2)
        var_x2 = x2.rolling(sub_window).var().replace(0, np.nan)
        slope_resid = cov_resid / var_x2
        raw = -slope_resid
        # Rolling Z-Score / Clip (Case C) - for spread-like signal
        mu = raw.rolling(window).mean()
        sigma = raw.rolling(window).std().replace(0, np.nan)
        zscore = (raw - mu) / sigma
        normalized = zscore.clip(-1, 1)
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_007_sign(df, window=80, sub_window=7):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        cov = df['close'].rolling(window).cov(vwap)
        var = vwap.rolling(window).var().replace(0, np.nan)
        slope = cov / var
        intercept = df['close'].rolling(window).mean() - slope * vwap.rolling(window).mean()
        resid = df['close'] - (intercept + slope * vwap)
        x2 = pd.Series(np.arange(len(df)), index=df.index)
        cov_resid = resid.rolling(sub_window).cov(x2)
        var_x2 = x2.rolling(sub_window).var().replace(0, np.nan)
        slope_resid = cov_resid / var_x2
        raw = -slope_resid
        # Sign/Binary Soft (Case D) - for trend following
        normalized = np.sign(raw)
        return -pd.Series(normalized, index=df.index).fillna(0)

    @staticmethod
    def alpha_factorminer_vn_007_wf(df, window=80, sub_window=10, p1=0.05, p2=63):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        cov = df['close'].rolling(window).cov(vwap)
        var = vwap.rolling(window).var().replace(0, np.nan)
        slope = cov / var
        intercept = df['close'].rolling(window).mean() - slope * vwap.rolling(window).mean()
        resid = df['close'] - (intercept + slope * vwap)
        x2 = pd.Series(np.arange(len(df)), index=df.index)
        cov_resid = resid.rolling(sub_window).cov(x2)
        var_x2 = x2.rolling(sub_window).var().replace(0, np.nan)
        slope_resid = cov_resid / var_x2
        raw = -slope_resid
        # Winsorized Fisher (Case E) with hardcoded p1=0.05, p2=63
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_008_rank(df, window_1=20, window_2=30):
        close = df['close']
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        ret = df['close'].pct_change()
        days = np.arange(len(df))
        # RegResi: residual of close regressed on vwap over window_1
        cov_c_v = close.rolling(window_1).cov(vwap)
        var_v = vwap.rolling(window_1).var().replace(0, np.nan)
        beta_resi = cov_c_v / var_v
        resi = close - beta_resi * vwap
        # RegBeta: beta of resi regressed on returns over window_2
        cov_r_ret = resi.rolling(window_2).cov(ret)
        var_ret = ret.rolling(window_2).var().replace(0, np.nan)
        beta_final = cov_r_ret / var_ret
        # CsZScore: cross-sectional z-score within rolling window
        roll_mean = beta_final.rolling(window_2).mean()
        roll_std = beta_final.rolling(window_2).std().replace(0, np.nan)
        zscore = (beta_final - roll_mean) / roll_std
        # Neg(Neg(...)) => positive
        raw = -(-zscore)
        # Normalization: Rolling Rank
        signal = (raw.rolling(window_2).rank(pct=True) * 2) - 1
        signal = signal.ffill().fillna(0)
        return -signal

