    @staticmethod
    def alpha_factorminer_vn_016_rank(df, window=31):
        returns = df['close'].pct_change()
        sorted_rets = returns.rolling(window).apply(lambda x: np.sort(x), raw=True)
        quantile_idx = max(1, int(window * 0.05))
        var = sorted_rets.apply(lambda x: x[quantile_idx] if len(x) == window else np.nan)
        signal = np.where(var > 0, df['matchingVolume'], -df['matchingVolume'])
        signal = pd.Series(signal, index=df.index)
        normalized = (signal.rolling(window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

