    @staticmethod
    def alpha_factorminer_vn_019_rank(df, window=100):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        high = df['high']
        low = df['low']
        close = df['close']
        tr = pd.concat([high - low, (high - close.shift()).abs(), (low - close.shift()).abs()], axis=1).max(axis=1)
        atr = tr.rolling(window=11).mean()
        atr = atr.replace(0, np.nan).ffill()
        entropy = -((vwap / vwap.rolling(window).sum()) * np.log(vwap / vwap.rolling(window).sum() + 1e-9)).rolling(window).sum()
        raw = entropy / atr
        zscore = (raw - raw.rolling(window).mean()) / raw.rolling(window).std()
        raw = -zscore
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

