    @staticmethod
    def alpha_factorminer_vn_020_wf(df, window=60, winsor_quantile=0.9):
        amount = df.get('amount', df['close'] * df['matchingVolume'])
        skew = amount.rolling(window).skew()
        raw = -skew
        low = raw.rolling(window).quantile(winsor_quantile)
        high = raw.rolling(window).quantile(1 - winsor_quantile)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        ratio = ((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99
        ratio = ratio.clip(-0.99, 0.99)
        signal = np.arctanh(ratio)
        return -signal.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_021_rank(df, window_1=90, window_2=7):
        # Step 1: Compute residual of volume regressed on close
        x = df['close']
        y = df['matchingVolume']
        # Beta for residual regression: slope of x on y? Actually RegResi(volume, close): residual from volume ~ close
        # Use rolling covariance
        y_mean = y.rolling(window_1).mean()
        x_mean = x.rolling(window_1).mean()
        cov = (y * x).rolling(window_1).mean() - y_mean * x_mean
        var_x = (x ** 2).rolling(window_1).mean() - x_mean ** 2
        beta = cov / var_x.replace(0, np.nan)
        residual = y - beta * x
        # Step 2: Compute beta of residual on returns
        ret = df['close'].pct_change()
        ret_mean = ret.rolling(window_2).mean()
        res_mean = residual.rolling(window_2).mean()
        cov2 = (residual * ret).rolling(window_2).mean() - res_mean * ret_mean
        var_ret = (ret ** 2).rolling(window_2).mean() - ret_mean ** 2
        reg_beta = cov2 / var_ret.replace(0, np.nan)
        raw = -reg_beta
        # Normalize: Rolling Rank
        rank_result = raw.rolling(window_2).rank(pct=True) * 2 - 1
        result = rank_result.fillna(0)
        return -result

