    @staticmethod
    def alpha_factorminer_vn_023_rank(df, window=15):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        days = pd.Series(np.arange(len(df)), index=df.index)
        slope = vwap.rolling(window).cov(days) / days.rolling(window).var().replace(0, np.nan)
        intercept = vwap.rolling(window).mean() - slope * days.rolling(window).mean()
        resid = vwap - (intercept + slope * days)
        raw = -resid.fillna(0)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

