        corr = cross.rolling(window).corr(log_ret)
        co_skew = corr ** 3
        raw = -co_skew
        # Dynamic Tanh
        std = raw.rolling(window).std().replace(0, np.nan)
        result = np.tanh(raw / std).fillna(0)
        return -pd.Series(result, index=df.index)

