    @staticmethod
    def alpha_factorminer_vn_025_wf(df, window=60, factor=0.7):
        close = df['close']
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        log_ret = np.log(close / close.shift(1))
        cross = (amount - amount.shift(1)) / amount.shift(1).replace(0, np.nan)
        corr = cross.rolling(window).corr(log_ret)
        co_skew = corr ** 3
        raw = -co_skew
        # Winsorized Fisher
        p1 = factor
        p2 = window
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        denom = (high - low).replace(0, np.nan)
        scaled = (winsorized - low) / (denom + 1e-9)
        normalized = np.arctanh(scaled * 1.98 - 0.99)
        result = normalized.fillna(0)
        return -pd.Series(result, index=df.index)

    @staticmethod
    def alpha_factorminer_vn_026_k(df, window_29=70, window_13=7):
        volume = df['matchingVolume'] if 'matchingVolume' in df.columns else df.get('volume', 1)
        rolling_mean_29 = volume.rolling(window_29).mean()
        rolling_std_29 = volume.rolling(window_29).std().replace(0, np.nan)
        robust_z_volume = (volume - rolling_mean_29) / rolling_std_29
        days = pd.Series(np.arange(len(df)), index=df.index)
        slope = robust_z_volume.rolling(window_13).cov(days) / days.rolling(window_13).var().replace(0, np.nan)
        neg_slope = -slope
        raw = neg_slope
        param = window_13
        normalized = (raw.rolling(param).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

