    @staticmethod
    def alpha_factorminer_vn_029_rank(df, window=65):
        amt = df.get('amount', df['close'] * df['matchingVolume'])
        rolling_min = amt.rolling(window, min_periods=1).min()
        range_amt = amt.rolling(window, min_periods=1).max() - rolling_min
        range_amt = range_amt.replace(0, np.nan)
        daily_dd = (amt - rolling_min) / range_amt
        dd_sq_sum = (daily_dd ** 2).rolling(window, min_periods=1).sum()
        ulcer_index = np.sqrt(dd_sq_sum / window)
        ts_max = amt.rolling(window, min_periods=1).max()
        div_val = ulcer_index / ts_max.replace(0, np.nan)
        neg_val = -div_val
        raw_rank = neg_val.rolling(window).rank(pct=True)
        signal = (raw_rank * 2) - 1
        signal = signal.ffill().fillna(0)
        return signal

