    @staticmethod
    def alpha_factorminer_vn_037_rank(df, window=20):
        raw = df['close'].pct_change().fillna(0)
        robust_z = (raw - raw.rolling(17).median()) / (raw.rolling(17).mad().replace(0, np.nan))
        x = pd.Series(np.arange(len(df)), index=df.index)
        slope = - (robust_z.rolling(11).cov(x) / x.rolling(11).var().replace(0, np.nan))
        signal = (slope.rolling(window).rank(pct=True) * 2) - 1
        return signal.fillna(0)

