    @staticmethod
    def alpha_factorminer_vn_043_rank(df, window=5):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        hma_length = 13
        # HMA calculation
        half_length = int(hma_length / 2)
        sqrt_length = int(np.sqrt(hma_length))
        wma_half = vwap.rolling(half_length).apply(lambda x: np.average(x, weights=np.arange(1, len(x)+1)), raw=True)
        wma_full = vwap.rolling(hma_length).apply(lambda x: np.average(x, weights=np.arange(1, len(x)+1)), raw=True)
        hma_raw = 2 * wma_half - wma_full
        hma = hma_raw.rolling(sqrt_length).apply(lambda x: np.average(x, weights=np.arange(1, len(x)+1)), raw=True)
        # Regression residual
        reg_length = 31
        x_reg = pd.Series(np.arange(reg_length), index=df.index[:reg_length].repeat(reg_length)[:reg_length] if len(df) >= reg_length else df.index[:reg_length])
        # Use vectorized covariance for slope
        days = np.arange(len(df))
        x_series = pd.Series(days, index=df.index)
        slope_reg = vwap.rolling(reg_length).cov(x_series) / x_series.rolling(reg_length).var().replace(0, np.nan)
        intercept_reg = vwap.rolling(reg_length).mean() - slope_reg * x_series.rolling(reg_length).mean()
        fitted_reg = slope_reg * x_series + intercept_reg
        resi = vwap - fitted_reg
        # TsLinRegSlope of resi
        x_slope = pd.Series(np.arange(len(df)), index=df.index)
        slope = resi.rolling(window).cov(x_slope) / x_slope.rolling(window).var().replace(0, np.nan)
        raw = -slope
        # Normalize A: Rolling Rank
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        result = normalized.ffill().fillna(0)
        return -result

    @staticmethod
    def alpha_factorminer_vn_043_tanh(df, window=5):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
