    @staticmethod
    def alpha_factorminer_vn_043_zscore(df, window=5):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        hma_length = 13
        half_length = int(hma_length / 2)
        sqrt_length = int(np.sqrt(hma_length))
