        hma = hma_raw.rolling(sqrt_length).apply(lambda x: np.average(x, weights=np.arange(1, len(x)+1)), raw=True)
        reg_length = 31
        days = np.arange(len(df))
        x_series = pd.Series(days, index=df.index)
        slope_reg = vwap.rolling(reg_length).cov(x_series) / x_series.rolling(reg_length).var().replace(0, np.nan)
        intercept_reg = vwap.rolling(reg_length).mean() - slope_reg * x_series.rolling(reg_length).mean()
        fitted_reg = slope_reg * x_series + intercept_reg
        resi = vwap - fitted_reg
        x_slope = pd.Series(np.arange(len(df)), index=df.index)
