    @staticmethod
    def alpha_factorminer_vn_046_rank(df, window=10, period=60):
        close = df['close'].values
        vol = df.get('matchingVolume', df.get('volume', 1)).values
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3).values
        ret = df['close'].pct_change().values
        ret[0] = 0.0
        n = len(df)
        # CoKurtosis: E[(x-mu)^3(y-mu)] / (sigma_x^3 sigma_y)
        close_mean = pd.Series(close).rolling(window=period, min_periods=period).mean().values
        close_std = pd.Series(close).rolling(window=period, min_periods=period).std().values
        ret_mean = pd.Series(ret).rolling(window=period, min_periods=period).mean().values
        ret_std = pd.Series(ret).rolling(window=period, min_periods=period).std().values
        # CoKurtosis denominator: sigma_close^3 * sigma_ret
        denom = (close_std ** 3) * ret_std
        denom = np.where(denom == 0, np.nan, denom)
        # Cross-moment: E[(close - mu_close)^3 * (ret - mu_ret)]
        cross_moment = pd.Series((close - close_mean) ** 3 * (ret - ret_mean)).rolling(window=period, min_periods=period).mean().values
        cokurt = cross_moment / denom
        cokurt = np.nan_to_num(cokurt, nan=0.0, posinf=0.0, neginf=0.0)
        # Multiply by volume
        raw_ts = vol * cokurt
        # Correlation with vwap
        corr = pd.Series(raw_ts).rolling(window=window, min_periods=window).corr(pd.Series(vwap)).values
        corr = np.nan_to_num(corr, nan=0.0, posinf=0.0, neginf=0.0)
        # Negate
        raw = -corr
        # Normalization: Z-score rolling (Type C)
        norm = ((raw - pd.Series(raw).rolling(window).mean()) / pd.Series(raw).rolling(window).std()).fillna(0).clip(-1, 1).values
        return -pd.Series(norm, index=df.index)

    @staticmethod
    def alpha_factorminer_vn_046_tanh(df, window=5, period=40):
        close = df['close'].values
        vol = df.get('matchingVolume', df.get('volume', 1)).values
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3).values
