        corr = np.nan_to_num(corr, nan=0.0, posinf=0.0, neginf=0.0)
        raw = -corr
        # Normalization: Dynamic Tanh (Type B)
        std = pd.Series(raw).rolling(window).std().replace(0, np.nan).fillna(1).values
        norm = np.tanh(raw / std)
        return -pd.Series(norm, index=df.index)

