    @staticmethod
    def alpha_factorminer_vn_048_wf(df, window=70, sub_window=3, p1=0.05):
        # Input: close, window=31, sub_window=7, p1 fixed hardcode
        close = df['close']
        ema1 = close.ewm(span=13, adjust=False).mean()
        ema2 = ema1.ewm(span=13, adjust=False).mean()
        dema = 2 * ema1 - ema2
        cross = close.rolling(window).cov(dema)
        var_dema = dema.rolling(window).var().replace(0, np.nan)
        slope = cross / var_dema
        intercept = close.rolling(window).mean() - slope * dema.rolling(window).mean()
        residual = close - (slope * dema + intercept)
        days = pd.Series(np.arange(len(df)), index=df.index)
        cov_res = residual.rolling(sub_window).cov(days)
        var_days = days.rolling(sub_window).var().replace(0, np.nan)
        ts_slope = cov_res / var_days
        raw = -ts_slope
        # Normalization: Winsorized Fisher (Case E) - xử lý heavy tails
        p1 = 0.05  # hardcoded
        p2 = max(window, sub_window) * 2  # rolling window cho winsorize
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        scaled = ((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99
        norm = np.arctanh(np.clip(scaled, -0.99, 0.99))
        return -norm.fillna(0).clip(-1, 1)

