    @staticmethod
    def alpha_factorminer_vn_052_wf(df, window=20, quantile_param=0.3):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        returns = df['close'].pct_change()
        vwap_mean = vwap.rolling(window).mean()
        count = (vwap > vwap_mean).rolling(window).sum()
        raw = -1 * np.where(returns > 0, count, -count)
        raw = pd.Series(raw, index=df.index).fillna(0)
        # Winsorized Fisher normalization E
        p1 = quantile_param
        p2 = window
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_053_rank(df, window=3, kurt_window=80):
        volume = df['matchingVolume']
        close = df['close']
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        kurt = close.rolling(kurt_window).kurt()
        product = volume * kurt
        corr = product.rolling(window).corr(vwap)
        neg_corr = -corr
        raw = -neg_corr
        raw = raw.replace([np.inf, -np.inf], np.nan).ffill().fillna(0)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized

