    @staticmethod
    def alpha_factorminer_vn_054_rank(df, window=100):
        volume = df.get('matchingVolume', df.get('volume', 0))
        amount = df.get('amount', df['close'] * volume)
        returns = df['close'].pct_change()
        sum_amt = amount.rolling(window).sum()
