    @staticmethod
    def alpha_factorminer_vn_062_wf(df, window=60, winsor_quantile=0.3):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        volume = df.get('matchingVolume', df.get('volume', 1))
        entropy_ratio = (vwap / vwap.rolling(window).sum()).replace(0, np.nan)
