    @staticmethod
    def alpha_factorminer_vn_070_e(df, window=85):
        vol = df.get('matchingVolume', df.get('volume', 1))
        close = df['close']
        half_len = 11 // 2
        sqrt_len = int(np.sqrt(11))
        wma_half = vol.rolling(half_len).apply(lambda x: np.sum(x * np.arange(1, len(x)+1)) / np.sum(np.arange(1, len(x)+1)), raw=True)
        wma_full = vol.rolling(11).apply(lambda x: np.sum(x * np.arange(1, len(x)+1)) / np.sum(np.arange(1, len(x)+1)), raw=True)
        raw_hma = 2 * wma_half - wma_full
        hma_vol = raw_hma.rolling(sqrt_len).apply(lambda x: np.sum(x * np.arange(1, len(x)+1)) / np.sum(np.arange(1, len(x)+1)), raw=True)
        er = abs(vol.diff(10)) / vol.diff().abs().rolling(10).sum().replace(0, np.nan)
        sc = (er * (2.0/(11+1) - 2.0/(30+1)) + 2.0/(30+1)) ** 2
        kama_vol = vol.copy()
        for i in range(11, len(vol)):
            kama_vol.iloc[i] = kama_vol.iloc[i-1] + sc.iloc[i] * (vol.iloc[i] - kama_vol.iloc[i-1])
        x = kama_vol
        y = hma_vol
        cov_xy = y.rolling(7).cov(x)
        var_x = x.rolling(7).var().replace(0, np.nan)
        slope = cov_xy / var_x
        intercept = y.rolling(7).mean() - slope * x.rolling(7).mean()
        residual = y - (slope * x + intercept)
        raw_signal = -residual
        norm_signal = ((raw_signal - raw_signal.rolling(window).mean()) / raw_signal.rolling(window).std().replace(0, np.nan)).clip(-1, 1)
        norm_signal = norm_signal.fillna(0)
        return -norm_signal

