    @staticmethod
    def alpha_factorminer_vn_072_rank(df, roll_rank=5):
        high = df['high']
        ema_short = high.ewm(span=7, adjust=False).mean()
        ema_long = high.ewm(span=19, adjust=False).mean()
        macd = ema_short - ema_long
        pop_mean = macd.rolling(roll_rank).mean()
        pop_std = macd.rolling(roll_rank).std()
        zscore = (macd - pop_mean) / pop_std.replace(0, np.nan)
        zscore = zscore.ffill().fillna(0)
        ranked = zscore.rolling(roll_rank).rank(pct=True)
        raw = -(ranked * 2 - 1)
        return -raw

