    @staticmethod
    def alpha_factorminer_vn_085_rank(df, window_rank=30):
        ret = df['close'].pct_change()
        returns = ret.fillna(0)
        log_ret = np.log(1 + returns)
        hma_len = 11
        half_len = hma_len // 2
        sqrt_len = int(np.sqrt(hma_len))
        wma_half = log_ret.rolling(half_len).apply(lambda x: np.sum(x * np.arange(1, half_len + 1)) / np.sum(np.arange(1, half_len + 1)), raw=True)
        wma_full = log_ret.rolling(hma_len).apply(lambda x: np.sum(x * np.arange(1, hma_len + 1)) / np.sum(np.arange(1, hma_len + 1)), raw=True)
        hma_values = 2 * wma_half - wma_full
        hma = hma_values.rolling(sqrt_len).apply(lambda x: np.sum(x * np.arange(1, sqrt_len + 1)) / np.sum(np.arange(1, sqrt_len + 1)), raw=True)
        resid = log_ret - hma
        linreg_len = 17
        slope = resid.rolling(linreg_len).apply(lambda x: np.polyfit(np.arange(len(x)), x, 1)[0], raw=True)
        neg_slope = -slope
        window = 7
        neg_slope_neg = -neg_slope.rolling(window).apply(lambda x: np.polyfit(np.arange(len(x)), x, 1)[0], raw=True)
        raw_signal = neg_slope_neg
        signal = (raw_signal.rolling(window_rank).rank(pct=True) * 2) - 1
        return signal.fillna(0)

