    @staticmethod
    def alpha_factorminer_vn_089_k(df, window=10):
        ret = df['close'].pct_change()
        # UlcerIndex = sqrt(mean(square(drawdown))), drawdown = (close - rolling_max) / rolling_max
        rolling_max = df['close'].rolling(window).max()
        dd = (df['close'] - rolling_max) / rolling_max
        ulcer = (dd ** 2).rolling(window).mean().apply(np.sqrt)
        mean_ulcer = ulcer.rolling(window).mean()
        condition = ulcer > mean_ulcer
        # CsZScore = (ret - ret.rolling(window).mean()) / ret.rolling(window).std()
        zscore = (ret - ret.rolling(window).mean()) / ret.rolling(window).std()
        signal = pd.Series(np.where(condition, zscore, -zscore), index=df.index)
        return (signal.rolling(window).rank(pct=True) * 2) - 1

