    @staticmethod
    def alpha_factorminer_vn_093_r(df, window=100, p1=0.1, p2=30):
        if 'vwap' in df.columns:
            vwap = df['vwap']
        else:
            vwap = (df['high'] + df['low'] + df['close']) / 3
        volume = df['matchingVolume']
        returns = df['close'].pct_change().fillna(0)
        mean_vwap = vwap.rolling(window).mean()
        std_vwap = vwap.rolling(window).std().replace(0, 1e-9)
        mean_vol = volume.rolling(window).mean()
        std_vol = volume.rolling(window).std().replace(0, 1e-9)
        z_vwap = ((vwap - mean_vwap) / std_vwap).fillna(0)
        z_vol = ((volume - mean_vol) / std_vol).fillna(0)
        cokurt = (z_vwap**3 * z_vol).rolling(window).mean() / (std_vwap * std_vol + 1e-9)
        condition = cokurt > 0
        raw_signal = pd.Series(np.where(condition, returns, -returns), index=df.index)
        final = -raw_signal
        low = final.rolling(p2).quantile(p1)
        high = final.rolling(p2).quantile(1 - p1)
        winsorized = final.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return normalized.fillna(0).replace([np.inf, -np.inf], 0).clip(-1, 1)

    @staticmethod
    def alpha_factorminer_vn_094_rank(df, window=60, sub_window=3):
        close = df['close']
