        pct_change = ts_mad.diff(sub_window) / ts_mad.shift(sub_window).replace(0, np.nan)
        pct_change = pct_change.fillna(0)
        raw = -pct_change
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

