    @staticmethod
    def alpha_factorminer_vn_095_rank(df, window=5):
        # Step 1: Compute raw value: -(-(CsZScore(Div(Prod(Sub(high, low), 5), TsMax(Sub(high, low), 5)))))
        #        => CsZScore( (high-low)*5 / rolling_max(high-low, 5) )
        # Simplify: raw = (high - low) * 5 / rolling_max(high - low, 5)
        hi = df['high']
        lo = df['low']
        hl_range = (hi - lo)
        max_hl = hl_range.rolling(window, min_periods=1).max()
        # avoid div by zero
        raw = hl_range * 5.0 / max_hl.replace(0, np.nan)
        # Step 2: CsZScore = (raw - rolling_mean) / rolling_std, then neg twice => just zscore
        mean_hl = raw.rolling(window, min_periods=1).mean()
        std_hl = raw.rolling(window, min_periods=1).std().fillna(1e-9)
        signal = (raw - mean_hl) / std_hl
        # Step 3: Normalization C: Rolling Z-score Clip [-1,1]
        norm_signal = ((signal - signal.rolling(window).mean()) / signal.rolling(window).std()).clip(-1, 1)
        norm_signal = norm_signal.ffill().fillna(0)
        return -norm_signal

