    @staticmethod
    def alpha_factorminer_vn_095_wf(df, window=90, quantile=0.9):
        hi = df['high']
        lo = df['low']
        hl_range = (hi - lo)
        max_hl = hl_range.rolling(window, min_periods=1).max()
        raw = hl_range * 5.0 / max_hl.replace(0, np.nan)
        mean_hl = raw.rolling(window, min_periods=1).mean()
        std_hl = raw.rolling(window, min_periods=1).std().fillna(1e-9)
        signal = (raw - mean_hl) / std_hl
        # Winsorized Fisher Transform
        low = signal.rolling(window).quantile(quantile)
        high = signal.rolling(window).quantile(1 - quantile)
        clipped_signal = signal.clip(lower=low, upper=high, axis=0)
        norm_signal = np.arctanh(((clipped_signal - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        norm_signal = norm_signal.ffill().fillna(0)
        return -norm_signal

