    @staticmethod
    def alpha_factorminer_vn_100_rank(df, window=50, rank_window=10):
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        returns = df['close'].pct_change()
        kurt = amt.rolling(window).kurt()
        # raw = - (kurt > 0) * rank(returns) + (kurt <= 0) * rank(returns)
        # Equiv: raw = - sign(kurt) * rank(returns)
        sign_kurt = (kurt > 0).astype(float) * 2 - 1  # 1 if >0, -1 otherwise
        raw = -sign_kurt * returns.rolling(rank_window).rank(pct=True) * 2 - 1
        return raw

    @staticmethod
    def alpha_factorminer_vn_100_tanh(df, window=10, vol_window=7):
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        returns = df['close'].pct_change()
        kurt = amt.rolling(window).kurt()
        # raw = - sign(kurt) * returns (with magnitude)
        sign_kurt = (kurt > 0).astype(float) * 2 - 1
        raw = -sign_kurt * returns
        return np.tanh(raw / raw.rolling(vol_window).std().replace(0, np.nan)).fillna(0)

    @staticmethod
    def alpha_factorminer_vn_100_zscore(df, window=10, z_window=7):
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        returns = df['close'].pct_change()
        kurt = amt.rolling(window).kurt()
        sign_kurt = (kurt > 0).astype(float) * 2 - 1
        raw = -sign_kurt * returns
        z = (raw - raw.rolling(z_window).mean()) / raw.rolling(z_window).std().replace(0, np.nan)
        return z.clip(-1, 1)

    @staticmethod
    def alpha_factorminer_vn_100_sign(df, window=15):
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        returns = df['close'].pct_change()
        kurt = amt.rolling(window).kurt()
