    @staticmethod
    def alpha_factorminer_vn_102_rank(df, window=30):
        close = df['close']
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        # KAMA calculation
        kama_period = 11
        alpha = 2.0 / (kama_period + 1)
        change = close.diff(1).abs()
        volatility = close.diff(9).abs().rolling(10).sum()
        er = change / volatility.replace(0, np.nan)
        sc = (er * (2.0 / (2 + 1) - 2.0 / (30 + 1)) + 2.0 / (30 + 1)) ** 2
        kama = close.copy()
        for i in range(1, len(close)):
            kama.iloc[i] = kama.iloc[i - 1] + sc.iloc[i] * (close.iloc[i] - kama.iloc[i - 1])
        kama = kama.ffill()
        # First regression: vwap ~ KAMA
        y = vwap
        x = kama
        mean_x = x.rolling(17).mean()
        mean_y = y.rolling(17).mean()
        cov = (x * y).rolling(17).mean() - mean_x * mean_y
        var_x = (x ** 2).rolling(17).mean() - mean_x ** 2
        slope = cov / var_x.replace(0, np.nan)
        intercept = mean_y - slope * mean_x
        resid1 = y - (slope * x + intercept)
        # Second regression: resid1 ~ time
        time_index = pd.Series(np.arange(len(df)), index=df.index)
        mean_time = time_index.rolling(11).mean()
        mean_resid = resid1.rolling(11).mean()
        cov_tr = (time_index * resid1).rolling(11).mean() - mean_time * mean_resid
        var_time = (time_index ** 2).rolling(11).mean() - mean_time ** 2
        slope_resid = cov_tr / var_time.replace(0, np.nan)
        resid_final = resid1 - slope_resid * time_index
        raw = -resid_final
        # Normalization: Rolling Rank
        result = ((raw.rolling(window).rank(pct=True)) * 2 - 1).fillna(0)
        return result

