        mean_vol = neutralized_vwap.rolling(window).mean()
        std_vol = neutralized_vwap.rolling(window).std().replace(0, np.nan)
        raw = mean_vol / std_vol
        raw = -(-raw)
        signal = np.tanh(raw / raw.rolling(window).std().replace(0, np.nan))
