    @staticmethod
    def alpha_factorminer_vn_105_rank(df, window=60):
        close = df['close']
        amt = df.get('amount', close * df.get('matchingVolume', df.get('volume', 1)))
        returns = close.pct_change()
        # Tính Co-Kurtosis (Pearson type: co-kurtosis = E[(X-muX)^3 * (Y-muY)] / (stdX^3 * stdY))
        # Sử dụng rolling covariance of cubed deviations
        amt_mean = amt.rolling(window).mean()
        close_mean = close.rolling(window).mean()
        amt_dev = amt - amt_mean
        close_dev = close - close_mean
        amt_cubed = amt_dev**3
        # numerator: E[(X-muX)^3 * (Y-muY)]
        num = (amt_cubed * close_dev).rolling(window).mean()
        # denominator: stdX^3 * stdY
        amt_std = amt.rolling(window).std().replace(0, np.nan)
        close_std = close.rolling(window).std().replace(0, np.nan)
        denom = (amt_std**3) * close_std
        cokurt = num / denom
        # Tính RegBeta: covariance / variance
        cov = amt.rolling(window).cov(returns)
        var_returns = returns.rolling(window).var().replace(0, np.nan)
        beta = cov / var_returns
        # Điều kiện: If cokurt > 0 -> -beta, else -(-beta) = beta? Actually Neg(IfElse(>0, RegBeta, Neg(RegBeta))) => - (beta if >0 else -beta) => -beta if >0 else beta
        condition = cokurt > 0
        raw = pd.Series(np.where(condition, -beta, beta), index=df.index)
        # Rolling Rank normalization (Case A)
        raw_clean = raw.replace([np.inf, -np.inf], np.nan).fillna(0)
        result = (raw_clean.rolling(window).rank(pct=True) * 2) - 1
        result = result.replace([np.inf, -np.inf], np.nan).fillna(0)
        return -result

    @staticmethod
    def alpha_factorminer_vn_105_tanh(df, window=80):
        close = df['close']
        amt = df.get('amount', close * df.get('matchingVolume', df.get('volume', 1)))
        returns = close.pct_change()
        # Tính Co-Kurtosis
        amt_mean = amt.rolling(window).mean()
        close_mean = close.rolling(window).mean()
        amt_dev = amt - amt_mean
        close_dev = close - close_mean
        amt_cubed = amt_dev**3
        num = (amt_cubed * close_dev).rolling(window).mean()
        amt_std = amt.rolling(window).std().replace(0, np.nan)
        close_std = close.rolling(window).std().replace(0, np.nan)
        denom = (amt_std**3) * close_std
        cokurt = num / denom
        # Beta
        cov = amt.rolling(window).cov(returns)
        var_returns = returns.rolling(window).var().replace(0, np.nan)
        beta = cov / var_returns
        condition = cokurt > 0
        raw = pd.Series(np.where(condition, -beta, beta), index=df.index)
        # Dynamic Tanh (Case B)
        raw_clean = raw.replace([np.inf, -np.inf], np.nan).ffill().fillna(0)
        result = np.tanh(raw_clean / (raw_clean.rolling(window).std().replace(0, np.nan) + 1e-9))
        result = result.replace([np.inf, -np.inf], np.nan).fillna(0)
        return result

    @staticmethod
    def alpha_factorminer_vn_105_zscore(df, window=35):
        close = df['close']
        amt = df.get('amount', close * df.get('matchingVolume', df.get('volume', 1)))
