    @staticmethod
    def alpha_factorminer_vn_109_rank(df, window=5):
        close = df['close']
        dema_7 = 2 * close.ewm(span=7, adjust=False).mean() - close.ewm(span=7, adjust=False).mean().ewm(span=7, adjust=False).mean()
        cumprod_dema = (1 + dema_7.pct_change()).fillna(1).rolling(window=window, min_periods=1).apply(lambda x: np.prod(x), raw=True)
        tsmax_close = close.rolling(window=37, min_periods=1).max()
        raw = cumprod_dema / tsmax_close
        raw = -raw
        normalized = (raw.rolling(window*2, min_periods=1).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

