        # Slope
        days = pd.Series(np.arange(len(df)), index=df.index).astype(float)
        y = returns.rolling(sub_window, min_periods=1)
        x = days.rolling(sub_window, min_periods=1)
        slope = (y.cov(x) / (x.var().replace(0, np.nan)))

        condition = entropy > 0.5
        signal = pd.Series(np.where(condition, slope, -slope), index=df.index)

        raw = -signal

        # Normalize using Dynamic Tanh (Case B)
        normalized = np.tanh(raw / (raw.rolling(window).std().replace(0, np.nan) + 1e-9))
        return normalized.fillna(0)

