    @staticmethod
    def alpha_factorminer_vn_115_k(df, window=20, ulcer_window=30):
        # Tinh Ulcer Index
        max_close = df['close'].rolling(ulcer_window).max()
        drawdown = (df['close'] - max_close) / max_close
        ulcer = np.sqrt((drawdown ** 2).rolling(ulcer_window).mean())
        # Tinh volume * ulcer
        combined = df['matchingVolume'] * ulcer
        # Tinh returns
        ret = df['close'].pct_change()
        # Corr(tich, ret, 7)
        corr = combined.rolling(window).corr(ret)
        # Neg = -corr
        raw = -corr
        # Chuan hoa Rolling Rank
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.ffill().fillna(0)

