    @staticmethod
    def alpha_factorminer_vn_120_wf(df, window_rank=20, winsor_p=0.1):
        raw = (df['high'] - df['low']) / df['close'].rolling(window_rank).mean()
        p1 = 1.0 - winsor_p
        low = raw.rolling(window_rank).quantile(p1)
        high = raw.rolling(window_rank).quantile(winsor_p)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return -normalized.fillna(0).clip(-1, 1)

    @staticmethod
    def alpha_factorminer_vn_121_rank(df, window=80, sub_window=30):
        close = df['close']
        returns = close.pct_change().fillna(0)
        y = returns
        x = pd.Series(np.arange(len(df)), index=df.index)
        x_mean = x.rolling(window).mean()
        y_mean = y.rolling(window).mean()
        x_diff = x - x_mean
        y_diff = y - y_mean
        beta = (x_diff * y_diff).rolling(window).sum() / (x_diff ** 2).rolling(window).sum().replace(0, np.nan)
        intercept = y_mean - beta * x_mean
        resid = y - (intercept + beta * x)
        y2 = resid
        x2 = pd.Series(np.arange(len(df)), index=df.index)
        x_mean2 = x2.rolling(sub_window).mean()
        y_mean2 = y2.rolling(sub_window).mean()
        x_diff2 = x2 - x_mean2
        y_diff2 = y2 - y_mean2
        beta2 = (x_diff2 * y_diff2).rolling(sub_window).sum() / (x_diff2 ** 2).rolling(sub_window).sum().replace(0, np.nan)
        intercept2 = y_mean2 - beta2 * x_mean2
        resid2 = y2 - (intercept2 + beta2 * x2)
        raw = -(-resid2)
        result = (raw.rolling(sub_window).rank(pct=True) * 2) - 1
        return result.fillna(0)

