        z_close = (close - close_mean) / close_std
        z_volume = (volume - volume_mean) / volume_std
        coskew = (z_close * z_volume ** 2).rolling(n).mean()
        raw = -coskew
        normalized = np.tanh(raw / raw.rolling(window).std().replace(0, np.nan))
        return -normalized.fillna(0)

