    @staticmethod
    def alpha_factorminer_vn_125_wf(df, window=100, sub_window=5, p1=0.05):
        returns = df['close'].pct_change()
        ema1 = df['matchingVolume'].ewm(span=sub_window, adjust=False).mean()
        ema2 = ema1.ewm(span=sub_window, adjust=False).mean()
        dema_vol = 2 * ema1 - ema2
        cov = dema_vol.rolling(window).cov(df['close'])
        var = df['close'].rolling(window).var().replace(0, np.nan)
        beta = cov / var
        signal = pd.Series(np.where(returns > 0, beta, -beta), index=df.index)
        # Winsorized Fisher Transform normalization
        low = signal.rolling(window).quantile(p1)
        high = signal.rolling(window).quantile(1 - p1)
        winsorized = signal.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_126_rank(df, window=10, sub_window=20):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        ret = close.pct_change()
        # InformationRatio = slope of cumulative close over sub_window? Assuming close momentum
        # Here we use rolling mean of close as simple proxy for InformationRatio
        ir = close / close.rolling(sub_window).mean() - 1
        vol_factor = volume * ir
        # Rolling correlation between vol_factor and returns over window
        corr = vol_factor.rolling(window).corr(ret)
        # Neg(Neg(corr)) = +corr (two negatives cancel)
        raw = corr
        # Normalize using Rolling Z-Score (Case C)
        norm = (raw - raw.rolling(window).mean()) / raw.rolling(window).std()
        norm = norm.clip(-1, 1)
        return -norm.fillna(0)

