    @staticmethod
    def alpha_factorminer_vn_127_rank(df, window=30):
        amount = df.get('amount', df['close'] * df.get('matchingVolume', 1))
        raw = -((amount.cumsum() / (amount.rolling(window).max() - (amount.rolling(window).expanding().min() if window > 1 else 0)) + 1.0).clip(lower=1.0)).rolling(window).rank(pct=True) * 2 - 1
        signal = raw.ffill().fillna(0)
        return signal

