    @staticmethod
    def alpha_factorminer_vn_128_rank(df, window=50):
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        ret = df['close'].pct_change()
        raw = amt.rolling(window=window).skew() / amt.rolling(window=window).kurt().replace(0, np.nan)
        sign = np.sign(ret)
        compound = raw * (2 * (sign > 0).astype(int) - 1)
        normalized = (compound.rolling(window=window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

