    @staticmethod
    def alpha_factorminer_vn_131_wf(df, window=80):
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        alpha = 2.0 / (window + 1.0)
        ema = amt.ewm(alpha=alpha, adjust=False).mean()
        dema = 2 * ema - ema.ewm(alpha=alpha, adjust=False).mean()
        ret = df['close'].pct_change()
        kurt_window = 37
        n = kurt_window
        mean = dema.rolling(n).mean()
        std = dema.rolling(n).std(ddof=0).replace(0, np.nan)
        m4 = ((dema - mean) ** 4).rolling(n).mean()
        kurt = (m4 / (std ** 4 + 1e-9)) - 3
        neg_kurt = -kurt
        raw = pd.Series(np.where(ret > 0, kurt, neg_kurt), index=df.index)
        # Normalize: Winsorized Fisher (E)
        p1 = 0.05
        p2 = 63
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        norm = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return norm.dropna().reindex(df.index).fillna(0)

    @staticmethod
    def alpha_factorminer_vn_132_rank(df, window=60):
        returns = df['close'].pct_change().fillna(0)
        z = (returns - returns.rolling(window).mean()) / returns.rolling(window).std().replace(0, np.nan)
        z = z.fillna(0)
        scaled = returns / returns.abs().sum()
        signal = np.where(z > 0, scaled, -scaled)
        signal = pd.Series(signal, index=df.index)
        result = -signal
        normalized = result.rolling(window).rank(pct=True) * 2 - 1
        return normalized.fillna(0)

