    @staticmethod
    def alpha_factorminer_vn_144_rank(df, window=80, sub_window=20):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        close = df['close']
        # Regression residual using covariance method
        cov = close.rolling(window).cov(vwap)
        var_vwap = vwap.rolling(window).var().replace(0, np.nan)
        slope = cov / var_vwap
        intercept = vwap.rolling(window).mean() - slope * close.rolling(window).mean()
        predicted_vwap = intercept + slope * close
        resi = vwap - predicted_vwap
        # Slope of residual
        y = resi
        x = pd.Series(np.arange(len(df)), index=df.index)
        cov2 = y.rolling(sub_window).cov(x)
        var_x = x.rolling(sub_window).var().replace(0, np.nan)
        raw = -(cov2 / var_x)
        # Normalize (A): Rolling Rank
        result = (raw.rolling(sub_window).rank(pct=True) * 2) - 1
        return result.fillna(0)

