    @staticmethod
    def alpha_factorminer_vn_150_k(df, window=100):
        high = df['high']
        low = df['low']
        close = df['close']
        # Tính CumMax của high
        cum_max = high.expanding().max().shift(1)
        # Tính numerator và denominator
        numerator = cum_max - low
        denominator = (high - low).abs()
        ratio = numerator / denominator
        # CsMean của ratio
        cs_mean = ratio.expanding().mean()
        # Tính returns
        returns = close.pct_change()
        # IfElse: nếu ratio > cs_mean thì dùng CsScale(returns), ngược lại -CsScale(returns)
        # CsScale là rank (pct=True) -> scale [-1,1] bằng cách *2-1
        cs_scale_returns = (returns.rolling(window).rank(pct=True) * 2) - 1
        condition = ratio > cs_mean
        signal = pd.Series(np.where(condition, cs_scale_returns, -cs_scale_returns), index=df.index)
        # Neg(Neg(...)) = Pos(...) = tín hiệu
        raw = signal
        # Chuẩn hóa về [-1, 1] bằng Rolling Rank
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        result = result.ffill().fillna(0)
        return -result

    @staticmethod
    def alpha_factorminer_vn_150_h(df, window=95):
        high = df['high']
        low = df['low']
        close = df['close']
        cum_max = high.expanding().max().shift(1)
        numerator = cum_max - low
        denominator = (high - low).abs()
        ratio = numerator / denominator
        cs_mean = ratio.expanding().mean()
        returns = close.pct_change()
        cs_scale_returns = (returns.rolling(window).rank(pct=True) * 2) - 1
        condition = ratio > cs_mean
        signal = pd.Series(np.where(condition, cs_scale_returns, -cs_scale_returns), index=df.index)
        raw = signal
        std = raw.rolling(window).std().replace(0, np.nan)
        result = np.tanh(raw / std)
        result = pd.Series(result, index=df.index).ffill().fillna(0)
        return -result

    @staticmethod
    def alpha_factorminer_vn_150_e(df, window=75):
        high = df['high']
        low = df['low']
        close = df['close']
        cum_max = high.expanding().max().shift(1)
        numerator = cum_max - low
        denominator = (high - low).abs()
        ratio = numerator / denominator
        cs_mean = ratio.expanding().mean()
        returns = close.pct_change()
        cs_scale_returns = (returns.rolling(window).rank(pct=True) * 2) - 1
        condition = ratio > cs_mean
        signal = pd.Series(np.where(condition, cs_scale_returns, -cs_scale_returns), index=df.index)
        raw = signal
        roll_mean = raw.rolling(window).mean()
        roll_std = raw.rolling(window).std().replace(0, np.nan)
        result = ((raw - roll_mean) / roll_std).clip(-1, 1)
        result = result.ffill().fillna(0)
        return -result

