        corr = decay_vol.rolling(window).cov(cum_ret) / (decay_vol.rolling(window).std() * cum_ret.rolling(window).std())
        raw = -corr
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

