    def alpha_factorminer_vn_155_wf(df, window=60, p1=0.9):
        p2 = window
        volume = np.log1p(df['matchingVolume'])
        mean = volume.rolling(window).mean()
        ulcer = volume.rolling(window).std() / mean.replace(0, np.nan)
        cs_mean_ulcer = ulcer.rolling(window).mean()
        ret = df['close'].pct_change()
        raw = pd.Series(np.where(ulcer > cs_mean_ulcer, (ret - ret.rolling(window).mean()) / ret.rolling(window).std(), -((ret - ret.rolling(window).mean()) / ret.rolling(window).std())), index=df.index)
        raw = raw.ffill().fillna(0)
        result = -(-raw)
        low = result.rolling(p2).quantile(p1)
        high = result.rolling(p2).quantile(1 - p1)
        winsorized = result.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99).fillna(0)
        return -normalized

    @staticmethod
    def alpha_factorminer_vn_156_rank(df, window=19, sub_window=7):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        hma_volume = close.rolling(window).apply(lambda x: (2 * x.rolling(13).mean() - x.rolling(26).mean()).rolling(13).mean(), raw=True)
        resi = close - hma_volume
        days = pd.Series(np.arange(len(df)), index=df.index)
        slope = (resi.rolling(sub_window).cov(days) / days.rolling(sub_window).var().replace(0, np.nan)).ewm(span=7, adjust=False).mean()
        raw = -slope
        result = (raw.rolling(sub_window).rank(pct=True) * 2) - 1
        return result.fillna(0).clip(-1, 1)

