    @staticmethod
    def alpha_factorminer_vn_158_k(df, window=90, sub_window=30):
        close = df['close']
        ret = close.pct_change().fillna(0)
        neg_returns = ret.where(ret < 0, 0)
        sum_squared = (neg_returns ** 2).rolling(window).sum()
        sqrt_val = sum_squared.replace(0, np.nan) ** 0.5
        ulcer = sqrt_val / close.rolling(window).mean().replace(0, np.nan)
        ts_rank_ulcer = (ulcer.rolling(sub_window).rank(pct=True) * 2 - 1)
        ts_rank_close = (close.rolling(sub_window).rank(pct=True) * 2 - 1)
        sub = ts_rank_ulcer - ts_rank_close
        neg_sub = -sub
        neg_neg_sub = -neg_sub
        signal = (neg_neg_sub.rolling(sub_window).rank(pct=True) * 2 - 1)
        signal = signal.fillna(0)
        return -pd.Series(signal, index=df.index)

