    @staticmethod
    def alpha_factorminer_vn_159_rank(df, window=10):
        days = pd.Series(np.arange(len(df)), index=df.index)
        low_wma = df['low'].ewm(span=13, adjust=False).mean()
        # slope = cov(high, days) / var(days)
        high_cov = df['high'].rolling(window).cov(days)
        days_var = days.rolling(window).var().replace(0, np.nan)
        slope = high_cov / days_var
        # regression residual = high - (intercept + slope * days)
        intercept = df['high'].rolling(window).mean() - slope * days.rolling(window).mean()
        residual = df['high'] - (intercept + slope * days)
        # neutralize with low_wma (cross-sectional centering)
        neutralized = residual - residual.rolling(100, min_periods=1).mean()
        raw = -neutralized
        # Rolling Rank normalization (Case A)
        result = (raw.rolling(20).rank(pct=True) * 2) - 1
        result = result.ffill().fillna(0)
        return -result

