        resi = returns - slope * days

        entropy = - (volume / volume.rolling(window).sum()) * np.log(volume / volume.rolling(window).sum() + 1e-9)
        entropy = entropy.rolling(window).sum().fillna(0)

        reg_resi = resi.rolling(13).apply(lambda x: np.polyfit(np.arange(len(x)), x, 1)[0] if len(x) == 13 else np.nan, raw=True)

        days_slope = pd.Series(np.arange(len(df)), index=df.index)
        final_slope = reg_resi.rolling(5).cov(days_slope) / days_slope.rolling(5).var().replace(0, np.nan)

        raw = -final_slope

        normalized = ((raw - raw.rolling(window).mean()) / raw.rolling(window).std().replace(0, np.nan)).clip(-1, 1)
        return -normalized.fillna(0)

