    @staticmethod
    def alpha_factorminer_vn_164_rank(df, window=15):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        returns = df['close'].pct_change().fillna(0)
        x = vwap
        y = returns
        x_mean = x.rolling(window).mean()
        y_mean = y.rolling(window).mean()
        x_diff = x - x_mean
        y_diff = y - y_mean
        var_x = (x_diff ** 2).rolling(window).sum()
        var_y = (y_diff ** 2).rolling(window).sum()
        cov_xy = (x_diff * y_diff).rolling(window).sum()
        term1 = (x_diff ** 2).rolling(window).sum() * (y_diff ** 2).rolling(window).sum()
        co_kurt = (var_x * var_y) / (term1 + 1e-9)
        raw = -co_kurt
        # Normalize using Rolling Rank (A)
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -signal.fillna(0)

