        ts_rank_ret = ret.rolling(window_rank).rank(pct=True)
        middle = close.rolling(window_boll).mean()
        std = close.rolling(window_boll).std()
        boll_up = middle + 2 * std
        boll_low = middle - 2 * std
        boll_range = boll_up - boll_low
        raw = pd.Series(np.where(ts_rank_ret > 0.5, boll_range, -boll_range), index=df.index)
