    @staticmethod
    def alpha_factorminer_vn_166_rank(df, window=70, sub_window=3):
        returns = df['close'].pct_change()
        count_above = (returns.rolling(window).apply(lambda x: np.sum(x > 0.02), raw=True)).fillna(0)
        adjusted = np.where(count_above > 15, returns, -returns)
