    @staticmethod
    def alpha_factorminer_vn_171_k(df, window=60, sub_window=7):
        close = df['close']
        hma_length = 13
        reg_window = sub_window
        # HMA calculation
        wma_half = close.rolling(window=hma_length // 2).apply(lambda x: (x * (np.arange(len(x)) + 1)).sum() / (np.arange(len(x)) + 1).sum(), raw=True) if hma_length // 2 > 0 else close
        wma_full = close.rolling(window=hma_length).apply(lambda x: (x * (np.arange(len(x)) + 1)).sum() / (np.arange(len(x)) + 1).sum(), raw=True)
        hma_raw = (2 * wma_half - wma_full)
        hma = hma_raw.rolling(window=int(np.sqrt(hma_length))).apply(lambda x: (x * (np.arange(len(x)) + 1)).sum() / (np.arange(len(x)) + 1).sum(), raw=True)
        # Regression residuals
        days = pd.Series(np.arange(len(df)), index=df.index)
        cov = close.rolling(reg_window).cov(days)
        var = days.rolling(reg_window).var().replace(0, np.nan)
        slope = cov / var
        intercept = close.rolling(reg_window).mean() - slope * days.rolling(reg_window).mean()
        fitted = slope * days + intercept
        resid = close - fitted
        # Kurtosis of residuals
        mean_resid = resid.rolling(window).mean()
        std_resid = resid.rolling(window).std().replace(0, np.nan)
        kurt = ( ((resid - mean_resid) / std_resid) ** 4 ).rolling(window).mean() * (window * (window + 1) / ((window - 1) * (window - 2) * (window - 3))) - 3 * ((window - 1) ** 2) / ((window - 2) * (window - 3))
        raw = kurt
        # Normalization A
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -result.fillna(0)

