    @staticmethod
    def alpha_factorminer_vn_173_r(df, window=80, percent=0.7):
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        ret = df['close'].pct_change()
        cumamt = amount.cumsum()
        y = ret
        x = cumamt
        cov = y.rolling(window).cov(x)
        var = x.rolling(window).var().replace(0, np.nan)
        raw = cov / var
        # Winsorized Fisher Transform
        low = raw.rolling(window).quantile(percent)
        high = raw.rolling(window).quantile(1 - percent)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        # Transform
        numerator = (winsorized - low) / (high - low + 1e-9)
        numerator = numerator * 1.98 - 0.99
        numerator = numerator.clip(-0.99, 0.99)
        signal = np.arctanh(numerator)
        signal = pd.Series(signal, index=df.index).ffill().fillna(0)
        return signal

    @staticmethod
    def alpha_factorminer_vn_174_rank(df, window_rank=19):
        vol = df['matchingVolume']
        dema_period = 13
        kurt_period = 31
        # DEMA calculation manually
        ema1 = vol.ewm(span=dema_period, adjust=False).mean()
        ema2 = ema1.ewm(span=dema_period, adjust=False).mean()
        dema = 2 * ema1 - ema2
        kurt = dema.rolling(kurt_period).kurt()
        count_gt_12 = vol.rolling(window_rank).apply(lambda x: (x > vol.shift(1)).sum(), raw=True) > 12
        condition = (vol.rolling(window_rank).count() > 0) & (count_gt_12)
        raw = pd.Series(np.where(condition, kurt, -kurt), index=df.index)
        raw = -raw
        normalized = (raw.rolling(window_rank).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

