    @staticmethod
    def alpha_factorminer_vn_177_rank(df, window=85):
        close = df['close']
        volume = df['matchingVolume']
        delta_close = close.diff(1)
        # Calculate co-kurtosis: E[(X-mu_x)^2 * (Y-mu_y)^2] / (sigma_x^2 * sigma_y^2) - 1
        # Using rolling window
        mean_close = close.rolling(window).mean()
        mean_volume = volume.rolling(window).mean()
        std_close = close.rolling(window).std(ddof=0)
        std_volume = volume.rolling(window).std(ddof=0)
        # Co-kurtosis term
        diff_close = close - mean_close
        diff_volume = volume - mean_volume
        product_sq = (diff_close ** 2) * (diff_volume ** 2)
        var_close = std_close ** 2
        var_volume = std_volume ** 2
        denominator = (window * var_close * var_volume).replace(0, np.nan)
        cokurt = product_sq.rolling(window).sum() / denominator - 1
        cokurt = cokurt.fillna(0)
        # Apply condition
        condition = delta_close > 0
        raw = pd.Series(np.where(condition, cokurt, -cokurt), index=df.index)
        raw = -raw
        # Normalization A: Rolling Rank
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_177_tanh(df, window=85):
        close = df['close']
        volume = df['matchingVolume']
        delta_close = close.diff(1)
        mean_close = close.rolling(window).mean()
        mean_volume = volume.rolling(window).mean()
        std_close = close.rolling(window).std(ddof=0)
        std_volume = volume.rolling(window).std(ddof=0)
        diff_close = close - mean_close
        diff_volume = volume - mean_volume
        product_sq = (diff_close ** 2) * (diff_volume ** 2)
        var_close = std_close ** 2
        var_volume = std_volume ** 2
        denominator = (window * var_close * var_volume).replace(0, np.nan)
        cokurt = product_sq.rolling(window).sum() / denominator - 1
        cokurt = cokurt.fillna(0)
        condition = delta_close > 0
        raw = pd.Series(np.where(condition, cokurt, -cokurt), index=df.index)
        raw = -raw
        std_raw = raw.rolling(window).std()
        normalized = np.tanh(raw / std_raw.replace(0, np.nan))
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_177_zscore(df, window=60):
        close = df['close']
        volume = df['matchingVolume']
        delta_close = close.diff(1)
        mean_close = close.rolling(window).mean()
        mean_volume = volume.rolling(window).mean()
        std_close = close.rolling(window).std(ddof=0)
        std_volume = volume.rolling(window).std(ddof=0)
        diff_close = close - mean_close
        diff_volume = volume - mean_volume
        product_sq = (diff_close ** 2) * (diff_volume ** 2)
        var_close = std_close ** 2
        var_volume = std_volume ** 2
        denominator = (window * var_close * var_volume).replace(0, np.nan)
        cokurt = product_sq.rolling(window).sum() / denominator - 1
        cokurt = cokurt.fillna(0)
        condition = delta_close > 0
        raw = pd.Series(np.where(condition, cokurt, -cokurt), index=df.index)
        raw = -raw
        mean_raw = raw.rolling(window).mean()
        std_raw = raw.rolling(window).std()
        normalized = ((raw - mean_raw) / std_raw.replace(0, np.nan)).clip(-1, 1)
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_177_sign(df, window=75):
        close = df['close']
        volume = df['matchingVolume']
        delta_close = close.diff(1)
        mean_close = close.rolling(window).mean()
        mean_volume = volume.rolling(window).mean()
        std_close = close.rolling(window).std(ddof=0)
        std_volume = volume.rolling(window).std(ddof=0)
        diff_close = close - mean_close
        diff_volume = volume - mean_volume
        product_sq = (diff_close ** 2) * (diff_volume ** 2)
        var_close = std_close ** 2
        var_volume = std_volume ** 2
        denominator = (window * var_close * var_volume).replace(0, np.nan)
        cokurt = product_sq.rolling(window).sum() / denominator - 1
        cokurt = cokurt.fillna(0)
        condition = delta_close > 0
        raw = pd.Series(np.where(condition, cokurt, -cokurt), index=df.index)
        raw = -raw
        normalized = np.sign(raw)
        return -normalized.fillna(0)

