    def alpha_factorminer_vn_183_wf(df, window=100, sub_window=20, p1=0.05, p2=31):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        ret = (close - close.shift(1)) / close.shift(1).replace(0, np.nan)
        ret = ret.fillna(0)
        w = window
        rv = ret * volume
        rv_mean = rv.rolling(w).mean()
        rv_centered = rv - rv_mean
        third = (rv_centered ** 3).rolling(w).mean()
        second = (rv_centered ** 2).rolling(w).mean().replace(0, np.nan)
        co_skew = third / (second ** 1.5)
        w2 = sub_window
        cov = ret.rolling(w2).cov(volume)
        var_vol = volume.rolling(w2).var().replace(0, np.nan)
        beta = cov / var_vol
        cond = co_skew > 0
        raw = pd.Series(np.where(cond, beta, -beta), index=df.index).fillna(0)
        raw = -raw
        # Normalize E: Winsorized Fisher
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        norm = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return norm.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_184_rank(df, window=90):
        close = df['close']
        ret = close.pct_change()
        y = ret.rolling(window).mean()
        x = pd.Series(np.arange(len(df)), index=df.index)
        slope = y.rolling(window).cov(x) / x.rolling(window).var().replace(0, np.nan)
        raw = -slope.rolling(31).std()
        normalized = raw.rolling(window).rank(pct=True) * 2 - 1
