    @staticmethod
    def alpha_factorminer_vn_185_rank(df, window=70, corr_window=3):
        close = df['close']
        volume = df['matchingVolume']
        rets = close.pct_change()
        # UlcerIndex: sqrt(sum of squared drawdowns / n)
        max_close = close.rolling(window).max()
        pct_drawdown = (close - max_close) / max_close
        pct_drawdown_sq = pct_drawdown ** 2
        ulcer = np.sqrt(pct_drawdown_sq.rolling(window).mean()).fillna(0)
        raw = volume * ulcer
        corr_val = raw.rolling(corr_window).corr(close)
        neg_corr = -corr_val
        # Rolling Rank A
        normalized = (neg_corr.rolling(corr_window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

