        close_rank = close.rolling(window_e).rank(pct=True)
        raw = atr_rank - close_rank
        raw = -(-raw)
        low_raw = raw.rolling(window_e).quantile(p1_e)
        high_raw = raw.rolling(window_e).quantile(1 - p1_e)
        winsorized = raw.clip(lower=low_raw, upper=high_raw, axis=0)
        denom = (high_raw - low_raw).replace(0, np.nan)
        scaled = ((winsorized - low_raw) / denom) * 1.98 - 0.99
        scaled = scaled.clip(-0.9999, 0.9999)
        normalized = np.arctanh(scaled)
        return -normalized.fillna(0.0)

