    @staticmethod
    def alpha_factorminer_vn_197_rank(df, window=35):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        ret = df['close'].pct_change()
        mean_vwap = vwap.rolling(window).mean()
        var_vwap = vwap.rolling(window).var().replace(0, np.nan)
        kurt = ((vwap - mean_vwap) ** 4).rolling(window).mean() / (var_vwap ** 2) - 3
        kurt = kurt.fillna(0)
        signal = pd.Series(np.where(kurt > 0, ret, -ret), index=df.index).fillna(0)
        rank_signal = signal.rolling(window).rank(pct=True) * 2 - 1
        return rank_signal.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_197_tanh(df, window=35):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        ret = df['close'].pct_change()
        mean_vwap = vwap.rolling(window).mean()
        var_vwap = vwap.rolling(window).var().replace(0, np.nan)
        kurt = ((vwap - mean_vwap) ** 4).rolling(window).mean() / (var_vwap ** 2) - 3
        kurt = kurt.fillna(0)
