    @staticmethod
    def alpha_factorminer_vn_204_rank(df, window=30):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        daily_returns = vwap.pct_change()
        mean_ret = daily_returns.rolling(window).mean()
        std_ret = daily_returns.rolling(window).std().replace(0, np.nan)
        info_ratio = mean_ret / std_ret
        # Kurtosis manually: fourth central moment / variance^2 - 3
        dev = daily_returns - daily_returns.rolling(window).mean()
        var = (dev**2).rolling(window).mean()
        kurt = (dev**4).rolling(window).mean() / (var**2 + 1e-9) - 3
        raw = -(info_ratio * kurt)
        raw = raw.ffill().fillna(0)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return normalized

