        aroon_up = ((window - high.rolling(window).apply(lambda x: x[::-1].argmax(), raw=False)) / window) * 100
        aroon_down = ((window - low.rolling(window).apply(lambda x: x[::-1].argmin(), raw=False)) / window) * 100
