    @staticmethod
    def alpha_factorminer_vn_209_rank(df, window_a=60, window_b=5):
        close = df['close']
        kama_period = 13
        er = (close - close.shift(kama_period)).abs() / (close.diff().abs().rolling(kama_period).sum() + 1e-9)
        sc = (er * (2.0 / (window_b + 1.0) - 2.0 / (kama_period + 1.0)) + 2.0 / (kama_period + 1.0)) ** 2
        kama = close.copy()
        for i in range(kama_period, len(kama)):
            kama.iloc[i] = kama.iloc[i-1] + sc.iloc[i] * (close.iloc[i] - kama.iloc[i-1])
        skew_kama = kama.rolling(window_a).skew()
        condition = skew_kama > 0
        zscore_close = (close - close.rolling(20).mean()) / close.rolling(20).std()
        raw = pd.Series(np.where(condition, zscore_close, -zscore_close), index=df.index)
        raw = -raw
        normalized = (raw.rolling(20).rank(pct=True) * 2) - 1
        return normalized

    @staticmethod
    def alpha_factorminer_vn_209_tanh(df, window_a=40, window_b=3):
        close = df['close']
        kama_period = 13
        er = (close - close.shift(kama_period)).abs() / (close.diff().abs().rolling(kama_period).sum() + 1e-9)
        sc = (er * (2.0 / (window_b + 1.0) - 2.0 / (kama_period + 1.0)) + 2.0 / (kama_period + 1.0)) ** 2
        kama = close.copy()
        for i in range(kama_period, len(kama)):
            kama.iloc[i] = kama.iloc[i-1] + sc.iloc[i] * (close.iloc[i] - kama.iloc[i-1])
        skew_kama = kama.rolling(window_a).skew()
