    @staticmethod
    def alpha_factorminer_vn_211_rank(df, window=17):
        ret = df['close'].pct_change()
        delta_ret = ret.diff(3)
        days = pd.Series(np.arange(len(df)), index=df.index)
        # Theil-Sen slope: median of pairwise slopes
        y = delta_ret
        x = days
        # Rolling pairwise slopes
        def alpha_factorminer_vn_211_rank(y, x, w):
            # For each window, compute median slope
            # Use convolution for efficiency
            slope = np.full_like(y, np.nan, dtype=np.float64)
            for i in range(w, len(y) + 1):
                y_win = y.iloc[i-w:i].values
                x_win = x.iloc[i-w:i].values
                # Compute all pairwise slopes: (y_j - y_i) / (x_j - x_i)
                n = len(y_win)
                slopes = []
                for k in range(n):
                    for l in range(k+1, n):
                        dx = x_win[l] - x_win[k]
                        if dx != 0:
                            slopes.append((y_win[l] - y_win[k]) / dx)
                if len(slopes) > 0:
                    slope[i-1] = np.median(slopes)
            return pd.Series(slope, index=y.index)
        raw = _vectorized_slope(y, x, window)
        neg_raw = -raw
        # Normalize using Rolling Rank (Type A)
        neg_raw_ff = neg_raw.fillna(method='ffill').fillna(0)
        result = (neg_raw_ff.rolling(window).rank(pct=True) * 2) - 1
        return result.fillna(0)

