    @staticmethod
    def alpha_factorminer_vn_218_rank(df, window=40, sub_window=1):
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        mid = (df['high'] + df['low']) / 2
        upper = mid + 2 * (df['high'] - df['low']).rolling(window).mean()
        lower = mid - 2 * (df['high'] - df['low']).rolling(window).mean()
        bollinger_range = (amount - lower) / (upper - lower + 1e-9)
        rank = bollinger_range.rolling(sub_window).rank(pct=True)
        condition = rank > 0.8
        ret = df['close'].pct_change()
        mean_ret = ret.rolling(window).mean()
        neutralized_ret = ret - mean_ret
        raw = np.where(condition, neutralized_ret, -neutralized_ret)
        raw = pd.Series(raw, index=df.index).fillna(0)
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        return signal.fillna(0)

