    @staticmethod
    def alpha_factorminer_vn_221_rank(df, window=20, sub_window=90):
        close = df['close']
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        days = pd.Series(np.arange(len(df)), index=df.index)
        x = days
        y = close - vwap
        x_mean = x.rolling(window).mean()
        y_mean = y.rolling(window).mean()
        num = ((x - x_mean) * (y - y_mean)).rolling(window).sum()
        den = ((x - x_mean) ** 2).rolling(window).sum().replace(0, np.nan)
        slope = num / den
        residuals = y - slope * (x - x_mean) - y_mean
        kurt = residuals.rolling(sub_window).kurt()
        returns = close.pct_change()
        amt = df.get('amount', close * df.get('matchingVolume', df.get('volume', 1)))
        raw = -returns.where(kurt > 0, amt)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

