    @staticmethod
    def alpha_factorminer_vn_225_rank(df, window_13=50, window_17=30):
        w = window_13
        high_wma = df['high'].rolling(window=w, min_periods=w).apply(lambda x: np.average(x, weights=np.arange(1, w+1)), raw=False)
        low_wma = df['low'].rolling(window=w, min_periods=w).apply(lambda x: np.average(x, weights=np.arange(1, w+1)), raw=False)
        raw = high_wma / low_wma.replace(0, np.nan)
        param = window_17
        ranked = raw.rolling(param).rank(pct=True)
        signal = (ranked * 2) - 1
        signal = signal.clip(-1, 1)
        signal = signal.fillna(0)
        return -signal

