    @staticmethod
    def alpha_factorminer_vn_226_rank(df, window=15):
        ret = df['close'].pct_change()
        vol = df.get('matchingVolume', df.get('volume', 1))
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        # CoSkew = E[(ret-mu_ret)^3 * (vol-mu_vol)] / (sigma_ret^3 * sigma_vol)
        mu_ret = ret.rolling(window).mean()
        mu_vol = vol.rolling(window).mean()
        num = ((ret - mu_ret) ** 3 * (vol - mu_vol)).rolling(window).mean()
        den = (ret.rolling(window).std() ** 3) * vol.rolling(window).std()
        coskew = num / den.replace(0, np.nan)
        # IfElse: Nếu coskew > 0 thì ra CsZScore(ret), ngược lại ra -CsZScore(amt)
        cond = coskew > 0
        z_ret = (ret - ret.rolling(window).mean()) / ret.rolling(window).std().replace(0, np.nan)
        z_amt = (amt - amt.rolling(window).mean()) / amt.rolling(window).std().replace(0, np.nan)
        raw = pd.Series(np.where(cond, z_ret, -z_amt), index=df.index)
        # Chuẩn hóa A: Rolling Rank
        raw_ff = raw.ffill().fillna(0)
        signal = (raw_ff.rolling(window).rank(pct=True) * 2) - 1
        return signal.ffill().fillna(0)

