    @staticmethod
    def alpha_factorminer_vn_229_wf(df, window=40, p1=0.1):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        mid = vwap.rolling(window).mean()
        std = vwap.rolling(window).std()
        upper = mid + 2 * std
        lower = mid - 2 * std
        range_ = upper - lower
        raw = (vwap - mid) / range_.replace(0, np.nan)
        p2 = window
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
