    @staticmethod
    def alpha_factorminer_vn_231_wf(df, window=60, p1=0.1):
        p2 = window
        high = df['high']
        low = df['low']
        close = df['close']
        tr = pd.concat([high - low, (high - close.shift(1).abs()), (low - close.shift(1).abs())], axis=1).max(axis=1)
