    @staticmethod
    def alpha_factorminer_vn_232_rank(df, window=20):
        high_wma = df['high'].rolling(7).apply(lambda x: np.sum(x * np.arange(1, len(x)+1) / np.sum(np.arange(1, len(x)+1))), raw=True)
        low_wma = df['low'].rolling(7).apply(lambda x: np.sum(x * np.arange(1, len(x)+1) / np.sum(np.arange(1, len(x)+1))), raw=True)
        ret = df['close'].pct_change()
        sum_high = high_wma.rolling(13).apply(lambda x: np.sum(x * ret.iloc[np.where(~np.isnan(ret))[:len(x)]]), raw=True) if len(ret.dropna()) > 0 else pd.Series(0, index=df.index)
        sum_low = low_wma.rolling(13).apply(lambda x: np.sum(x * ret.iloc[np.where(~np.isnan(ret))[:len(x)]]), raw=True) if len(ret.dropna()) > 0 else pd.Series(0, index=df.index)
        condition = sum_high > sum_low
        zscore = (ret - ret.rolling(window).mean()) / ret.rolling(window).std()
        raw = np.where(condition, zscore, -zscore)
        raw = pd.Series(raw, index=df.index)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

