        wma_low = low.rolling(window, min_periods=1).apply(lambda x: np.sum(np.arange(1, len(x)+1) * x) / np.sum(np.arange(1, len(x)+1)), raw=True)
        rank_high = wma_high.rolling(sub_window, min_periods=1).rank(pct=True)
        rank_low = wma_low.rolling(sub_window, min_periods=1).rank(pct=True)
        raw = rank_low - rank_high
        p1 = 0.05
        low_q = raw.rolling(sub_window).quantile(p1)
        high_q = raw.rolling(sub_window).quantile(1 - p1)
        clipped = raw.clip(lower=low_q, upper=high_q, axis=0)
        denom = (high_q - low_q).replace(0, np.nan)
        normalized = np.arctanh(((clipped - low_q) / denom) * 1.98 - 0.99)
        signal = normalized.ffill().fillna(0)
        return signal

