        std7 = _range.rolling(7).std()
        mean19 = _range.rolling(window).mean()
        std7_valid = std7.replace(0, np.nan).fillna(0)
        raw = pd.Series(np.where(cond, -std7_valid / std7_valid.abs().mean(), -mean19 / mean19.abs().mean()), index=df.index)
