        # Chuẩn hóa Rolling Z-Score/Clip C
        mean_res = raw.rolling(window).mean()
        std_res = raw.rolling(window).std().replace(0, np.nan)
        signal = ((raw - mean_res) / std_res).clip(-1, 1)
        return -signal.fillna(0)

