    @staticmethod
    def alpha_factorminer_vn_246_wf(df, window=90, p1=0.1):
        close = df['close']
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        # Tính slope của linear regression close ~ vwap
        slope = close.rolling(window).cov(vwap) / vwap.rolling(window).var().replace(0, np.nan)
        intercept = close.rolling(window).mean() - slope * vwap.rolling(window).mean()
        predicted = intercept + slope * vwap
        residual = close - predicted
        raw = -residual
        # Chuẩn hóa Winsorized Fisher E
        low = raw.rolling(window).quantile(p1)
        high = raw.rolling(window).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        # Fisher Transform
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_247_k(df, window=20):
        # Tính delta của close (2 kỳ trước - hiện tại) và delta của amount
        # Giải thích: Công thức gốc: IfElse(Greater(Delta($close,2),0), -CsNeutralize(Delta($amt,2)), CsNeutralize(Delta($amt,2)))
        # Logic: Nếu close giảm (delta close > 0) thì lấy - delta amt, ngược lại lấy delta amt (vì delta close <= 0)
        # Điều này tương đương: sign(close_change) * - amount_change (vì Delta close có thể dương khi giá giảm)
        # Thực tế: Delta(close,2) > 0 nghĩa là close hiện tại thấp hơn 2 kỳ trước (giá giảm)
        close_delta = df['close'].diff(2)  # close hiện tại - close 2 kỳ trước
        # amount: nếu không có cột amount, tái tạo từ close * volume
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        amount_delta = amount.diff(2)
        # Trung hòa ngành: giả sử đã có, ở đây dùng rolling mean trung hòa
        # Neutralize đơn giản: subtract rolling mean
        amt_neutral = amount_delta - amount_delta.rolling(window, min_periods=1).mean()
        # Xử lý condition: close_delta > 0 (giá giảm) -> lấy -amt_neutral, else lấy amt_neutral
        # Tương đương: amt_neutral * -1 nếu close_delta > 0, * 1 nếu không
        # Có thể viết bằng np.where
        raw = np.where(close_delta > 0, -amt_neutral, amt_neutral)
        raw = pd.Series(raw, index=df.index).fillna(0)
        # Rolling Rank
        result = (raw.rolling(window, min_periods=1).rank(pct=True) * 2) - 1
        return -result.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_247_h(df, window=90):
        close_delta = df['close'].diff(2)
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        amount_delta = amount.diff(2)
        amt_neutral = amount_delta - amount_delta.rolling(window, min_periods=1).mean()
        raw = np.where(close_delta > 0, -amt_neutral, amt_neutral)
        raw = pd.Series(raw, index=df.index).fillna(0)
        # Dynamic Tanh
        std = raw.rolling(window, min_periods=1).std().replace(0, np.nan)
        result = np.tanh(raw / std)
        return -pd.Series(result, index=df.index).fillna(0)

