    @staticmethod
    def alpha_factorminer_vn_254_k(df, window=10):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        volume_ema = volume.ewm(span=5, adjust=False).mean()
        volume_div = volume / volume_ema.replace(0, np.nan)

        ret = close.pct_change()

        # CoSkew: joint third standardized moment
        mean_x = ret.rolling(window).mean()
        mean_y = volume_div.rolling(window).mean()

        dx = ret - mean_x
        dy = volume_div - mean_y

        std_x = ret.rolling(window).std(ddof=0).replace(0, np.nan)
        std_y = volume_div.rolling(window).std(ddof=0).replace(0, np.nan)

        # E[dX * dY^2]
        coskew = (dx * dy**2).rolling(window).mean()
        denominator = (std_x * std_y**2).replace(0, np.nan)
        zscore = coskew / denominator

        raw = -zscore
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

