    @staticmethod
    def alpha_factorminer_vn_260_rank(df, window=90, sub_window=7):
        # Calculate slope of close
        y_close = df['close']
        x = pd.Series(np.arange(len(df)), index=df.index)
        covariance_close = y_close.rolling(window).cov(x).fillna(0)
        variance_x = x.rolling(window).var().replace(0, np.nan)
        slope_close = covariance_close / variance_x
        # Calculate slope of volume (using log1p for volume)
        y_vol = np.log1p(df['matchingVolume'])
        covariance_vol = y_vol.rolling(window).cov(x).fillna(0)
        slope_vol = covariance_vol / variance_x
        # Correlation between slopes
        corr = slope_close.rolling(sub_window).corr(slope_vol).fillna(0)
        # ZScore of correlation
        mean_corr = corr.rolling(sub_window).mean()
        std_corr = corr.rolling(sub_window).std().replace(0, np.nan)
        zscore = (corr - mean_corr) / std_corr
        # Negate and normalize to [-1,1] using Rolling Rank
        signal = (-zscore).rolling(window).rank(pct=True) * 2 - 1
        return -signal.fillna(0)

