        dev_vol = vol_ratio - mean_vol
        num = (dev_ret * dev_vol).rolling(window=co_window, min_periods=1).mean()
        std_ret = dev_ret.rolling(window=co_window, min_periods=1).std().replace(0, np.nan)
        std_vol = dev_vol.rolling(window=co_window, min_periods=1).std().replace(0, np.nan)
        coskew_est = num / (std_ret * std_vol + 1e-9)
        cs_zscore = (coskew_est - coskew_est.rolling(window=co_window, min_periods=1).mean()) / coskew_est.rolling(window=co_window, min_periods=1).std().replace(0, np.nan)
        neg = -cs_zscore
        neg = neg.ffill().fillna(0)
        # Normalize via dynamic tanh
        norm = np.tanh(neg / neg.rolling(window=window).std().replace(0, np.nan))
