    @staticmethod
    def alpha_factorminer_vn_266_wf(df, window=30, sub_window=30, winsor_quantile=0.05):
        high = df['high']
        low = df['low']
        close = df['close']
        tr = pd.concat([high - low, (high - close.shift(1)).abs(), (low - close.shift(1)).abs()], axis=1).max(axis=1)
        atr11 = tr.rolling(11).mean()
        z_atr = (atr11 - atr11.rolling(window).mean()) / atr11.rolling(window).std()
        factor_signal = np.where(z_atr > 1.5, 1, 0)
        vwap = df.get('vwap', (high + low + close) / 3)
        returns = close.pct_change()
        days = pd.Series(np.arange(len(df)), index=df.index)
        cov = returns.rolling(sub_window).cov(vwap)
        var_vwap = vwap.rolling(sub_window).var().replace(0, np.nan)
        beta = cov / var_vwap
        resid = returns - beta * vwap
        resid_mean = resid.rolling(sub_window).mean()
        resid_std = resid.rolling(sub_window).std()
        z_resid = (resid - resid_mean) / resid_std
        beta_mean = beta.rolling(sub_window).mean()
        beta_std = beta.rolling(sub_window).std()
        z_beta = (beta - beta_mean) / beta_std
        raw = -(factor_signal * z_resid + (1 - factor_signal) * z_beta)
        raw = raw.fillna(0)
        low_q = raw.rolling(window).quantile(winsor_quantile)
        high_q = raw.rolling(window).quantile(1 - winsor_quantile)
        winsorized = raw.clip(lower=low_q, upper=high_q, axis=0)
        eps = 1e-9
        result = np.arctanh(((winsorized - low_q) / (high_q - low_q + eps)) * 1.98 - 0.99)
        result = result.fillna(0)
        return result

    @staticmethod
    def alpha_factorminer_vn_267_rank(df, window=30, rank_window=100):
        # Tính log volume để chuẩn hóa độ lệch
        vol = df.get('matchingVolume', df.get('volume', 1))
        amt = df.get('amount', df['close'] * vol)
        log_amt = np.log1p(amt)

        # Tính returns
        returns = df['close'].pct_change()

        # Tính Std của amt (window 11 fix cứng)
        std_amt = log_amt.rolling(11).std()

        # Tính Quantile của std_amt (window 23, quantile 0.6 fix cứng)
        quantile_std = std_amt.rolling(23).quantile(0.6)

        # Compare để chọn: nếu greater -> Beta, else -> Resid
        condition = std_amt > quantile_std

        # Beta = covariance(x,y)/variance(x)
        cov = returns.rolling(window).cov(log_amt)
        var = log_amt.rolling(window).var().replace(0, np.nan)
        beta = cov / var

        # Resid = phần dư từ regression đơn giản: y - beta*x (không intercept)
        resid = returns - beta * log_amt

        # Trung hòa beta/resid theo cross-section (standardize)
        # Dùng rolling rank
        raw = beta.where(condition, resid)

        # Áp dụng phương pháp A: Rolling Rank
        normalized = (raw.rolling(rank_window).rank(pct=True) * 2) - 1

        # Negate
        signal = -normalized

        return -signal.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_267_tanh(df, window=5, norm_window=70):
        # Tính log volume để chuẩn hóa độ lệch
        vol = df.get('matchingVolume', df.get('volume', 1))
        amt = df.get('amount', df['close'] * vol)
        log_amt = np.log1p(amt)

        # Tính returns
        returns = df['close'].pct_change()

        # Tính Std của amt (window 11 fix cứng)
        std_amt = log_amt.rolling(11).std()

        # Tính Quantile của std_amt (window 23, quantile 0.6 fix cứng)
        quantile_std = std_amt.rolling(23).quantile(0.6)

        # Compare để chọn: nếu greater -> Beta, else -> Resid
        condition = std_amt > quantile_std

        # Beta
        cov = returns.rolling(window).cov(log_amt)
        var = log_amt.rolling(window).var().replace(0, np.nan)
        beta = cov / var

        # Resid
        resid = returns - beta * log_amt

        # Combined raw signal
        raw = beta.where(condition, resid)

        # Phương pháp B: Dynamic Tanh
        std_raw = raw.rolling(norm_window).std().replace(0, np.nan)
        normalized = np.tanh(raw / std_raw)

        # Negate
        signal = -normalized

        return signal.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_267_zscore(df, window=5, norm_window=70):
        # Tính log volume để chuẩn hóa độ lệch
        vol = df.get('matchingVolume', df.get('volume', 1))
        amt = df.get('amount', df['close'] * vol)
        log_amt = np.log1p(amt)

        # Tính returns
        returns = df['close'].pct_change()

        # Tính Std của amt (window 11 fix cứng)
        std_amt = log_amt.rolling(11).std()

        # Tính Quantile của std_amt (window 23, quantile 0.6 fix cứng)
        quantile_std = std_amt.rolling(23).quantile(0.6)

        # Compare để chọn: nếu greater -> Beta, else -> Resid
        condition = std_amt > quantile_std

        # Beta
        cov = returns.rolling(window).cov(log_amt)
        var = log_amt.rolling(window).var().replace(0, np.nan)
        beta = cov / var

        # Resid
        resid = returns - beta * log_amt

        # Combined raw signal
        raw = beta.where(condition, resid)

        # Phương pháp C: Z-Score/Clip
        mean_raw = raw.rolling(norm_window).mean()
        std_raw = raw.rolling(norm_window).std().replace(0, np.nan)
        normalized = ((raw - mean_raw) / std_raw).clip(-1, 1)

        # Negate
        signal = -normalized

        return signal.fillna(0)

