    @staticmethod
    def alpha_factorminer_vn_267_wf(df, window=100, p1=0.1, p2=40):
        # Tính log volume để chuẩn hóa độ lệch
        vol = df.get('matchingVolume', df.get('volume', 1))
        amt = df.get('amount', df['close'] * vol)
        log_amt = np.log1p(amt)

        # Tính returns
        returns = df['close'].pct_change()

        # Tính Std của amt (window 11 fix cứng)
        std_amt = log_amt.rolling(11).std()

        # Tính Quantile của std_amt (window 23, quantile 0.6 fix cứng)
        quantile_std = std_amt.rolling(23).quantile(0.6)

        # Compare để chọn: nếu greater -> Beta, else -> Resid
        condition = std_amt > quantile_std

        # Beta
        cov = returns.rolling(window).cov(log_amt)
        var = log_amt.rolling(window).var().replace(0, np.nan)
        beta = cov / var

        # Resid
        resid = returns - beta * log_amt

        # Combined raw signal
        raw = beta.where(condition, resid)

        # Phương pháp E: Winsorized Fisher
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)

        # Fisher Transform để xấp xỉ [-1,1]
        numerator = (winsorized - low)
        denominator = (high - low).replace(0, np.nan)
        scaled = (numerator / denominator) * 1.98 - 0.99
        scaled = scaled.clip(-0.9999, 0.9999)
        normalized = np.arctanh(scaled)

        # Negate
        signal = -normalized

        return -signal.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_268_rank(df, window=65):
        high = df['high']
        low = df['low']
        close = df['close']
        atr_5 = (high - low).rolling(5).mean()
        atr_5_mean = atr_5.rolling(window).mean()
        atr_5_median = atr_5.rolling(window).median()
        rsi_14 = close.diff().clip(lower=0).rolling(14).mean() / close.diff().abs().rolling(14).mean()
        rsi_14 = 100 - 100 / (1 + rsi_14)
        rsi_14.fillna(50, inplace=True)
        delta_rsi_3 = rsi_14.diff(3)
        condition = atr_5_mean > atr_5_median
        zscore_rsi = (rsi_14 - rsi_14.rolling(window).mean()) / rsi_14.rolling(window).std()
        zscore_delta_rsi = (delta_rsi_3 - delta_rsi_3.rolling(window).mean()) / delta_rsi_3.rolling(window).std()
        raw = pd.Series(np.where(condition, -zscore_rsi, -zscore_delta_rsi), index=df.index)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

