        zscore_rsi = (rsi_14 - rsi_14.rolling(window).mean()) / rsi_14.rolling(window).std()
        zscore_delta_rsi = (delta_rsi_3 - delta_rsi_3.rolling(window).mean()) / delta_rsi_3.rolling(window).std()
        raw = pd.Series(np.where(condition, -zscore_rsi, -zscore_delta_rsi), index=df.index)
        low_q = raw.rolling(p2).quantile(p1)
