    @staticmethod
    def alpha_factorminer_vn_270_rank(df, window=5):
        returns = df['close'].pct_change()
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        mean_amt_13 = amount.rolling(13).mean()
        div_amt_mean = amount / mean_amt_13.replace(0, np.nan)
        amt_series = div_amt_mean.ffill().fillna(0)
        ret_series = returns.ffill().fillna(0)
        # CoSkew = Pearson correlation cubed between returns and squared amt
        # Using rolling covariance and variance approach for speed
        cov = ret_series.rolling(window).cov(amt_series**2)
        var_ret = ret_series.rolling(window).var().replace(0, np.nan)
        var_amt2 = (amt_series**2).rolling(window).var().replace(0, np.nan)
        skew = cov / (np.sqrt(var_ret) * np.sqrt(var_amt2) + 1e-9)
        raw = -skew
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

