    @staticmethod
    def alpha_factorminer_vn_272_rank(df, window=100):
        ret = df['close'].pct_change(fill_method=None)
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        tsmax_amt = amt.rolling(window, min_periods=1).max().replace(0, np.nan)
        condition = ret > 0
        raw = pd.Series(np.where(condition, amt / tsmax_amt, -(amt / tsmax_amt)), index=df.index)
        raw = -raw
        raw = raw.ffill().fillna(0)
        result = (raw.rolling(window, min_periods=1).rank(pct=True) * 2) - 1
        return -result.replace([np.inf, -np.inf], 0).fillna(0)

    @staticmethod
    def alpha_factorminer_vn_272_tanh(df, window=15):
        ret = df['close'].pct_change(fill_method=None)
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        tsmax_amt = amt.rolling(window, min_periods=1).max().replace(0, np.nan)
        condition = ret > 0
        raw = pd.Series(np.where(condition, amt / tsmax_amt, -(amt / tsmax_amt)), index=df.index)
        raw = -raw
