        std7 = close.rolling(7).std()
        raw_ret = (close - ema7) / std7
        ret = close.pct_change()
        coskew_num = ((ret - ret.rolling(window).mean()) * ((raw_ret - raw_ret.rolling(window).mean()) ** 2)).rolling(window).sum() / window
        coskew_den = ret.rolling(window).std() * (raw_ret.rolling(window).std() ** 2)
        cscale_coskew = coskew_num / coskew_den
        raw = -cscale_coskew
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized

