    @staticmethod
    def alpha_factorminer_vn_279_rank(df, window=85):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        returns = close.pct_change()
        # corr: volume vs returns over window
        vol_mean = volume.rolling(window).mean()
        ret_mean = returns.rolling(window).mean()
        cov = (volume * returns).rolling(window).mean() - vol_mean * ret_mean
        vol_std = volume.rolling(window).std()
        ret_std = returns.rolling(window).std()
        corr = cov / (vol_std * ret_std + 1e-9)
        # regbeta: slope of returns on volume
        x = volume
        y = returns
        x_mean = x.rolling(11).mean()
        y_mean = y.rolling(11).mean()
        cov_xy = (x * y).rolling(11).mean() - x_mean * y_mean
        var_x = (x ** 2).rolling(11).mean() - x_mean ** 2
        beta = cov_xy / var_x.replace(0, np.nan)
        # regresi: residual = y - beta * x
        resid = y - beta * x
        # raw signal base: CsZScore on beta or resid
        cond = corr > 0
        # compute zscore for both
        beta_mean = beta.rolling(11).mean()
        beta_std = beta.rolling(11).std()
        beta_z = (beta - beta_mean) / beta_std.replace(0, np.nan)
        resid_mean = resid.rolling(11).mean()
        resid_std = resid.rolling(11).std()
        resid_z = (resid - resid_mean) / resid_std.replace(0, np.nan)
        # Neg
        raw = pd.Series(np.where(cond, beta_z, resid_z), index=df.index)
        # fillna
        raw = raw.ffill().fillna(0)
        # Rolling Rank normalization A
        norm = raw.rolling(window).rank(pct=True) * 2 - 1
        return norm.fillna(0).replace([np.inf, -np.inf], 0)

