    @staticmethod
    def alpha_factorminer_vn_281_wf(df, window=30, sub_window=7, p1=0.05):
        # p1 là quantile để cắt Winsorized, fix cứng p1=0.05
        returns = df['close'].pct_change()
        std_ret = returns.rolling(sub_window).std()
        hl = df['high'] - df['low']
        cov = std_ret.rolling(window).cov(hl)
        var_hl = hl.rolling(window).var().replace(0, np.nan)
        beta = cov / var_hl
        raw = -beta
        # Chuẩn hóa Winsorized Fisher (E)
        low = raw.rolling(window).quantile(p1)
        high = raw.rolling(window).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        epsilon = 1e-9
        scaled = ((winsorized - low) / (high - low + epsilon)) * 1.98 - 0.99
        normalized = np.arctanh(scaled)
        # Xử lý NaN: nếu nan do arctanh(±1) là vô cùng, thay bằng 0
        normalized = normalized.replace([np.inf, -np.inf], np.nan)
        normalized = normalized.ffill().fillna(0)
        # Clip để đảm bảo nằm trong [-1, 1]
        normalized = normalized.clip(-1, 1)
        return normalized

    @staticmethod
    def alpha_factorminer_vn_282_rank(df, window=10):
        high = df['high']
        close = df['close']
        ts_max_high = high.rolling(window).max()
        cond = close > ts_max_high
        delta_close_2 = close.diff(2)
        cs_zscore_1 = (delta_close_2 - delta_close_2.expanding().mean()) / delta_close_2.expanding().std()
        delta_neg = -delta_close_2
        cs_zscore_2 = (delta_neg - delta_neg.expanding().mean()) / delta_neg.expanding().std()
        raw = pd.Series(np.where(cond, cs_zscore_1, cs_zscore_2), index=df.index)
        return -(raw.rolling(window).rank(pct=True) * 2) - 1

