        ret = df['close'].pct_change().fillna(0)
        # Tính volume delta và TsMad
        vol = df.get('matchingVolume', df.get('volume', 1))
        vol_delta = vol.diff(1).fillna(0)
        vol_mad = (vol - vol.rolling(window).mean()).abs().rolling(window).mean().fillna(0)
        # Sign(returns) * (vol_delta / vol_mad)
        raw = np.sign(ret) * vol_delta / (vol_mad + 1e-9)
        # Chuẩn hóa Neg và CsScale tương đương: đảo dấu và chuẩn hóa [-1,1]
        raw = -raw
        # Rolling Rank
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -result.fillna(0)

