        vwap_rank_norm = (vwap_rank - vwap_rank.rolling(window).mean()) / vwap_rank.rolling(window).std()
        div_amt_close_rank_norm = (div_amt_close_rank - div_amt_close_rank.rolling(window).mean()) / div_amt_close_rank.rolling(window).std()
        raw = vwap_rank_norm.rolling(window).corr(div_amt_close_rank_norm)
        raw = raw.ffill().fillna(0)
