    @staticmethod
    def alpha_factorminer_vn_304_k(df, window=20):
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        returns = df['close'].pct_change().fillna(0)
        window_13 = 13
        window_31 = 31
        window_slope = 13
        # Beta calculation: slope from regression of amt on returns
        amt_roll = amt.rolling(window_13)
        returns_roll = returns.rolling(window_13)
        beta = amt_roll.cov(returns_roll) / (returns_roll.var().replace(0, np.nan)).replace(np.nan, 0)
        mean_beta = beta.rolling(window_31).mean().fillna(0)
        # TsLinRegSlope of amt over window_slope
        days = pd.Series(np.arange(len(df)), index=df.index)
        x = days
        y = amt
        w = window_slope
        # slope = Cov(y,x)/Var(x) using rolling
        slope = y.rolling(w).cov(x) / (x.rolling(w).var().replace(0, np.nan)).replace(np.nan, 0)
        cs_slope = (slope - slope.mean()) / slope.std().replace(0, np.nan).replace(np.nan, 0)
        # IfElse logic: if beta > mean_beta, use cs_slope, else use -cs_slope (Neg of cs_slope)
        condition = beta > mean_beta
        raw = pd.Series(np.where(condition, cs_slope, -cs_slope), index=df.index)
        # Rolling rank normalization
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        return result.fillna(0)

