    @staticmethod
    def alpha_factorminer_vn_305_rank(df, window=60, sub_window=40):
        close = df['close']
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        returns = close.pct_change()
        # Compute amount/close ratio
        ratio = amount / close
        # Compute skew of ratio
        skew_val = ratio.rolling(window).skew()
        # Cross-sectional mean of skew
        cs_mean = skew_val.expanding().mean()
        # Condition: skew > cs_mean
        cond = skew_val > cs_mean
        # For True branch: CsZScore of RegBeta(returns, ratio, sub_window)
        # Rolling covariance of returns and ratio
        cov = returns.rolling(sub_window).cov(ratio)
        var_ratio = ratio.rolling(sub_window).var().replace(0, np.nan)
        beta = cov / var_ratio
        # Z-score of beta (cross-sectional)
        beta_z = (beta - beta.expanding().mean()) / beta.expanding().std().replace(0, np.nan)
        # For False branch: CsZScore of RegResi - use regression residuals
        # y = returns, x = ratio, slope = beta, intercept can be approximated
        pred = beta * ratio + (returns.rolling(sub_window).mean() - beta * ratio.rolling(sub_window).mean())
        resid = returns - pred
        resid_z = (resid - resid.expanding().mean()) / resid.expanding().std().replace(0, np.nan)
        # Combine using np.where
        raw_signal = pd.Series(np.where(cond, beta_z, resid_z), index=df.index)
        # Normalize using Rolling Rank (Method A)
        norm = (raw_signal.rolling(window).rank(pct=True) * 2) - 1
        # Negate
        final = -norm
        return -final.fillna(0)

