    @staticmethod
    def alpha_factorminer_vn_305_wf(df, window=70, sub_window=30, p1=0.05):
        close = df['close']
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        returns = close.pct_change()
        ratio = amount / close
        skew_val = ratio.rolling(window).skew()
        cs_mean = skew_val.expanding().mean()
        cond = skew_val > cs_mean
        cov = returns.rolling(sub_window).cov(ratio)
        var_ratio = ratio.rolling(sub_window).var().replace(0, np.nan)
        beta = cov / var_ratio
        beta_z = (beta - beta.expanding().mean()) / beta.expanding().std().replace(0, np.nan)
        pred = beta * ratio + (returns.rolling(sub_window).mean() - beta * ratio.rolling(sub_window).mean())
        resid = returns - pred
        resid_z = (resid - resid.expanding().mean()) / resid.expanding().std().replace(0, np.nan)
        raw_signal = pd.Series(np.where(cond, beta_z, resid_z), index=df.index)
        # Normalize using Winsorized Fisher (Method E)
        p2 = window
        low = raw_signal.rolling(p2).quantile(p1)
        high = raw_signal.rolling(p2).quantile(1 - p1)
        winsorized = raw_signal.clip(lower=low, upper=high, axis=0)
        # Fisher Transform
        scaled = ((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99
        norm = np.arctanh(scaled.clip(-0.99, 0.99))
        final = -norm
        return -final.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_306_rank(df, window=80):
        close = df['close']
        amount = df.get('amount', close * df.get('matchingVolume', df.get('volume', 1)))
        vol_dollar = amount
        returns = close.pct_change().fillna(0)
        weight = vol_dollar / close
        # Calculate centered returns and weight for skewness
        mean_ret = returns.rolling(window).mean()
        centered = returns - mean_ret
        # Co-skewness numerator and denominator
        num = (centered ** 2 * weight).rolling(window).sum()
        denom = ((centered ** 2).rolling(window).sum() + 1e-9) ** 0.5 * ((weight ** 2).rolling(window).sum() + 1e-9) ** 0.5
        coskew = num / denom
        # Neutralize cross-sectionally (simplified: subtract mean)
        neutral = coskew - coskew.rolling(window).mean()
        raw = -neutral
        # Normalized via Rolling Rank (Case A)
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        return result

