    @staticmethod
    def alpha_factorminer_vn_311_rank(df, window_skew=55):
        returns = df['close'].pct_change().fillna(0)
        volume = df.get('matchingVolume', df.get('volume', 1))
        valid_idx = returns.notna() & volume.notna()
        returns = returns.where(valid_idx, 0)
        volume = volume.where(valid_idx, 1)
        returns_clean = returns.fillna(0)
        volume_clean = volume.fillna(1)
        roll = window_skew
        mean_r = returns_clean.rolling(roll).mean()
        mean_v = volume_clean.rolling(roll).mean()
        num = ((returns_clean - mean_r) * (volume_clean - mean_v) * (volume_clean - mean_v)).rolling(roll).sum()
        denom = (roll * (returns_clean - mean_r).rolling(roll).std().fillna(1) * (volume_clean - mean_v).rolling(roll).var().fillna(1) + 1e-9)
        coskew = num / denom
        condition = coskew > 0
        slope_returns = (returns_clean.rolling(7).cov(pd.Series(range(7), index=df.index[-7:] if len(df)>=7 else df.index)) / returns_clean.rolling(7).var().replace(0, np.nan)).fillna(0)
        slope_volume = (volume_clean.rolling(7).cov(pd.Series(range(7), index=df.index[-7:] if len(df)>=7 else df.index)) / volume_clean.rolling(7).var().replace(0, np.nan)).fillna(0)
        cs_slope_ret = (slope_returns - slope_returns.rolling(21).mean()) / slope_returns.rolling(21).std().replace(0, np.nan)
        cs_slope_vol = (slope_volume - slope_volume.rolling(21).mean()) / slope_volume.rolling(21).std().replace(0, np.nan)
        signal = pd.Series(np.where(condition, cs_slope_ret, cs_slope_vol), index=df.index).fillna(0)
        result = -signal
        normalized = (result.rolling(20).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

