    @staticmethod
    def alpha_factorminer_vn_313_e(df: pd.DataFrame, p1: float = 0.1, p2: int = 252) -> pd.Series:
        # Tinh x (time index) cho regresssion
        amt = df.get('amount', df['close'] * df['matchingVolume'])
        x = pd.Series(np.arange(len(df)), index=df.index)
        w = 17
        # TsLinRegSlope
        slope_linreg = amt.rolling(w).cov(x) / x.rolling(w).var().replace(0, np.nan)
        # TheilSenSlope: median of slopes between all pairs
        # Su dung convolution de tinh slope cho tung cap
        def alpha_factorminer_vn_313_e(series):
            n = len(series)
            if n < 2:
                return -np.nan
            idx = np.arange(n)
            pairs = []
            for i in range(n):
                for j in range(i+1, n):
                    if series[j] != series[i]:
                        pairs.append((series[j] - series[i]) / (idx[j] - idx[i]))
            if len(pairs) == 0:
                return np.nan
            return np.median(pairs)
        # Vectorized TheilSen (avoid loop)
        # Use expanding window to compute TheilSen for each point
        slopes = np.full(len(amt), np.nan)
        for i in range(w-1, len(amt)):
            sub_series = amt.iloc[i-w+1:i+1].values
            n = len(sub_series)
            if n < 2:
                continue
            idx_vec = np.arange(n)
            diff_y = sub_series[:, None] - sub_series[None, :]
            diff_x = idx_vec[:, None] - idx_vec[None, :]
            mask = diff_x != 0
            slopes_pairs = diff_y[mask] / diff_x[mask]
            if len(slopes_pairs) == 0:
                continue
            slopes[i] = np.median(slopes_pairs)
        slope_theil = pd.Series(slopes, index=amt.index)
        # Sub
        raw = slope_linreg - slope_theil
        # CsZScore: cross-sectional z-score (here time series, use rolling)
        # Interpret as TsZScore
        mean_ = raw.rolling(w).mean()
        std_ = raw.rolling(w).std().replace(0, np.nan)
        raw_norm = (raw - mean_) / std_
        # Neg
        neg_raw = -raw_norm
        # Winsorized Fisher Transform
        low = neg_raw.rolling(p2).quantile(p1)
        high = neg_raw.rolling(p2).quantile(1 - p1)
        winsorized = neg_raw.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return normalized.fillna(0).replace([np.inf, -np.inf], 0).replace([np.nan], 0)

    @staticmethod
    def alpha_factorminer_vn_313_rank(df, window=30):
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        days = pd.Series(np.arange(len(df)), index=df.index)
        slope_ls = (amt.rolling(window).cov(days) / days.rolling(window).var().replace(0, np.nan))
        slope_ts = (amt - amt.rolling(window).mean()) / (days - days.rolling(window).mean()).rolling(window).std().replace(0, np.nan)
        slope_ts = slope_ts * (amt.rolling(window).std().replace(0, np.nan) / days.rolling(window).std().replace(0, np.nan))
        raw = (slope_ls - slope_ts).fillna(0)
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        return signal.fillna(0)

