    @staticmethod
    def alpha_factorminer_vn_313_wf(df, window=30, percentile=0.1):
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        days = pd.Series(np.arange(len(df)), index=df.index)
        slope_ls = (amt.rolling(window).cov(days) / days.rolling(window).var().replace(0, np.nan))
        slope_ts = (amt - amt.rolling(window).mean()) / (days - days.rolling(window).mean()).rolling(window).std().replace(0, np.nan)
        slope_ts = slope_ts * (amt.rolling(window).std().replace(0, np.nan) / days.rolling(window).std().replace(0, np.nan))
