    @staticmethod
    def alpha_factorminer_vn_314_rank(df, window=85):
        delta_close = df['close'].diff(3)
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        delta_vwap = vwap.diff(3)
        # Regression residual using vectorized slope
        y = delta_close
        x = delta_vwap
        slope = y.rolling(window).cov(x) / x.rolling(window).var().replace(0, np.nan)
        intercept = y.rolling(window).mean() - slope * x.rolling(window).mean()
        residual = y - (slope * x + intercept)
        raw = -residual
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

