    @staticmethod
    def alpha_factorminer_vn_315_g(df, window=10):
        returns = df['close'].pct_change().fillna(0)
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        var_window = 15
        percentile = 0.05
        var_series = returns.rolling(var_window).quantile(percentile)
        cs_mean_var = var_series.rolling(window).mean()
        condition = var_series > cs_mean_var
        # Beta regression using window=11
        w = 11
        x = vwap
        y = returns
        cov = y.rolling(w).cov(x)
        var_x = x.rolling(w).var().replace(0, np.nan)
        beta = cov / var_x
        z_beta = (beta - beta.rolling(w).mean()) / beta.rolling(w).std().replace(0, np.nan)
        # Residual using window=11
        mean_y = y.rolling(w).mean()
        mean_x = x.rolling(w).mean()
        alpha_resi = mean_y - beta * mean_x
        fitted = beta * x + alpha_resi
        resid = y - fitted
        z_resi = (resid - resid.rolling(w).mean()) / resid.rolling(w).std().replace(0, np.nan)
        raw = pd.Series(np.where(condition, z_beta, z_resi), index=df.index).fillna(0)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        signal = -normalized
        return -signal.replace([np.inf, -np.inf], 0).fillna(0)

