    @staticmethod
    def alpha_factorminer_vn_316_rank(df, window=45):
        close = df['close']
        slope_linreg = close.rolling(window).cov(pd.Series(np.arange(window), index=close.index[:window])) / close.rolling(window).var().replace(0, np.nan)
        slope_theilsen = np.tile(np.nan, len(df))
        for i in range(window - 1, len(df)):
            y = close.iloc[i - window + 1:i + 1].values
            x = np.arange(window)
            slopes = (y[:, None] - y[None, :]) / (x[:, None] - x[None, :] + 1e-9)
            slope_theilsen[i] = np.median(slopes[np.isfinite(slopes)])
        slope_theilsen = pd.Series(slope_theilsen, index=df.index)
