    @staticmethod
    def alpha_factorminer_vn_317_rank(df, window=10):
        close = df['close']
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        ret = close.pct_change().fillna(0).replace([np.inf, -np.inf], 0)
        downside_std = ret.copy()
        below_mask = ret < 0
        downside_std.loc[below_mask] = (ret[below_mask]**2).rolling(window=window).mean().pow(0.5)
        downside_std = downside_std.fillna(0)
        mean_downside = downside_std.rolling(window=window, min_periods=1).mean().fillna(0)
        reg_beta = ret.rolling(11).cov(vwap) / vwap.rolling(11).var().replace(0, np.nan)
        reg_beta = reg_beta.fillna(0)
        reg_resi = ret - reg_beta * vwap
        beta_z = (reg_beta - reg_beta.rolling(11).mean()) / reg_beta.rolling(11).std()
        beta_z = beta_z.fillna(0).replace([np.inf, -np.inf], 0)
        resi_z = (reg_resi - reg_resi.rolling(11).mean()) / reg_resi.rolling(11).std()
        resi_z = resi_z.fillna(0).replace([np.inf, -np.inf], 0)
        cond = downside_std > mean_downside
        raw = pd.Series(np.where(cond, beta_z, resi_z), index=df.index)
        result = -raw
        normalized = (result.rolling(window).rank(pct=True) * 2) - 1
        return -normalized

