    @staticmethod
    def alpha_factorminer_vn_317_wf(df, window=10, p=0.9):
        close = df['close']
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        ret = close.pct_change().fillna(0).replace([np.inf, -np.inf], 0)
