        raw = close.rolling(window).cov(pd.Series(np.arange(len(df)), index=df.index)) / close.rolling(window).var().replace(0, np.nan) - close.rolling(window).apply(lambda x: np.polyfit(np.arange(len(x)), x, 1)[0])
