    @staticmethod
    def alpha_factorminer_vn_319_wf(df, window=80, sub_window=20):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        close_vwap_ratio = df['close'] / vwap
        volume_mean = df['matchingVolume'].rolling(window).mean()
        volume_ratio = df['matchingVolume'] / volume_mean
        entropy1 = -((close_vwap_ratio * np.log(close_vwap_ratio.clip(1e-9, None))).rolling(window).sum())
        entropy2 = -((volume_ratio * np.log(volume_ratio.clip(1e-9, None))).rolling(window).sum())
        raw = -(entropy1 - entropy2)
        # Winsorized Fisher normalization with p1=0.05 hardcoded
        p1 = 0.05
        low = raw.rolling(sub_window).quantile(p1)
        high = raw.rolling(sub_window).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        signal = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        signal = signal.fillna(0)
        return signal

    @staticmethod
    def alpha_factorminer_vn_320_rank(df, window=10):
        # Tính log return -cho high và low
        log_high = np.log(df['high'] / df['high'].shift(1))
        log_low = np.log(df['low'] / df['low'].shift(1))
        # Tính rolling std của log return
        std_high = log_high.rolling(window).std()
        std_low = log_low.rolling(window).std()
        raw = std_high - std_low
        # Âm dấu: Neg = -raw
        neg_raw = -raw
        # Chuẩn hóa rolling rank (A) lên [-1,1]
        neg_rank = (neg_raw.rolling(window).rank(pct=True) * 2) - 1
        return neg_rank.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_320_tanh(df, window=5):
        log_high = np.log(df['high'] / df['high'].shift(1))
        log_low = np.log(df['low'] / df['low'].shift(1))
        std_high = log_high.rolling(window).std()
        std_low = log_low.rolling(window).std()
        raw = std_high - std_low
        neg_raw = -raw
        # Dynamic tanh (B)
        norm_signal = np.tanh(neg_raw / (neg_raw.rolling(window).std() + 1e-9))
        return -norm_signal.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_320_zscore(df, window=10):
        log_high = np.log(df['high'] / df['high'].shift(1))
        log_low = np.log(df['low'] / df['low'].shift(1))
        std_high = log_high.rolling(window).std()
        std_low = log_low.rolling(window).std()
        raw = std_high - std_low
        neg_raw = -raw
        # Rolling z-score (C)
        mean_ = neg_raw.rolling(window).mean()
        std_ = neg_raw.rolling(window).std().replace(0, np.nan)
        zscore = ((neg_raw - mean_) / std_).clip(-1, 1)
        return -zscore.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_320_sign(df, window=15):
        log_high = np.log(df['high'] / df['high'].shift(1))
        log_low = np.log(df['low'] / df['low'].shift(1))
        std_high = log_high.rolling(window).std()
        std_low = log_low.rolling(window).std()
        raw = std_high - std_low
        neg_raw = -raw
        # Sign binary (D)
        signal = np.sign(neg_raw)
        return -pd.Series(signal, index=df.index).fillna(0)

    @staticmethod
    def alpha_factorminer_vn_320_wf(df, window=10, quantile=0.9):
        # WARNING: quantile is hardcoded inside function to avoid third param? Actually this is allowed as 2nd param
        log_high = np.log(df['high'] / df['high'].shift(1))
        log_low = np.log(df['low'] / df['low'].shift(1))
        std_high = log_high.rolling(window).std()
        std_low = log_low.rolling(window).std()
        raw = std_high - std_low
        neg_raw = -raw
        # Winsorized Fisher (E)
        low_q = neg_raw.rolling(window).quantile(quantile)
        high_q = neg_raw.rolling(window).quantile(1 - quantile)
        winsorized = neg_raw.clip(lower=low_q, upper=high_q)
        # Fisher transform
        denom = (high_q - low_q + 1e-9)
        normalized = np.arctanh(((winsorized - low_q) / denom) * 1.98 - 0.99)
        # Clip to [-1,1] to avoid overflow
        return -normalized.clip(-1, 1).fillna(0)

    @staticmethod
    def alpha_factorminer_vn_321_rank(df, window=30):
        close = df['close']
        bb_width = (close.rolling(20).max() - close.rolling(20).min()) / close.rolling(20).mean()
        returns = close.pct_change()
        std_returns = returns.rolling(20).std()
        raw = bb_width.rolling(window).corr(std_returns)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
