    @staticmethod
    def alpha_factorminer_vn_323_rank(df, window=7, sub_window=3):
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        returns = df['close'].pct_change()

        mean_amt_7 = amt.rolling(window).mean()
        delta_mean = mean_amt_7.diff(sub_window)

        # Beta: slope of returns vs amt
        x = amt.rolling(11)
        y = returns.rolling(11)
        beta = y.cov(x) / x.var().replace(0, np.nan)
        cs_zscore_beta = ((beta - beta.expanding().mean()) / beta.expanding().std()).clip(-1, 1)

        # Residual: returns - beta * amt
        amt_series = amt
        beta_full = returns.rolling(11).cov(amt_series.rolling(11)) / amt_series.rolling(11).var().replace(0, np.nan)
        resid = returns - beta_full * amt_series
        cs_zscore_resid = ((resid - resid.expanding().mean()) / resid.expanding().std()).clip(-1, 1)

        cond = delta_mean > 0
        raw = pd.Series(np.where(cond, cs_zscore_beta, cs_zscore_resid), index=df.index)

        signal = -raw
        signal_mean = signal.rolling(window).mean()
        signal_std = signal.rolling(window).std().replace(0, np.nan)
        normalized = ((signal - signal_mean) / signal_std).fillna(0).clip(-1, 1)
        return normalized

