    @staticmethod
    def alpha_factorminer_vn_325_rank(df, window=19, rank_window=21):
        # Tính returns chuẩn hóa
        returns = df['close'].pct_change().replace([np.inf, -np.inf], 0)
        volume = df.get('matchingVolume', df.get('volume', 1))
        # Volume log transform để chuẩn hóa scale
        volume_log = np.log1p(volume)
        # Tính correlation giữa volume và returns (rolling 19 periods)
        corr_vol_ret = volume_log.rolling(window).corr(returns).fillna(0)
        # Tạo mask: corr > 0
        mask = corr_vol_ret > 0
        # Tính amt và vwap
        close = df['close']
        high = df['high']
        low = df['low']
        vwap = df.get('vwap', (high + low + close) / 3)
        amt = df.get('amount', close * volume)
        # Tính RegBeta(amt, vwap, 11) - slope của amt theo vwap
        days = pd.Series(np.arange(len(df)), index=df.index)
        cov_amt_vwap = amt.rolling(11).cov(vwap)
        var_vwap = vwap.rolling(11).var().replace(0, np.nan)
        beta_amt_vwap = cov_amt_vwap / var_vwap
        beta_amt_vwap = beta_amt_vwap.fillna(0)
        # CsZScore(beta_amt_vwap)
        z_beta = ((beta_amt_vwap - beta_amt_vwap.mean()) / beta_amt_vwap.std().replace(0, np.nan)).fillna(0)
        # Tính RegResi(amt, vwap, 11) - residual = amt - (beta * vwap + intercept)
        intercept = amt.rolling(11).mean() - beta_amt_vwap * vwap.rolling(11).mean()
        residual = amt - (beta_amt_vwap * vwap + intercept)
        residual = residual.fillna(0)
        # CsZScore(residual)
        z_resi = ((residual - residual.mean()) / residual.std().replace(0, np.nan)).fillna(0)
        # If-Else logic
        raw = pd.Series(np.where(mask, z_beta, z_resi), index=df.index)
        # Áp dụng Rolling Rank Normalization
        signal = ((raw.rolling(rank_window).rank(pct=True) * 2) - 1).fillna(0)
        return signal

