        residual = amt - (beta_amt_vwap * vwap + intercept)
        residual = residual.fillna(0)
        # CsZScore(residual)
        z_resi = ((residual - residual.mean()) / residual.std().replace(0, np.nan)).fillna(0)
        # If-Else logic
        raw = pd.Series(np.where(mask, z_beta, z_resi), index=df.index)
        # Áp dụng Winsorized Fisher Normalization
        low = raw.rolling(p2).quantile(p1, interpolation='lower')
        high = raw.rolling(p2).quantile(1 - p1, interpolation='higher')
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        # Fisher Transform
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        # Replace inf/nan that can occur in arctanh
        normalized = normalized.replace([np.inf, -np.inf], np.nan).fillna(0)
