    @staticmethod
    def alpha_factorminer_vn_330_rank(df, window=10, rank_window=70):
        close = df['close']
        bollinger_range = (close - close.rolling(window).mean()).abs() / close.rolling(window).std()
        bollinger_range_mean = bollinger_range.rolling(rank_window).mean()
        days = pd.Series(np.arange(len(df)), index=df.index)
        slope = (close.rolling(window).cov(days) / days.rolling(window).var().replace(0, np.nan)).fillna(0)
        resid = close - (slope * days + close.rolling(window).mean())
        resid_zscore = (resid - resid.rolling(window).mean()) / resid.rolling(window).std().replace(0, np.nan)
        slope_zscore = (slope - slope.rolling(window).mean()) / slope.rolling(window).std().replace(0, np.nan)
        condition = bollinger_range > bollinger_range_mean
        raw = pd.Series(np.where(condition, resid_zscore, slope_zscore), index=df.index)
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -result.fillna(0).clip(-1, 1)

