    @staticmethod
    def alpha_factorminer_vn_332_rank(df, window=25):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        amount = df.get('amount', close * volume)
        returns = np.log(close / close.shift(1))
        days = np.arange(len(df))
        volume_ts = pd.Series(volume.values, index=df.index)
        amount_ts = pd.Series(amount.values, index=df.index)
        returns_ts = pd.Series(returns.values, index=df.index)
        cov_vol = volume_ts.rolling(window).cov(returns_ts)
        var_returns = returns_ts.rolling(window).var().replace(0, np.nan)
        beta_vol = cov_vol / var_returns
        cov_amt = amount_ts.rolling(window).cov(returns_ts)
        beta_amt = cov_amt / var_returns
