    @staticmethod
    def alpha_factorminer_vn_334_rank(df, window=90):
        high = df['high']
        low = df['low']
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        amount = df.get('amount', close * volume)
        vwap = amount / volume.replace(0, np.nan)
        vwap = vwap.fillna(method='ffill').fillna(close)
        returns = df['close'].pct_change()
        tr = pd.concat([high - low, (high - close.shift()).abs(), (low - close.shift()).abs()], axis=1).max(axis=1)
        atr = tr.rolling(7).mean()
        median_atr = atr.rolling(window).median()
        # Beta and residual
        x = vwap
        y = returns
        cov = y.rolling(13).cov(x)
        var_x = x.rolling(13).var().replace(0, np.nan)
        beta = cov / var_x
        # Residual
        resid = y - beta * x
        # Raw signal
        raw = pd.Series(np.where(atr > median_atr, -((y - y.rolling(13).mean()) / y.rolling(13).std()), -((resid - resid.rolling(13).mean()) / resid.rolling(13).std())), index=df.index)
        raw = raw.fillna(0)
        # Normalize A: Rolling Rank
        result = raw.rolling(window).rank(pct=True) * 2 - 1
        return -result.fillna(0)

