        mean_kurt = kurt.rolling(window).mean()
        cond = kurt > mean_kurt
        delta_close = df['close'].diff(3)
        zscore_delta = (delta_close - delta_close.rolling(sub_window).mean()) / delta_close.rolling(sub_window).std()
