        slope = cov / var_x
        zscore_slope = (slope - slope.rolling(sub_window).mean()) / slope.rolling(sub_window).std()
        raw = np.where(cond, neg_zscore_delta, zscore_slope.fillna(0))
        raw_series = pd.Series(raw, index=df.index).fillna(0)
        result = (raw_series.rolling(window).rank(pct=True) * 2) - 1
        return -result.fillna(0)

