        bol_range = 2 * std
        bol_range_mean = bol_range.rolling(window_ema).mean()
        condition = bol_range > bol_range_mean
        skew = returns.rolling(window).skew()
        skew_z = (skew - skew.rolling(window).mean()) / skew.rolling(window).std()
        ir = returns.rolling(window).mean() / returns.rolling(window).std().replace(0, np.nan)
        ir_z = (ir - ir.rolling(window).mean()) / ir.rolling(window).std()
        raw = pd.Series(np.where(condition, skew_z, ir_z), index=df.index)
