    @staticmethod
    def alpha_factorminer_vn_337_wf(df, window=20, window_ema=40, winsor_quantile=0.01):
        close = df['close']
        returns = close.pct_change()
        mid = close.rolling(window).mean()
        std = close.rolling(window).std()
        bol_range = 2 * std
        bol_range_mean = bol_range.rolling(window_ema).mean()
        condition = bol_range > bol_range_mean
        skew = returns.rolling(window).skew()
        skew_z = (skew - skew.rolling(window).mean()) / skew.rolling(window).std()
        ir = returns.rolling(window).mean() / returns.rolling(window).std().replace(0, np.nan)
        ir_z = (ir - ir.rolling(window).mean()) / ir.rolling(window).std()
        raw = pd.Series(np.where(condition, skew_z, ir_z), index=df.index)
        raw = raw.fillna(0)
        result = -raw
        p = winsor_quantile
        low = result.rolling(window).quantile(p)
        high = result.rolling(window).quantile(1 - p)
        winsorized = result.clip(lower=low, upper=high)
        norm = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return -norm

    @staticmethod
    def alpha_factorminer_vn_338_rank(df, window=40):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1)).astype(float)
        ret = close.pct_change().fillna(0)
        corr_9 = ret.rolling(window).corr(volume)
        delay_5 = corr_9.shift(5)
        raw = corr_9 - delay_5
        # rolling z-score negative
        mean = raw.rolling(window).mean()
        std = raw.rolling(window).std().replace(0, np.nan)
        z = (raw - mean) / std
        result = -z.clip(-1, 1)
        return -result.fillna(0)

