    @staticmethod
    def alpha_factorminer_vn_339_rank(df, window=17, median_window=41):
        close = df['close']
        returns = close.pct_change()
        # Ulcer Index (window)
        max_close = close.rolling(window).max()
        percent_drawdown = (close - max_close) / max_close * 100
        squared_avg = (percent_drawdown ** 2).rolling(window).mean()
        ulcer_index = np.sqrt(squared_avg)
        # Median of Ulcer Index (median_window)
        median_ui = ulcer_index.rolling(median_window).median()
        # Condition: greater than median
        condition = ulcer_index > median_ui
        # Cross-sectional Z-score of Skew(returns, 9)
        skew_9 = returns.rolling(9).skew()
        # Replace NaN/Inf for safe Z-score
        skew_9 = skew_9.replace([np.inf, -np.inf], np.nan)
        mean_skew = skew_9.mean()
        std_skew = skew_9.std()
        z_skew = (skew_9 - mean_skew) / std_skew.replace(0, np.nan)
        # Cross-sectional Z-score of Kurt(returns, 9)
        kurt_9 = returns.rolling(9).kurt()
        kurt_9 = kurt_9.replace([np.inf, -np.inf], np.nan)
        mean_kurt = kurt_9.mean()
        std_kurt = kurt_9.std()
        z_kurt = (kurt_9 - mean_kurt) / std_kurt.replace(0, np.nan)
        # IfElse
        raw = pd.Series(np.where(condition, -z_skew, z_kurt), index=df.index)
        # Normalization: Rolling Z-Score/Clip (case C)
        rolling_mean = raw.rolling(window).mean()
        rolling_std = raw.rolling(window).std()
        normalized = ((raw - rolling_mean) / rolling_std.replace(0, np.nan)).clip(-1, 1)
        normalized = normalized.fillna(0)
        return normalized

