    @staticmethod
    def alpha_factorminer_vn_339_wf(df, window=17, median_window=41, p1=0.05, p2=60):
        close = df['close']
        returns = close.pct_change()
        max_close = close.rolling(window).max()
        percent_drawdown = (close - max_close) / max_close * 100
        squared_avg = (percent_drawdown ** 2).rolling(window).mean()
