    @staticmethod
    def alpha_factorminer_vn_342_k(df, window=20):
        close = df['close']
        volume = df['matchingVolume']
        returns = close.pct_change().fillna(0)
        volume_log = np.log1p(volume)
        corr_vol_ret = returns.rolling(window).corr(volume_log)
        ts_z_ret = (returns - returns.rolling(window).mean()) / returns.rolling(window).std().replace(0, np.nan)
        ts_z_ret = ts_z_ret.fillna(0)
        ts_z_vol = (volume_log - volume_log.rolling(window).mean()) / volume_log.rolling(window).std().replace(0, np.nan)
        ts_z_vol = ts_z_vol.fillna(0)
        raw = pd.Series(np.where(corr_vol_ret > 0, ts_z_ret.rolling(window).rank(pct=True), -ts_z_vol.rolling(window).rank(pct=True)), index=df.index)
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
