    @staticmethod
    def alpha_factorminer_vn_345_rank(df, window_rank=50):
        try:
            close = df['close']
            returns = close.pct_change().fillna(0)
            rolling_15 = returns.rolling(15, min_periods=1)
            median_15 = rolling_15.median()
            mad_15 = (returns - median_15).abs().rolling(15, min_periods=1).median()
            mad_15 = mad_15.replace(0, np.nan).ffill().fillna(1e-9)
            robust_z = (returns - median_15) / (mad_15 * 1.4826)
            condition = robust_z > 0
            std_7 = returns.rolling(7, min_periods=1).std().fillna(0)
            std_7_cs = (std_7 - std_7.min()) / (std_7.max() - std_7.min() + 1e-9)
            mean_15 = returns.rolling(15, min_periods=1).mean().fillna(0)
            mean_15_cs = (mean_15 - mean_15.min()) / (mean_15.max() - mean_15.min() + 1e-9)
            raw = pd.Series(np.where(condition, std_7_cs, mean_15_cs), index=df.index) * -1
            normalized = raw.rolling(window_rank, min_periods=1).rank(pct=True) * 2 - 1
            return normalized.fillna(0)
        except:
            return pd.Series(np.zeros(len(df)), index=df.index)

