    @staticmethod
    def alpha_factorminer_vn_346_rank(df, window=95):
        ret = df['close'].pct_change().fillna(0)
        vol = df.get('matchingVolume', df.get('volume', 1))
        x = ret * vol
        x_mean = x.rolling(window, min_periods=1).mean()
        ret_mean = ret.rolling(window, min_periods=1).mean()
        cov = (ret * x).rolling(window, min_periods=1).mean() - ret_mean * x_mean
        var_x = (x ** 2).rolling(window, min_periods=1).mean() - x_mean ** 2
        beta = cov / var_x.replace(0, np.nan)
        resid = ret - beta * (x - x_mean) - ret_mean
        resid = resid.ffill().fillna(0)
        norm = resid.rolling(window, min_periods=1).rank(pct=True) * 2 - 1
        return norm.ffill().fillna(0)

