    @staticmethod
    def alpha_factorminer_vn_350_rank(df, window=75):
        ret = df['close'].pct_change()
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        ret_center = ret - ret.rolling(window).mean()
        vwap_center = vwap - vwap.rolling(window).mean()
        cov = (ret_center * vwap_center).rolling(window).sum()
        var_ret = (ret_center ** 2).rolling(window).sum()
        std_ret = np.sqrt(var_ret.replace(0, np.nan))
        coskew = cov / (std_ret + 1e-9)
        raw = -coskew
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

