    @staticmethod
    def alpha_factorminer_vn_352_rank(df, window=21):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        price_chg = df['close'].pct_change()
        vwap_chg = vwap.pct_change()
        coskew = (price_chg.rolling(window).skew() * vwap_chg.rolling(window).skew()).fillna(0)
        cokurt = (price_chg.rolling(window).kurt() * vwap_chg.rolling(window).kurt()).fillna(0)
        # If coskew > 0 then z-score(coskew) else -z-score(cokurt)
        coskew_z = (coskew - coskew.mean()) / coskew.std().replace(0, np.nan)
        cokurt_z = (cokurt - cokurt.mean()) / cokurt.std().replace(0, np.nan)
        signal = pd.Series(np.where(coskew > 0, coskew_z, -cokurt_z), index=df.index).fillna(0)
        # Rolling Rank to [-1,1]
        return (signal.rolling(window).rank(pct=True) * 2 - 1).fillna(0)

    @staticmethod
    def alpha_factorminer_vn_352_tanh(df, window=20):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
