        vwap_chg = vwap.pct_change()
        coskew = (price_chg.rolling(window).skew() * vwap_chg.rolling(window).skew()).fillna(0)
        cokurt = (price_chg.rolling(window).kurt() * vwap_chg.rolling(window).kurt()).fillna(0)
        coskew_std = coskew.rolling(window).std().replace(0, np.nan)
        cokurt_std = cokurt.rolling(window).std().replace(0, np.nan)
        coskew_norm = coskew / coskew_std
        cokurt_norm = -cokurt / cokurt_std
        signal = pd.Series(np.where(coskew > 0, coskew_norm, cokurt_norm), index=df.index).fillna(0)
        return -np.tanh(signal).fillna(0)

