        coskew_z = ((coskew - coskew.rolling(window).mean()) / coskew.rolling(window).std().replace(0, np.nan)).fillna(0)
        cokurt_z = ((-cokurt - (-cokurt).rolling(window).mean()) / (-cokurt).rolling(window).std().replace(0, np.nan)).fillna(0)
