    @staticmethod
    def alpha_factorminer_vn_352_wf(df, window=30, p1=0.7):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        price_chg = df['close'].pct_change()
        vwap_chg = vwap.pct_change()
        coskew = (price_chg.rolling(window).skew() * vwap_chg.rolling(window).skew()).fillna(0)
        cokurt = (price_chg.rolling(window).kurt() * vwap_chg.rolling(window).kurt()).fillna(0)
        coskew_z = pd.Series(np.where(coskew > 0, coskew, -cokurt), index=df.index).fillna(0)
        # Winsorized Fisher Transform
        low = coskew_z.rolling(window).quantile(p1)
        high = coskew_z.rolling(window).quantile(1 - p1)
        winsorized = coskew_z.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_353_rank(df, window=15):
        close = df['close']
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        returns = close.pct_change().fillna(0)
        # Ulcer Index: sqrt(mean of squared drawdowns) over window
        max_close = close.rolling(window, min_periods=1).max()
        drawdown = (close - max_close) / max_close
        drawdown_sq = drawdown.pow(2)
        ulcer = drawdown_sq.rolling(window, min_periods=1).mean().pow(0.5)
        # CoSkew: third cross-moment / (std1^2 * std2)
        ret_mean = returns.rolling(window, min_periods=1).mean()
        vwap_mean = vwap.rolling(window, min_periods=1).mean()
        cov_ret_vwap = (returns - ret_mean).mul(vwap - vwap_mean).rolling(window, min_periods=1).mean()
        var_ret = (returns - ret_mean).pow(2).rolling(window, min_periods=1).mean().replace(0, np.nan)
        var_vwap = (vwap - vwap_mean).pow(2).rolling(window, min_periods=1).mean().replace(0, np.nan)
        std_ret = var_ret.pow(0.5)
        std_vwap = var_vwap.pow(0.5)
        coskew = ((returns - ret_mean).pow(2).mul(vwap - vwap_mean)).rolling(window, min_periods=1).mean() / (var_ret * std_vwap + 1e-9)
        abs_coskew = coskew.abs()
        raw = ulcer - abs_coskew
        raw = -raw
        raw = raw.replace([np.inf, -np.inf], np.nan)
        normalized = (raw.rolling(window, min_periods=1).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

