    @staticmethod
    def alpha_factorminer_vn_354_wf(df, window=20, sub_window=90, winsor_quantile=0.05):
        close = df['close']
        returns = close.pct_change().fillna(0)
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        entropy_series = pd.Series(index=df.index, dtype=float)
        for i in range(window, len(df) + 1):
            block = returns.iloc[i - window:i]
            valid = block[block != 0]
            if len(valid) < 2:
                entropy_series.iloc[i - 1] = 0.0
            else:
                prob = valid.value_counts(normalize=True)
                entropy_series.iloc[i - 1] = -np.sum(prob * np.log(prob + 1e-12))
        ts_entropy = entropy_series.shift(0)
        mean_entropy = ts_entropy.rolling(sub_window).mean()
        condition = ts_entropy > mean_entropy
        y = returns
        x = amt.pct_change().fillna(0)
        cov = y.rolling(11).cov(x)
        var_x = x.rolling(11).var().replace(0, np.nan)
        beta = cov / var_x
        beta_z = (beta - beta.rolling(11).mean()) / beta.rolling(11).std().replace(0, np.nan)
        slope = beta
        intercept = y.rolling(11).mean() - slope * x.rolling(11).mean()
        resid = y - (intercept + slope * x)
        resid_z = (resid - resid.rolling(11).mean()) / resid.rolling(11).std().replace(0, np.nan)
        raw = pd.Series(np.where(condition, beta_z, resid_z), index=df.index)
        raw = -raw
        # Chuẩn hóa Winsorized Fisher
        p1 = winsor_quantile
        p2 = window
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        numerator = (winsorized - low)
        denominator = (high - low + 1e-9)
        fisher_input = (numerator / denominator) * 1.98 - 0.99
        fisher_input = fisher_input.clip(-0.99, 0.99)
        norm = np.arctanh(fisher_input)
        return -norm.ffill().fillna(0)

    @staticmethod
    def alpha_factorminer_vn_355_rank(df, window=40, rank_window=70):
        close = df['close']
        # Ulcer Index calculation
        roll_high = close.rolling(window).max()
        pct_drawdown = (close - roll_high) / roll_high * 100
        ulcer = np.sqrt((pct_drawdown ** 2).rolling(window).mean())
        # Mean of ulcer
        mean_ulcer = ulcer.rolling(rank_window).mean()
        # Condition: ulcer > mean_ulcer
        condition = ulcer > mean_ulcer
        # If true: -CsZScore(delta(close,3)) else CsZScore(linreg slope close 11)
        delta_close = close.diff(3)
        z_delta = (delta_close - delta_close.rolling(rank_window).mean()) / delta_close.rolling(rank_window).std()
        # Linreg slope using covariance
        x = pd.Series(np.arange(len(df)), index=df.index)
        y = close
        slope = y.rolling(11).cov(x) / x.rolling(11).var().replace(0, np.nan)
        z_slope = (slope - slope.rolling(rank_window).mean()) / slope.rolling(rank_window).std()
        raw = pd.Series(np.where(condition, -z_delta, z_slope), index=df.index).ffill().fillna(0)
        # Normalize type A: Rolling Rank
        result = (raw.rolling(rank_window).rank(pct=True) * 2) - 1
        return -result.ffill().fillna(0)

