        z_slope = (slope - slope.rolling(rank_window).mean()) / slope.rolling(rank_window).std()
        raw = pd.Series(np.where(condition, -z_delta, z_slope), index=df.index).ffill().fillna(0)
        # Normalize type E: Winsorized Fisher with hardcoded p2
        p2 = 63
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return -normalized.ffill().fillna(0)

