        rolling_window = window
        amt_vol_ratio = amt / volume.replace(0, np.nan)
        ts_entropy_amt = -1 * (amt_vol_ratio * (amt_vol_ratio + 1e-9).apply(np.log)).rolling(window=rolling_window, min_periods=min_periods).sum()
        ts_entropy_ret = -1 * (returns * (returns.abs() + 1e-9).apply(np.log)).rolling(window=rolling_window, min_periods=min_periods).sum()
