    @staticmethod
    def alpha_factorminer_vn_358_rank(df, window=15):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        log_volume = np.log1p(volume)
        returns = close.pct_change()
        cov = log_volume.rolling(window).cov(returns)
        var_x = returns.rolling(window).var().replace(0, np.nan)
        beta = cov / var_x
        # Residual: volume - beta * returns
        resi = log_volume - beta * returns
        # Condition: beta > 0 -> CsZScore of residual
        cond = beta > 0
        raw = pd.Series(np.where(cond, (resi - resi.expanding().mean()) / resi.expanding().std().replace(0, np.nan), -beta), index=df.index)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

