    @staticmethod
    def alpha_factorminer_vn_362_rank(df, window=5):
        close = df['close']
        # Calculate UlcerIndex(close, 31)
        max_close = close.rolling(window).max()
        pct_drawdown = (close - max_close) / max_close
        ulcer = (pct_drawdown * 100).rolling(window).mean() ** 0.5
        # Calculate Quantile of UlcerIndex over 31 periods, quantile 0.75
        q75 = ulcer.rolling(window).quantile(0.75)
        condition = ulcer > q75
        # Calculate CsZScore(Delta(close, 5))
        delta_close_5 = close.diff(5)
        mean_delta = delta_close_5.rolling(window).mean()
        std_delta = delta_close_5.rolling(window).std().replace(0, np.nan)
        cszscore_delta = (delta_close_5 - mean_delta) / std_delta
        neg_cszscore = -cszscore_delta
        # Calculate CsZScore(TsLinRegSlope(close, 17))
        days = pd.Series(np.arange(len(df)), index=df.index)
        slope_17 = close.rolling(17).cov(days) / days.rolling(17).var().replace(0, np.nan)
        mean_slope = slope_17.rolling(window).mean()
