        cszscore_slope = (slope_17 - mean_slope) / std_slope
        # Combine signal
        raw = pd.Series(np.where(condition, neg_cszscore, cszscore_slope), index=df.index)
        # Normalization type A: Rolling Rank
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

