        std_delta = delta_close_5.rolling(window).std().replace(0, np.nan)
        cszscore_delta = (delta_close_5 - mean_delta) / std_delta
        neg_cszscore = -cszscore_delta
        # Calculate CsZScore(TsLinRegSlope(close, 17))
        days = pd.Series(np.arange(len(df)), index=df.index)
        slope_17 = close.rolling(17).cov(days) / days.rolling(17).var().replace(0, np.nan)
        mean_slope = slope_17.rolling(window).mean()
        std_slope = slope_17.rolling(window).std().replace(0, np.nan)
        cszscore_slope = (slope_17 - mean_slope) / std_slope
        # Combine signal
        raw = pd.Series(np.where(condition, neg_cszscore, cszscore_slope), index=df.index)
        # Normalization type E: Winsorized Fisher (hardcoded p2=window)
        p2 = window
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
