    @staticmethod
    def alpha_factorminer_vn_364_rank(df, window=70):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        returns = close.pct_change()
        delta_vol = volume.diff(1)
        entropy_rets = -((returns / returns.rolling(window).sum() + 1e-9) * np.log(returns / returns.rolling(window).sum() + 1e-9)).rolling(window).mean()
        entropy_dvol = -((delta_vol / delta_vol.rolling(window).sum() + 1e-9) * np.log(delta_vol / delta_vol.rolling(window).sum() + 1e-9)).rolling(window).mean()
        raw = entropy_rets - entropy_dvol
        zscore = (raw - raw.rolling(window).mean()) / raw.rolling(window).std().replace(0, np.nan)
        signal = -zscore
        signal = signal.ffill().fillna(0)
        signal = (signal.rolling(window).rank(pct=True) * 2) - 1
        return signal

