    @staticmethod
    def alpha_factorminer_vn_365_rank(df, window=80):
        close = df['close']
        volume = df['matchingVolume']
        returns = close.pct_change()

        # MaxDrawdown: tính drawdown từ đỉnh
        rolling_high = close.rolling(window).max()
        drawdown = (close - rolling_high) / rolling_high

        # Quantile(drawdown, 19, 0.25)
        quantile_25 = drawdown.rolling(window).quantile(0.25)

        # Beta(returns, volume, 11)
        log_volume = np.log1p(volume)
        cov = returns.rolling(11).cov(log_volume)
        var = log_volume.rolling(11).var().replace(0, np.nan)
        beta = cov / var

        # CsZScore của beta
        beta_mean = beta.rolling(11).mean()
        beta_std = beta.rolling(11).std().replace(0, np.nan)
        csz_beta = (beta - beta_mean) / beta_std

        # Resid(returns, volume, 11): residual của regression
        vol_mean = log_volume.rolling(11).mean()
        vol_std = log_volume.rolling(11).std().replace(0, np.nan)
        vol_z = (log_volume - vol_mean) / vol_std

        ret_mean = returns.rolling(11).mean()
        ret_std = returns.rolling(11).std().replace(0, np.nan)
        ret_z = (returns - ret_mean) / ret_std

        # Beta co-với volume z-score và returns
        betaresid = returns.rolling(11).corr(log_volume) * ret_std / vol_std
        resid = returns - betaresid * log_volume

        # CsZScore của resid
        resid_mean = resid.rolling(11).mean()
        resid_std = resid.rolling(11).std().replace(0, np.nan)
        csz_resid = (resid - resid_mean) / resid_std

        # Logic chính: IfElse
        condition = drawdown > quantile_25

        # raw signal
        raw = pd.Series(np.where(condition, csz_resid, -csz_beta), index=df.index)

        # Chuẩn hóa Rolling Rank
        result = raw.rolling(window).rank(pct=True) * 2 - 1
        return -result.fillna(0)

