        raw = (std_short - std_short_median) / std_short_mad.replace(0, np.nan)
        raw = raw.replace([np.inf, -np.inf], 0).fillna(0)
        result = np.tanh(raw / raw.rolling(window).std().replace(0, np.nan))
        result = result.replace([np.inf, -np.inf], 0).fillna(0)
        return result * (-1)

