    @staticmethod
    def alpha_factorminer_vn_366_r(df, window=100, sub_window=10, p1=0.05):
        returns = (df['close'] - df['close'].shift(1)) / df['close'].shift(1).replace(0, np.nan)
        returns = returns.ffill().fillna(0)
