    @staticmethod
    def alpha_factorminer_vn_367_k(df, window=15):
        returns = df['close'].pct_change(fill_method=None)
        volume = df.get('matchingVolume', df.get('volume', 1))
        slope = returns.rolling(19).cov(pd.Series(np.arange(len(df)), index=df.index)) / pd.Series(np.arange(len(df)), index=df.index).rolling(19).var().replace(0, np.nan)
        condition = slope < 0
        beta = returns.rolling(window).cov(volume) / volume.rolling(window).var().replace(0, np.nan)
        reg_resi = returns - beta * volume
        resi_z = (reg_resi - reg_resi.rolling(window).mean()) / reg_resi.rolling(window).std().replace(0, np.nan)
        beta_z = (beta - beta.rolling(window).mean()) / beta.rolling(window).std().replace(0, np.nan)
        signal = pd.Series(np.where(condition, resi_z, beta_z), index=df.index)
        signal = signal.ffill().fillna(0)
        normalized = (signal.rolling(window).rank(pct=True) * 2) - 1
        return normalized

