    @staticmethod
    def alpha_factorminer_vn_368_k(df, window=30):
        ret = df['close'].pct_change()
        vol = df['matchingVolume'] if 'matchingVolume' in df.columns else df.get('volume', df['close'] * 0.01)
        vol_delta = vol.diff(1)
        sign_ret = np.sign(ret)
        sign_vol = np.sign(vol_delta)
        sign_same = (sign_ret == sign_vol).astype(int)
        zscore_pos = (ret - ret.rolling(11).mean()) / ret.rolling(11).std().replace(0, np.nan)
        zscore_neg = -zscore_pos
        # IfElse: sign_same -> zscore_pos else zscore_neg
        combined = pd.Series(np.where(sign_same, zscore_pos, zscore_neg), index=df.index).fillna(0)
        # Neg(CrossSectionalRank) -> series rank
        raw = combined.rolling(window).rank(pct=True) * 2 - 1
        signal = -raw
        return signal.fillna(0)

