    @staticmethod
    def alpha_factorminer_vn_369_rank(df, window=20):
        returns = df['close'].pct_change()
        volume = df['matchingVolume']
        log_volume = np.log1p(np.where(volume > 0, volume, 0))
        scaled_returns = returns / log_volume.replace(0, np.nan)
        ema_scaled = scaled_returns.ewm(span=9, adjust=False).mean()
        ema_returns = returns.ewm(span=9, adjust=False).mean()
        sub = ema_scaled - ema_returns
        neg1 = -sub
        raw = -neg1
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        signal = signal.ffill().fillna(0)
        return signal

