    @staticmethod
    def alpha_factorminer_vn_372_rank(df, window=29, quantile_window=29):
        returns = df['close'].pct_change()
        var_window = window
        prob = 0.05
        sorted_returns = returns.rolling(var_window).apply(lambda x: np.percentile(x.dropna(), prob * 100), raw=True)
        var = sorted_returns
        quantile_var = var.rolling(quantile_window).quantile(0.25)
        slope_window = 7
        # Slope calculation without lookahead
        y = returns
        x = pd.Series(np.arange(len(df)), index=df.index)
        cov = y.rolling(slope_window).cov(x)
        var_x = x.rolling(slope_window).var().replace(0, np.nan)
        slope = cov / var_x
        z_slope = (slope - slope.rolling(slope_window).mean()) / slope.rolling(slope_window).std().replace(0, np.nan)
        # Z-Score normalization of slope cross-sectionally
        z_slope_cs = (slope - slope.mean()) / slope.std().replace(0, np.nan)
        condition = var < quantile_var
        raw = pd.Series(np.where(condition, z_slope, -z_slope_cs), index=df.index).ffill().fillna(0)
        normalized = (raw.rolling(21).rank(pct=True) * 2) - 1
        return normalized.ffill().fillna(0)

