        z_close = ((delta_close - delta_close.rolling(500).mean()) / delta_close.rolling(500).std().replace(0, np.nan)).fillna(0).clip(-3, 3)
        raw = pd.Series(np.where(cond, z_amt, z_close), index=df.index)
        raw = -raw
        normalized = (raw.rolling(window_rank).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

