    @staticmethod
    def alpha_factorminer_vn_375_rank(df, window=55):
        close = df['close']
        volume = df['matchingVolume']
        returns = close.pct_change()

        # BollingerBands range
        bollinger_mid = close.rolling(window).mean()
        bollinger_std = close.rolling(window).std()
        bollinger_range = 2 * bollinger_std

        # Mean of BollingerRange
        mean_bollinger_range = bollinger_range.rolling(window).mean()

        # Condition: BollingerRange > Mean(BollingerRange, 17)
        condition = bollinger_range > mean_bollinger_range

        # Calculate components
        # CsZScore of Resid(returns, volume, 11)
        # Resid: rolling OLS residuals, we approximate using returns - beta*volume
        # Beta is calculated via covariance/variance of returns and volume over window 11
        vol_log = np.log1p(volume)
        cov_ret_vol = returns.rolling(11).cov(vol_log)
        var_vol = vol_log.rolling(11).var().replace(0, np.nan)
        beta = cov_ret_vol / var_vol
        resid = returns - beta * vol_log
        resid_zscore = (resid - resid.rolling(11).mean()) / resid.rolling(11).std()

        # CsZScore of Beta(returns, volume, 11)
        beta_zscore = (beta - beta.rolling(11).mean()) / beta.rolling(11).std()

        # Combine
        raw = -(resid_zscore.where(condition, beta_zscore))

        # Normalize method A: Rolling Rank
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        result = result.ffill().fillna(0)
        return -result

