    def alpha_factorminer_vn_378_rank(df, window=100):
        returns = df['close'].pct_change()
        slope = returns.rolling(window).mean()
        std_close = df['close'].rolling(window).std()
        resid = returns - slope
        beta = returns.rolling(window).corr(std_close) * returns.rolling(window).std() / std_close.rolling(window).std()
        condition = slope > 0
        raw = pd.Series(np.where(condition, (resid - resid.rolling(window).mean()) / resid.rolling(window).std(), (beta - beta.rolling(window).mean()) / beta.rolling(window).std()), index=df.index)
        raw = raw.fillna(0)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        signal = -normalized
        return -signal.fillna(0)

