    @staticmethod
    def alpha_factorminer_vn_380_rank(df, window=30):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        returns = close.pct_change().fillna(0)
        # Calculate correlation (Corr(returns, volume, 11))
        corr = returns.rolling(window).corr(volume)
        # Delta(close, 5)
        delta_close = close.diff(5)
        # CsZScore(delta_close) - rolling z-score with window 20 (hardcoded)
        zscore_window = 20
        cs_zscore = (delta_close - delta_close.rolling(zscore_window).mean()) / delta_close.rolling(zscore_window).std().replace(0, np.nan)
        cs_zscore = cs_zscore.fillna(0)
        # Neg(CsZScore) and CsZScore
        neg_cs_zscore = -cs_zscore
        # IfElse: if corr > 0.2 then cs_zscore else neg_cs_zscore
        raw = pd.Series(np.where(corr > 0.2, cs_zscore, neg_cs_zscore), index=df.index)
        # Neg entire result
        raw = -raw
        # Normalization: Rolling Rank (method A)
        norm_window = 20
        rank = raw.rolling(norm_window).rank(pct=True)
        signal = (rank * 2) - 1
        return signal.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_380_tanh(df, window=25):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        returns = close.pct_change().fillna(0)
        corr = returns.rolling(window).corr(volume)
        delta_close = close.diff(5)
        zscore_window = 20
        cs_zscore = (delta_close - delta_close.rolling(zscore_window).mean()) / delta_close.rolling(zscore_window).std().replace(0, np.nan)
        cs_zscore = cs_zscore.fillna(0)
        neg_cs_zscore = -cs_zscore
        raw = pd.Series(np.where(corr > 0.2, cs_zscore, neg_cs_zscore), index=df.index)
        raw = -raw
        # Normalization: Dynamic Tanh (method B) with window=20
        std_window = 20
        rolling_std = raw.rolling(std_window).std().replace(0, np.nan).ffill()
        signal = np.tanh(raw / rolling_std)
        return signal.fillna(0)

