        raw = -raw
        # Normalization: Z-score clip (method C) with window=20
        norm_window = 20
        mean = raw.rolling(norm_window).mean()
        std = raw.rolling(norm_window).std().replace(0, np.nan).ffill()
        z = (raw - mean) / std
        signal = z.clip(-1, 1)
        return signal.fillna(0)

