    @staticmethod
    def alpha_factorminer_vn_380_wf(df, window=30, p1=0.1):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        returns = close.pct_change().fillna(0)
        corr = returns.rolling(window).corr(volume)
        delta_close = close.diff(5)
        zscore_window = 20
        cs_zscore = (delta_close - delta_close.rolling(zscore_window).mean()) / delta_close.rolling(zscore_window).std().replace(0, np.nan)
        cs_zscore = cs_zscore.fillna(0)
        neg_cs_zscore = -cs_zscore
        raw = pd.Series(np.where(corr > 0.2, cs_zscore, neg_cs_zscore), index=df.index)
        raw = -raw
        # Normalization: Winsorized Fisher (method E)
        p2 = 20
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        # Fisher transform
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        signal = normalized.fillna(0)
        return signal.replace([np.inf, -np.inf], 0)

    @staticmethod
    def alpha_factorminer_vn_381_rank(df, window=19):
        close = df['close']
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        returns = close.pct_change()
        # Bollinger range: (upper - lower) / middle
        ma = close.rolling(window).mean()
        std = close.rolling(window).std()
        bollinger_range = 2 * std / ma.replace(0, np.nan)
        # Condition: BollingerRange > 0.02
        cond = bollinger_range > 0.02
        # Beta calculation
        cov = returns.rolling(13).cov(vwap.pct_change())
        var = vwap.pct_change().rolling(13).var().replace(0, np.nan)
        beta = cov / var
        # Resid calculation: returns - beta * vwap_returns
        vwap_returns = vwap.pct_change()
        resid = returns - beta * vwap_returns
        # CsZScore-like: z-score on cross-section (rolling window)
        def alpha_factorminer_vn_381_rank(series):
            mean = series.rolling(13).mean()
            std = series.rolling(13).std().replace(0, np.nan)
            return (series - mean) / std
        beta_z = cs_zscore(beta).ffill().fillna(0)
        resid_z = cs_zscore(resid).ffill().fillna(0)
        raw = np.where(cond, beta_z, -resid_z)
        # Normalization: dynamic tanh
        signal = np.tanh(pd.Series(raw, index=df.index) / pd.Series(raw, index=df.index).rolling(63).std().replace(0, np.nan))
        return signal.ffill().fillna(0)

