        # Sub: vol_rank - ret_rank
        raw = vol_rank - ret_rank
        # CsRank (cross-sectional rank) trên toàn bộ series: sử dụng rank(pct=True) trên toàn bộ
        # Trường hợp A: Rolling Rank
        # Chuẩn hóa: (raw.rolling(param).rank(pct=True) * 2) - 1
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -signal

