        ret_rank = returns.rolling(window).rank(pct=True)
        raw = vol_rank - ret_rank
        # Trường hợp C: Rolling Z-Score/Clip
        mean = raw.rolling(window).mean()
        std = raw.rolling(window).std().replace(0, np.nan)
        signal = ((raw - mean) / std).clip(None, 1)
        signal = signal.clip(-1, None)
        signal = signal.fillna(0)
