    @staticmethod
    def alpha_factorminer_vn_387_rank(df, window=20):
        # Calculate returns
        returns = df['close'].pct_change()
        # Rolling standard deviation of returns
        std_returns = returns.rolling(window).std()
        # TsRank of std_returns over same window
        tsrank_std = std_returns.rolling(window).rank(pct=True)
        # Condition: tsrank_std > 0.7
        condition = tsrank_std > 0.7
        # Delta of close over 3 periods
        delta_close = df['close'].diff(3)
        # Negative of delta, cross-sectionally scaled (here using z-score scaling with rolling window)
        neg_delta_scaled = -(delta_close - delta_close.rolling(window).mean()) / delta_close.rolling(window).std()
        neg_delta_scaled = neg_delta_scaled.replace([np.inf, -np.inf], np.nan).fillna(0)
        # TsLinRegSlope of close over window
        x = pd.Series(np.arange(window), index=range(window))
        y = df['close'].rolling(window).apply(lambda s: pd.Series(s).corr(x) * pd.Series(s).std() / x.std(), raw=True)
        # Alternative simpler and faster slope calculation using covariance
        close_series = df['close']
        slope = close_series.rolling(window).cov(x) / x.rolling(window).var().replace(0, np.nan)
        # Actually better to compute slope without future:
        # Create time index
        t = pd.Series(np.arange(len(df)), index=df.index)
        slope_clean = close_series.rolling(window).corr(t) * close_series.rolling(window).std() / t.rolling(window).std()
        # Scale slope via CsScale (z-score with rolling window)
        slope_scaled = (slope_clean - slope_clean.rolling(window).mean()) / slope_clean.rolling(window).std()
        slope_scaled = slope_scaled.replace([np.inf, -np.inf], np.nan).fillna(0)
        # IfElse
        raw = pd.Series(np.where(condition, neg_delta_scaled, slope_scaled), index=df.index)
        # Normalize to [-1,1] with case A: rolling rank
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

