    @staticmethod
    def alpha_factorminer_vn_388_wf(df, p1=0.1, p2=60):
        high_minus_close = df['high'] - df['close']
        close_minus_low = df['close'] - df['low']
        volume = df['matchingVolume']
        window_int = p2
        cond_up = high_minus_close > 0
        sum_vol_up = (volume * cond_up).rolling(window_int).sum()
        count_up = cond_up.rolling(window_int).sum()
        avg_vol_up = sum_vol_up / count_up.replace(0, np.nan)
        cond_down = close_minus_low > 0
        sum_vol_down = (volume * cond_down).rolling(window_int).sum()
        count_down = cond_down.rolling(window_int).sum()
        avg_vol_down = sum_vol_down / count_down.replace(0, np.nan)
        raw = avg_vol_up - avg_vol_down
        # Winsorized Fisher Normalization (Case E)
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        # Avoid division by zero
        denom = (high - low).replace(0, np.nan)
        ratio = (winsorized - low) / denom
        signal = np.arctanh(ratio * 1.98 - 0.99)
        return signal.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_389_rank(df, window=5):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        returns = close.pct_change()
        # Tính correlation giữa volume và returns rolling window
        vol_ret_corr = volume.rolling(window).corr(returns)
        # Tính Delta(close, 2) = close - close.shift(2)
        delta_close = close - close.shift(2)
        # Tính CsZScore của delta_close (z-score rolling window)
        cs_delta_close = (delta_close - delta_close.rolling(window).mean()) / delta_close.rolling(window).std().replace(0, np.nan)
        # Tính Delta(amt, 2) = amount - amount.shift(2)
        delta_amt = amount - amount.shift(2)
        # Tính CsZScore của delta_amt
        cs_delta_amt = (delta_amt - delta_amt.rolling(window).mean()) / delta_amt.rolling(window).std().replace(0, np.nan)
        # IfElse: if corr > 0.15 then cs_delta_close else -cs_delta_amt
        raw = pd.Series(np.where(vol_ret_corr > 0.15, cs_delta_close, -cs_delta_amt), index=df.index)
        # Neg: multiply by -1
        raw = -raw
        raw = raw.fillna(0)
        # Chuẩn hóa Rolling Rank
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -result.fillna(0)

