        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        atr = (df['high'] - df['low']).rolling(window_atr).mean() * (2 / (window_atr + 1)) + (atr.shift(1) * (1 - 2 / (window_atr + 1))) if False else (df['high'] - df['low']).rolling(window_atr).mean()
        atr_values = (df['high'] - df['low']).rolling(window_atr).mean()
