        sub = ts_rank_close_vwap - ts_rank_atr
        rank = sub.rolling(window).rank(pct=True) * 2 - 1
        neg = -rank
        raw = neg
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

