    @staticmethod
    def alpha_factorminer_vn_391_rank(df, window=100):
        high = df['high']
        low = df['low']
        close = df['close']
        tr = pd.concat([high - low, (high - close.shift(1)).abs(), (low - close.shift(1)).abs()], axis=1).max(axis=1)
        atr = tr.rolling(window).mean()
        atr_rank = atr.rolling(window).rank(pct=True)
        condition = atr_rank > 0.8
        delta_close = close.diff(2)
        z_delta = (delta_close - delta_close.rolling(window).mean()) / delta_close.rolling(window).std()
        slope = close.rolling(window).apply(lambda x: np.polyfit(np.arange(len(x)), x, 1)[0] if len(x) == window else np.nan, raw=True)
        slope_corr = slope
        z_slope = (slope_corr - slope_corr.rolling(window).mean()) / slope_corr.rolling(window).std()
        raw = pd.Series(np.where(condition, -z_delta, z_slope), index=df.index).ffill().fillna(0)
        norm = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -norm.ffill().fillna(0)

