        delta_vol = df['matchingVolume'].diff(1)
        # Beta calculation using covariance and variance
        beta_vwap = returns.rolling(window).cov(vwap) / vwap.rolling(window).var().replace(0, np.nan)
        beta_amt = returns.rolling(window).cov(amount) / amount.rolling(window).var().replace(0, np.nan)
        # Condition: if delta_vol > 0 then use beta_vwap else beta_amt
        condition = delta_vol > 0
        raw = pd.Series(np.where(condition, beta_vwap, beta_amt), index=df.index)
        # Negate the result
        raw = -raw
        # Rolling Rank Normalization (Case A)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        # Handle NaN
        normalized = normalized.ffill().fillna(0)
        return -normalized

