    @staticmethod
    def alpha_factorminer_vn_397_zscore(df, window=20, sub_window=80):
        # Tính returns
        close = df['close']
        returns = close.pct_change().fillna(0)

        # Tính Std(returns, 13) - rolling std của returns
        std_returns_13 = returns.rolling(window=window).std()

        # Tính Mean(Std(returns, 13), 29) - rolling mean của std
        mean_std_13_29 = std_returns_13.rolling(window=sub_window).mean()

        # Điều kiện: Std(returns,13) > Mean(Std(returns,13),29)
        # Volume standardization
        volume = df['matchingVolume']
        volume_log = np.log1p(volume)

        # Tính Beta(volume, returns, 7) - rolling beta
        period_beta = 7
        cov_vol_ret = volume_log.rolling(period_beta).cov(returns * 100)
        var_ret = (returns * 100).rolling(period_beta).var().replace(0, np.nan)
        beta = cov_vol_ret / var_ret
        beta = beta.fillna(0)

        # CsZScore(Beta) - cross-sectional z-score
        beta_mean = beta.expanding().mean()
        beta_std = beta.expanding().std().replace(0, np.nan)
        beta_zscore = (beta - beta_mean) / beta_std
        beta_zscore = beta_zscore.fillna(0)

        # Tính Residual(volume, returns, 7)
        # Linear regression: volume ~ returns
        x = returns * 100
        y = volume_log

        slope = y.rolling(period_beta).cov(x) / x.rolling(period_beta).var().replace(0, np.nan)
        intercept = y - slope * x

        # Tính fitted values và residuals
        intercept_ma = intercept.rolling(period_beta).mean()
        fitted = intercept_ma + slope * x
        resid = y - fitted
        resid = resid.fillna(0)

        # CsZScore(Residual)
        resid_mean = resid.expanding().mean()
        resid_std = resid.expanding().std().replace(0, np.nan)
        resid_zscore = (resid - resid_mean) / resid_std
        resid_zscore = resid_zscore.fillna(0)

        # Điều kiện
        condition = std_returns_13 > mean_std_13_29

        # IfElse: condition ? CsZScore(Beta) : CsZScore(Residual)
        raw = pd.Series(np.where(condition, beta_zscore, resid_zscore), index=df.index)

        # Neg - đảo dấu
        raw = -raw

        # Chuẩn hóa Z-Score [1, -1]
        signal = ((raw - raw.rolling(window=window*2).mean()) / raw.rolling(window=window*2).std().replace(0, np.nan)).clip(-1, 1)
        signal = signal.fillna(0)

        return -signal

    @staticmethod
    def alpha_factorminer_vn_397_rank(df, window=20, sub_window=30):
        returns = df['close'].pct_change().replace([np.inf, -np.inf], np.nan)
        volume = df.get('matchingVolume', df.get('volume', 1))
        cond = returns.rolling(window).std() > returns.rolling(sub_window).std().rolling(window).mean()
        # Roll 7 for beta and resid
        roll7 = 7
        cov = volume.rolling(roll7).cov(returns)
        var_returns = returns.rolling(roll7).var().replace(0, np.nan)
        beta = cov / var_returns
        # Raw beta z-score
        raw = beta.fillna(method='ffill').fillna(0)
        rank_beta = (raw.rolling(window).rank(pct=True) * 2) - 1
        # Resid: volume - beta * returns
        resid = volume - beta * returns
        raw_resid = resid.fillna(method='ffill').fillna(0)
        rank_resid = (raw_resid.rolling(window).rank(pct=True) * 2) - 1
        signal = pd.Series(np.where(cond, rank_beta, -rank_resid), index=df.index)
        return signal.fillna(method='ffill').fillna(0)

    @staticmethod
    def alpha_factorminer_vn_397_tanh(df, window=40, sub_window=20):
        returns = df['close'].pct_change().replace([np.inf, -np.inf], np.nan)
        volume = df.get('matchingVolume', df.get('volume', 1))
