        var_returns = returns.rolling(roll7).var().replace(0, np.nan)
        beta = cov / var_returns
        resid = volume - beta * returns
        # Dynamic Tanh for both
        beta_tanh = np.tanh(beta / (beta.rolling(window).std().replace(0, np.nan)))
        resid_tanh = np.tanh(resid / (resid.rolling(window).std().replace(0, np.nan)))
        signal = pd.Series(np.where(cond, beta_tanh, -resid_tanh), index=df.index)
        return signal.fillna(method='ffill').fillna(0)

