    @staticmethod
    def alpha_factorminer_vn_397_wf(df, window=30, sub_window=20, p1=0.05, p2=30):
        returns = df['close'].pct_change().replace([np.inf, -np.inf], np.nan)
        volume = df.get('matchingVolume', df.get('volume', 1))
        cond = returns.rolling(window).std() > returns.rolling(sub_window).std().rolling(window).mean()
        roll7 = 7
        cov = volume.rolling(roll7).cov(returns)
        var_returns = returns.rolling(roll7).var().replace(0, np.nan)
        beta = cov / var_returns
        resid = volume - beta * returns
        # Winsorized Fisher for beta
        low_beta = beta.rolling(p2).quantile(p1)
        high_beta = beta.rolling(p2).quantile(1 - p1)
        winsorized_beta = beta.clip(lower=low_beta, upper=high_beta)
        beta_norm = np.arctanh(((winsorized_beta - low_beta) / (high_beta - low_beta + 1e-9)) * 1.98 - 0.99)
        # Winsorized Fisher for resid
        low_resid = resid.rolling(p2).quantile(p1)
        high_resid = resid.rolling(p2).quantile(1 - p1)
        winsorized_resid = resid.clip(lower=low_resid, upper=high_resid)
        resid_norm = np.arctanh(((winsorized_resid - low_resid) / (high_resid - low_resid + 1e-9)) * 1.98 - 0.99)
        signal = pd.Series(np.where(cond, beta_norm, -resid_norm), index=df.index)
        return signal.fillna(method='ffill').fillna(0)

    @staticmethod
    def alpha_factorminer_vn_398_rank(df, window=30, sub_window=50):
        close = df['close']
        returns = close.pct_change()
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        volume = df.get('matchingVolume', df.get('volume', 1))
        # Tính correlation giữa amount và close
        corr_amt_close = amount.rolling(window).corr(close)
        # Kiểm tra điều kiện
        condition = corr_amt_close > 0.1
        # Tính slope (regression beta) cho returns ~ amount
        cov_ret_amt = returns.rolling(sub_window).cov(amount)
        var_amt = amount.rolling(sub_window).var().replace(0, np.nan)
        beta_amt = cov_ret_amt / var_amt
        # Tính slope cho returns ~ volume
        cov_ret_vol = returns.rolling(sub_window).cov(volume)
        var_vol = volume.rolling(sub_window).var().replace(0, np.nan)
        beta_vol = cov_ret_vol / var_vol
        # Scale rolling z-score
        scaled_beta_amt = (beta_amt - beta_amt.rolling(window).mean()) / beta_amt.rolling(window).std()
        scaled_beta_vol = (beta_vol - beta_vol.rolling(window).mean()) / beta_vol.rolling(window).std()
        # Kết hợp từng element
        raw = pd.Series(np.where(condition, scaled_beta_amt, -scaled_beta_vol), index=df.index)
        raw = raw.ffill().fillna(0)
        # Chuẩn hóa Rolling Rank A
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -signal.ffill().fillna(0)

