    @staticmethod
    def alpha_factorminer_vn_399_rank(df, window=21):
        high = df['high']
        low = df['low']
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        amount = df.get('amount', close * volume)
        ret = df['close'].pct_change()
        atr = (high - low).rolling(11).mean()
        q75 = atr.rolling(window).quantile(0.75)
        cond = atr > q75
        x = ret
        y = amount
        cov = x.rolling(13).cov(y)
        var_y = y.rolling(13).var().replace(0, np.nan)
        beta = cov / var_y
        beta_z = (beta - beta.rolling(13).mean()) / beta.rolling(13).std().replace(0, np.nan)
        x_ts = ret
        n = 13
        days = pd.Series(np.arange(len(df)), index=df.index)
        x_ts_rolling = x_ts.rolling(n)
        days_rolling = days.rolling(n)
        cov_ts = x_ts_rolling.cov(days_rolling)
        var_days = days_rolling.var().replace(0, np.nan)
        slope = cov_ts / var_days
        slope_z = (slope - slope.rolling(13).mean()) / slope.rolling(13).std().replace(0, np.nan)
        raw = np.where(cond, -beta_z, slope_z)
        raw = pd.Series(raw, index=df.index).ffill().fillna(0)
        rank_raw = raw.rolling(window).rank(pct=True)
        signal = rank_raw * 2 - 1
        return signal

    @staticmethod
    def alpha_factorminer_vn_399_tanh(df, window=21):
        high = df['high']
