    @staticmethod
    def alpha_factorminer_vn_400_wf(df: pd.DataFrame, window: int = 19, sub_window: int = 11) -> pd.Series:
        high_low = df['high'] - df['low']
        high_close_prev = (df['high'] - df['close'].shift(1)).abs()
        low_close_prev = (df['low'] - df['close'].shift(1)).abs()
        tr = pd.concat([high_low, high_close_prev, low_close_prev], axis=1).max(axis=1)
        atr = tr.rolling(sub_window).mean()
        atr_rank = atr.rolling(window).rank(pct=True)
        condition = atr_rank > 0.8
        daily_ret = df['close'].pct_change()
        amt = df.get('amount', df['close'] * df.get('matchingVolume', 1))
        amt_chg = amt.pct_change()
        cov = daily_ret.rolling(7).cov(amt_chg)
        var = amt_chg.rolling(7).var().replace(0, np.nan)
        beta = cov / var
        reg_coef = cov / var
        reg_pred = reg_coef * amt_chg
        reg_resi = daily_ret - reg_pred
        base_beta = ((beta - beta.rolling(window).mean()) / beta.rolling(window).std()).clip(-1, 1)
        base_resi = ((reg_resi - reg_resi.rolling(window).mean()) / reg_resi.rolling(window).std()).clip(-1, 1)
        raw_signal = np.where(condition, base_beta, base_resi)
        result = -pd.Series(raw_signal, index=df.index)
        # Winsorized Fisher for heavy tails
        p1 = 0.05
