    @staticmethod
    def alpha_factorminer_vn_402_rank(df, window_20=100, window_5=3):
        close = df['close']
        # UlcerIndex calculation: sqrt(mean of squared drawdowns)
        max_close_20 = close.rolling(window_20).max()
        dd_20 = (close - max_close_20) / max_close_20
        ulcer_20 = np.sqrt((dd_20 ** 2).rolling(window_20).mean())
        max_close_5 = close.rolling(window_5).max()
        dd_5 = (close - max_close_5) / max_close_5
        ulcer_5 = np.sqrt((dd_5 ** 2).rolling(window_5).mean())
        raw = - (ulcer_20.rolling(window_20).rank(pct=True) - ulcer_5.rolling(window_5).rank(pct=True))
        signal = (raw.rolling(window_20).rank(pct=True) * 2) - 1
        return -signal.fillna(0)

