    def alpha_factorminer_vn_402_tanh(df, window_20=100, window_5=20):
        close = df['close']
        max_close_20 = close.rolling(window_20).max()
        dd_20 = (close - max_close_20) / max_close_20
        ulcer_20 = np.sqrt((dd_20 ** 2).rolling(window_20).mean())
        max_close_5 = close.rolling(window_5).max()
        dd_5 = (close - max_close_5) / max_close_5
        ulcer_5 = np.sqrt((dd_5 ** 2).rolling(window_5).mean())
        raw = - (ulcer_20 - ulcer_5)
        signal = np.tanh(raw / raw.rolling(window_20).std().replace(0, np.nan))
        return signal.fillna(0)

