    @staticmethod
    def alpha_factorminer_vn_404_rank(df, window=80, sub_window=40):
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        rets = df['close'].pct_change()
        std_amt = amount.rolling(sub_window).std()
        std_rets = rets.rolling(sub_window).std()
        days = pd.Series(np.arange(len(df)), index=df.index)
        y = std_rets
        x = std_amt
        x_var = x.rolling(window).var().replace(0, np.nan)
        x_cov = y.rolling(window).cov(x)
        beta = x_cov / x_var
        beta_mean = beta.rolling(window).mean()
        beta_std = beta.rolling(window).std().replace(0, np.nan)
        cs_zscore = -(beta - beta_mean) / beta_std
        raw = cs_zscore.fillna(0).replace([np.inf, -np.inf], 0)
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -result.fillna(0)

