    @staticmethod
    def alpha_factorminer_vn_405_rank(df, window=80):
        returns = df['close'].pct_change().fillna(0)
        var_17 = returns.rolling(window).quantile(0.05)
        mean_var = var_17.rolling(31).mean()
        days = pd.Series(np.arange(len(df)), index=df.index)
        slope = returns.rolling(7).cov(days) / days.rolling(7).var().replace(0, np.nan)
        resid = returns - (slope * days)
        condition = var_17 > mean_var
        raw = pd.Series(np.where(condition, slope, resid), index=df.index)
        raw = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -raw.fillna(0)

