    @staticmethod
    def alpha_factorminer_vn_408_rank(df, window=75):
        close = df['close']
        ret = close.pct_change()
        delay_ret = ret.shift(1)
        valid = pd.concat([ret, delay_ret], axis=1).dropna().index
        corr_series = pd.Series(index=df.index, dtype=float)
        for i in range(window, len(df)):
            if i in valid:
                x = ret.iloc[i-window:i]
                y = delay_ret.iloc[i-window:i]
                if len(x) == window and len(y) == window:
                    corr_series.iloc[i] = x.corr(y)
        raw = -corr_series
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        signal = normalized.fillna(0)
        return signal

