        volume = df['matchingVolume']
        ema_vol = volume.ewm(span=7, adjust=False).mean()
        condition_high = volume > ema_vol
        condition_low = volume < ema_vol
        sum_high = ret.where(condition_high, 0).rolling(window).sum()
        sum_low = ret.where(condition_low, 0).rolling(window).sum()
        raw = - (sum_high - sum_low)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        signal = normalized.fillna(0).replace([np.inf, -np.inf], 0)
        return -signal

