    @staticmethod
    def alpha_factorminer_vn_410_rank(df, window=20, sub_window=70):
        ret = df['close'].pct_change()
        amt = df.get('amount', df['close'] * df.get('matchingVolume', 1))
        kurt_17 = ret.rolling(window).kurt()
        kurt_29_mean = kurt_17.rolling(sub_window).mean()
        cond = kurt_17 > kurt_29_mean
        # Beta
        days = pd.Series(np.arange(len(df)), index=df.index)
        x = amt
        y = ret
        cov = y.rolling(11).cov(x)
        var_x = x.rolling(11).var().replace(0, np.nan)
        beta = cov / var_x
        # RegResi: slope * x + intercept
        slope = cov / var_x
        intercept = y.rolling(11).mean() - slope * x.rolling(11).mean()
        regresi = y - (slope * x + intercept)
        # CsScale: rank pct to [-1,1]
        beta_scaled = (beta.rank(pct=True) * 2 - 1)
        regresi_scaled = (regresi.rank(pct=True) * 2 - 1)
        raw_signal = -pd.Series(np.where(cond, beta_scaled, regresi_scaled), index=df.index)
        signal = (raw_signal.rolling(window).rank(pct=True) * 2 - 1)
        return -signal.fillna(0)

