    @staticmethod
    def alpha_factorminer_vn_410_wf(df, window=40, sub_window=20, p1=0.05, p2=50):
        ret = df['close'].pct_change()
        amt = df.get('amount', df['close'] * df.get('matchingVolume', 1))
        kurt_17 = ret.rolling(window).kurt()
        kurt_29_mean = kurt_17.rolling(sub_window).mean()
        cond = kurt_17 > kurt_29_mean
        days = pd.Series(np.arange(len(df)), index=df.index)
        x = amt
        y = ret
        cov = y.rolling(11).cov(x)
        var_x = x.rolling(11).var().replace(0, np.nan)
        beta = cov / var_x
        slope = cov / var_x
        intercept = y.rolling(11).mean() - slope * x.rolling(11).mean()
        regresi = y - (slope * x + intercept)
        # Winsorized Fisher for beta
        low_b = beta.rolling(p2).quantile(p1)
        high_b = beta.rolling(p2).quantile(1 - p1)
        winsorized_b = beta.clip(lower=low_b, upper=high_b, axis=0)
        beta_fisher = np.arctanh(((winsorized_b - low_b) / (high_b - low_b + 1e-9)) * 1.98 - 0.99)
        # Winsorized Fisher for regresi
        low_r = regresi.rolling(p2).quantile(p1)
        high_r = regresi.rolling(p2).quantile(1 - p1)
        winsorized_r = regresi.clip(lower=low_r, upper=high_r, axis=0)
        regresi_fisher = np.arctanh(((winsorized_r - low_r) / (high_r - low_r + 1e-9)) * 1.98 - 0.99)
        raw_signal = -pd.Series(np.where(cond, beta_fisher, regresi_fisher), index=df.index)
        return -raw_signal.fillna(0)

