    @staticmethod
    def alpha_factorminer_vn_413_rank(df, window=70):
        ret = df['close'].pct_change()
        mean_ret = ret.rolling(7).mean()
        std_ret = ret.rolling(7).std()
        cond = mean_ret > 0
        # RegResi: resid = y - beta*x, y=returns, x=std_ret
        std_ret_filled = std_ret.replace(0, np.nan).ffill()
        beta_resi = ret.rolling(window).cov(std_ret_filled) / std_ret_filled.rolling(window).var().replace(0, np.nan)
        resid = ret - beta_resi * std_ret_filled
        # CsScale: rank(pct) * 2 - 1 within rolling window
        resid_rank = resid.rolling(window).rank(pct=True) * 2 - 1
        # RegBeta: beta with rolling window
        beta = ret.rolling(window).cov(std_ret_filled) / std_ret_filled.rolling(window).var().replace(0, np.nan)
        beta_rank = beta.rolling(window).rank(pct=True) * 2 - 1
        raw = resid_rank.where(~cond, beta_rank)
        neg_raw = -raw
        # Normalization A: Rolling rank
        result = (neg_raw.rolling(window).rank(pct=True) * 2 - 1)
        return -result

