    @staticmethod
    def alpha_factorminer_vn_414_k(df, window=80, sub_window=5):
        returns = np.log(df['close'] / df['close'].shift(1))
        delay_returns = returns.shift(1)
        corr = returns.rolling(window).corr(delay_returns)
        days = pd.Series(np.arange(len(df)), index=df.index)
        slope = days.rolling(sub_window).cov(df['close']) / days.rolling(sub_window).var().replace(0, np.nan)
