    @staticmethod
    def alpha_factorminer_vn_417_7(df, window=7):
        high = df['high']
        low = df['low']
        close = df['close']
        returns = close.pct_change()
        tr = pd.concat([high - low, (high - close.shift()).abs(), (low - close.shift()).abs()], axis=1).max(axis=1)
        atr = tr.rolling(window=window).mean()
        median_atr = atr.rolling(window=29).median()
        beta_returns = returns.rolling(window=13).apply(lambda x: x.cov(pd.Series(np.arange(len(x)), index=x.index)) / pd.Series(np.arange(len(x)), index=x.index).var(), raw=False)
        std_returns_7 = returns.rolling(window=7).std()
        reg_resi = returns.rolling(window=13).apply(lambda x: x - np.polyval(np.polyfit(np.arange(len(x)), x, 1), np.arange(len(x))), raw=False)
        cs_zscore_beta = (beta_returns - beta_returns.expanding().mean()) / beta_returns.expanding().std()
        cs_zscore_resi = (reg_resi - reg_resi.expanding().mean()) / reg_resi.expanding().std()
        condition = atr > median_atr
        result = np.where(condition, cs_zscore_beta, cs_zscore_resi)
        result = -result
        result = pd.Series(result, index=df.index).fillna(0)
        normalized = ((result - result.rolling(window=100).mean()) / result.rolling(window=100).std()).clip(-1, 1)
        return normalized.fillna(0)

