    @staticmethod
    def alpha_factorminer_vn_418_rank(df, window=75):
        returns = df['close'].pct_change()
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        n = len(df)

        ret_mean = returns.rolling(window).mean()
        ret_std = returns.rolling(window).std().replace(0, np.nan)
        ret_z = (returns - ret_mean) / ret_std
        co_kurt = ret_z ** 4 - 3
        co_skew = ret_z ** 3

        amt_mean = amt.rolling(window).mean()
        amt_std = amt.rolling(window).std().replace(0, np.nan)
        amt_z = (amt - amt_mean) / amt_std

