        co_skew_tc = co_skew * amt_z

        raw = pd.Series(np.where(co_kurt_tc > 0, -co_kurt_tc, co_skew_tc), index=df.index)
        raw_rank = raw.rolling(window).rank(pct=True)
        signal = (raw_rank * 2) - 1
        return signal.fillna(0)

