    @staticmethod
    def alpha_factorminer_vn_419_wf(df: pd.DataFrame, window: int=23, smoothing_window: int=47) -> pd.Series:
        returns = df['close'].pct_change().fillna(0)
        neg_returns = returns.where(returns < 0, 0)
        neg_returns_sq = neg_returns ** 2
        downside_std = np.sqrt(neg_returns_sq.rolling(window=window, min_periods=1).mean() * window / (window - 1))
        downsidestd_mean = downside_std.rolling(window=smoothing_window, min_periods=1).mean()
        condition = (downside_std < downsidestd_mean).fillna(False)
        # Branch 1
        delta_close_5 = df['close'].diff(5)
        cs_mean_delta = delta_close_5.rolling(window=smoothing_window, min_periods=1).mean()
        cs_std_delta = delta_close_5.rolling(window=smoothing_window, min_periods=1).std().replace(0, np.nan)
        cs_zscore_delta = (delta_close_5 - cs_mean_delta) / cs_std_delta
        neg_cszscore = -cs_zscore_delta
        # Branch 2
        days = pd.Series(np.arange(len(df)), index=df.index)
        close_series = df['close']
        y = close_series
        x = days
        x_mean = x.rolling(window=window, min_periods=1).mean()
        y_mean = y.rolling(window=window, min_periods=1).mean()
        cov = (x - x_mean) * (y - y_mean)
        cov_roll = cov.rolling(window=window, min_periods=1).sum() / (window - 1)
        var_x = ((x - x_mean) ** 2).rolling(window=window, min_periods=1).sum() / (window - 1)
        slope = cov_roll / var_x.replace(0, np.nan)
        slope_mean = slope.rolling(window=smoothing_window, min_periods=1).mean()
        slope_std = slope.rolling(window=smoothing_window, min_periods=1).std().replace(0, np.nan)
        cszscore_slope = (slope - slope_mean) / slope_std
        raw = pd.Series(np.where(condition, neg_cszscore, cszscore_slope), index=df.index)
        # Normalize using Winsorized Fisher with parameters p1=0.05 (percentile), p2 = max(window, smoothing_window)
        p1 = 0.05
        p2 = max(window, smoothing_window)
        low = raw.rolling(window=p2, min_periods=1).quantile(p1)
        high = raw.rolling(window=p2, min_periods=1).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high)
        # Fisher Transform
        r = (winsorized - low) / (high - low + 1e-9)
        r_clipped = r.clip(-0.9999, 0.9999)
        normalized = np.arctanh(r_clipped * 1.98 - 0.99)
        return normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_420_rank(df, window=1, window_factor=50):
        close = df['close']
        amt = df.get('amount', df['close'] * df.get('matchingVolume', 1))
        returns = close.pct_change()
        skew = returns.rolling(window).skew()
        corr = skew.rolling(window_factor).corr(amt.pct_change())
        beta = returns.rolling(13).cov(amt.pct_change()) / amt.pct_change().rolling(13).var().replace(0, np.nan)
        resid = (returns - beta * amt.pct_change())
        beta_scale = beta / beta.abs().mean()
        resid_scale = resid / resid.abs().mean()
        raw = np.where(corr > 0, beta_scale, resid_scale)
        raw_series = pd.Series(raw, index=df.index).ffill().fillna(0)
        signal = (raw_series.rolling(10).rank(pct=True) * 2) - 1
        return signal.fillna(0)

