    @staticmethod
    def alpha_factorminer_vn_420_wf(df, window=1, window_factor=60, winsor_quantile=0.05):
        close = df['close']
        amt = df.get('amount', df['close'] * df.get('matchingVolume', 1))
        returns = close.pct_change()
        skew = returns.rolling(window).skew()
        corr = skew.rolling(window_factor).corr(amt.pct_change())
        beta = returns.rolling(13).cov(amt.pct_change()) / amt.pct_change().rolling(13).var().replace(0, np.nan)
        resid = (returns - beta * amt.pct_change())
        beta_scale = beta / beta.abs().mean()
        resid_scale = resid / resid.abs().mean()
        raw = np.where(corr > 0, beta_scale, resid_scale)
        raw_series = pd.Series(raw, index=df.index).ffill().fillna(0)
        p1 = winsor_quantile
        p2 = 20
        low = raw_series.rolling(p2).quantile(p1)
        high = raw_series.rolling(p2).quantile(1 - p1)
        winsorized = raw_series.clip(lower=low, upper=high, axis=0)
        numerator = ((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99
        numerator = numerator.clip(-0.99, 0.99)
        signal = np.arctanh(numerator).fillna(0)
        return signal

    @staticmethod
    def alpha_factorminer_vn_421_rank(df, window=40):
        returns = df['close'].pct_change()
        volume_delta = df.get('matchingVolume', df.get('volume', 1)).diff(1)
        sign_volume_delta = np.sign(volume_delta)
        mul_returns_sign = returns * sign_volume_delta
        decay_weight = np.array([0.5 ** (window - i - 1) for i in range(window)])
        decay_weight = decay_weight / decay_weight.sum()
        decayed = mul_returns_sign.rolling(window).apply(lambda x: np.dot(x, decay_weight), raw=True)
        rank = decayed.rolling(window).rank(pct=True)
        neg_rank = -rank
        normalized = (neg_rank.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

