    @staticmethod
    def alpha_factorminer_vn_423_rank(df, window=85):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        raw = (df['close'] - vwap) / vwap.abs()
        ema_7 = raw.ewm(span=7, adjust=False).mean()
        sub = raw - ema_7
        zscore = sub.rolling(window).std().replace(0, 0)
        cs_zscore = (sub - sub.rolling(window).mean()) / (zscore + 1e-9)
        neg_cs = -cs_zscore
        neg_cs = neg_cs.ffill().fillna(0)
        return -(neg_cs.rolling(window).rank(pct=True) * 2) - 1

