    def alpha_factorminer_vn_425_rank(df, window=80, delta=7):
        ret = df['close'].pct_change()
        ts_rank = (ret.rolling(window).rank(pct=True) * 2) - 1
        condition = ts_rank < 0.3
        delta_close = df['close'].diff(delta)
        cs_scale = (delta_close - delta_close.mean()) / (delta_close.std() + 1e-9)
        cs_scale_neg = -cs_scale
        signal = pd.Series(np.where(condition, cs_scale, cs_scale_neg), index=df.index)
        return ((signal.rolling(window).rank(pct=True) * 2) - 1).fillna(0)

