    @staticmethod
    def alpha_factorminer_vn_429_wf(df, window=80, p1=0.1, p2=11):
        close = df['close']
        returns = close.pct_change()
        delta_close = close.diff(1)
        raw = np.sign(delta_close) * returns
        # Decay using rolling mean
        decay = raw.rolling(window).mean()
        # Winsorized Fisher Transform
        low = decay.rolling(p2).quantile(p1)
        high = decay.rolling(p2).quantile(1 - p1)
        winsorized = decay.clip(lower=low, upper=high)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        signal = -normalized
        signal = signal.ffill().fillna(0)
        return signal

    @staticmethod
    def alpha_factorminer_vn_430_rank(df, window=70, sub_window=3):
        close = df['close']
        # BollingerRange = (upper - lower) / middle, approximates width
        mid = close.rolling(window).mean()
        std = close.rolling(window).std()
        upper = mid + 2 * std
        lower = mid - 2 * std
        boll_width = (upper - lower) / mid

        # TsLinRegSlope(close, 10) using vectorized covariance method
        days = pd.Series(np.arange(len(df)), index=df.index)
        cov = close.rolling(sub_window).cov(days)
        var_days = days.rolling(sub_window).var().replace(0, np.nan)
        slope = cov / var_days
        slope_ranked = slope.rolling(window).rank(pct=True) * 2 - 1

        # CsZScore of slope
        z_slope = (slope - slope.rolling(window).mean()) / slope.rolling(window).std()
        z_slope = z_slope.clip(None, 0)

        # Delta(close, 1) zscore
        delta = close.diff(1)
        z_delta = (delta - delta.rolling(window).mean()) / delta.rolling(window).std()
        z_delta = z_delta.clip(None, 0)

        # IfElse condition: if boll_width < 0.1 then slope_zscore else delta_zscore
        condition = boll_width < 0.1
        raw = pd.Series(np.where(condition, z_slope, z_delta), index=df.index)

        # Negate the result
        neg_raw = -raw

        # Normalize to [-1, 1] using sign/soft (case D)
        result = np.sign(neg_raw)
        return -result.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_430_tanh(df, window=10, sub_window=3):
        close = df['close']
        mid = close.rolling(window).mean()
        std = close.rolling(window).std()
        upper = mid + 2 * std
        lower = mid - 2 * std
        boll_width = (upper - lower) / mid

        days = pd.Series(np.arange(len(df)), index=df.index)
        cov = close.rolling(sub_window).cov(days)
        var_days = days.rolling(sub_window).var().replace(0, np.nan)
        slope = cov / var_days
        z_slope = (slope - slope.rolling(window).mean()) / slope.rolling(window).std()

        delta = close.diff(1)
        z_delta = (delta - delta.rolling(window).mean()) / delta.rolling(window).std()

        condition = boll_width < 0.1
        raw = pd.Series(np.where(condition, z_slope, z_delta), index=df.index)
        neg_raw = -raw

        # Normalize via dynamic tanh (case B) to preserve magnitude
        result = np.tanh(neg_raw / neg_raw.rolling(window).std().replace(0, np.nan))
        return -result.fillna(0)

