    @staticmethod
    def alpha_factorminer_vn_443_k(df, window=95):
        close = df['close']
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        ret_close = close.pct_change(5)
        ret_vwap = vwap.pct_change(5)
        cov = ret_close.rolling(window).cov(ret_vwap)
        var_vwap = ret_vwap.rolling(window).var().replace(0, np.nan)
        slope = cov / var_vwap
        intercept = ret_close.rolling(window).mean() - slope * ret_vwap.rolling(window).mean()
        residual = ret_close - (slope * ret_vwap + intercept)
        zscore = (residual - residual.rolling(window).mean()) / residual.rolling(window).std().replace(0, np.nan)
        result = -(-zscore)
        result = (result.rolling(window).rank(pct=True) * 2) - 1
        return result.fillna(0)

