    @staticmethod
    def alpha_factorminer_vn_444_rank(df, window=20):
        bollinger_range = (df['high'].rolling(window).max() - df['low'].rolling(window).min()) / df['close'].rolling(window).mean()
        quantile_25 = bollinger_range.rolling(window).quantile(0.25)
        cond = bollinger_range < quantile_25
        delta_close_2 = df['close'].diff(2)
        z1 = (delta_close_2 - delta_close_2.rolling(window).mean()) / delta_close_2.rolling(window).std()
        neg_delta = -delta_close_2
        z2 = (neg_delta - neg_delta.rolling(window).mean()) / neg_delta.rolling(window).std()
        raw = pd.Series(np.where(cond, z1, z2), index=df.index)
        raw_neg = -raw
        normalized = (raw_neg.rolling(window).rank(pct=True) * 2) - 1
        return normalized.replace([np.inf, -np.inf], np.nan).ffill().fillna(0)

