    @staticmethod
    def alpha_factorminer_vn_448_wf(df, p1=0.1, p2=80):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        amount = df.get('amount', close * volume)
        returns = close.pct_change().fillna(0)
        amt = np.log1p(amount)
        y = returns
        x = amt
        window = 19
        cov = y.rolling(window).cov(x)
        var_x = x.rolling(window).var().replace(0, np.nan)
        regbeta = cov / var_x
        regbeta = regbeta.fillna(0)
        days = pd.Series(np.arange(len(df)), index=df.index)
        y2 = returns
        window2 = 11
        cov2 = y2.rolling(window2).cov(days)
        var_days = days.rolling(window2).var().replace(0, np.nan)
        slope = cov2 / var_days
        slope = slope.fillna(0)
        raw = regbeta * slope
        raw = raw.fillna(0)
        neg_raw = -raw
        low = neg_raw.rolling(p2).quantile(p1)
        high = neg_raw.rolling(p2).quantile(1 - p1)
        winsorized = neg_raw.clip(lower=low, upper=high, axis=0)
