    @staticmethod
    def alpha_factorminer_vn_450_0(df, window=75):
        close = df['close']
        returns = close.pct_change().fillna(0)
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))

        mean_returns = returns.rolling(window=window).mean()
        skew_returns = returns.rolling(window=window).skew()
        skew_amt_init = amt.rolling(window=window).skew()

        mean_returns_z = (mean_returns - mean_returns.rolling(window).mean()) / mean_returns.rolling(window).std().replace(0, np.nan)
        skew_returns_z = (skew_returns - skew_returns.rolling(window).mean()) / skew_returns.rolling(window).std().replace(0, np.nan)
        skew_amt_z = (skew_amt_init - skew_amt_init.rolling(window).mean()) / skew_amt_init.rolling(window).std().replace(0, np.nan)

        cond = mean_returns_z > 0
        raw = pd.Series(np.where(cond, skew_returns_z, skew_amt_z), index=df.index).fillna(0)

        return -np.tanh(raw / raw.rolling(window).std().replace(0, np.nan)).fillna(0)

