    @staticmethod
    def alpha_factorminer_vn_456_6(df, window=10):
        try:
            close = df['close']
            amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
            delta_close = close.diff(1)
            delta_amt = amt.diff(1)
            rolling_corr = delta_close.rolling(window).corr(delta_amt)
            rolling_mean = rolling_corr.rolling(window).mean()
            rolling_std = rolling_corr.rolling(window).std().replace(0, np.nan)
            zscore = (rolling_corr - rolling_mean) / rolling_std
            # Negate and then use E (Winsorized Fisher) normalization for heavy-tailed correlation z-score
            neg_zscore = -zscore
            p1 = 0.05
            p2 = window
            low = neg_zscore.rolling(p2).quantile(p1)
            high = neg_zscore.rolling(p2).quantile(1 - p1)
            winsorized = neg_zscore.clip(lower=low, upper=high, axis=0)
            normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
            signal = normalized.fillna(0)
            # Additional nan fill for initial periods
            signal = signal.replace([np.inf, -np.inf], 0).fillna(0)
            return -signal
        except Exception as e:
            return pd.Series(0, index=df.index)

