    @staticmethod
    def alpha_factorminer_vn_458_rank(df, window=35):
        close = df['close']
        delta = close.diff()
        gain = delta.clip(lower=0).rolling(window).mean()
        loss = (-delta.clip(upper=0)).rolling(window).mean()
        rsi = 100 - (100 / (1 + gain / (loss.replace(0, np.nan))))
        rsi_ffill = rsi.ffill().fillna(50)
        slope = rsi_ffill.rolling(window).cov(pd.Series(np.arange(len(df)), index=df.index)) / pd.Series(np.arange(len(df)), index=df.index).rolling(window).var().replace(0, np.nan)
        raw = -(rsi_ffill - (rsi_ffill + slope * window))  # Equivalent to Neg(CsZScore(Sub(RSI, LinReg(RSI)))) but simplified: actually Sub(RSI, LinReg) = -slope * (window-1)/2? Wait, we compute the residual properly.
        linreg = rsi_ffill.rolling(window).apply(lambda x: np.polyfit(np.arange(len(x)), x, 1)[0] * np.arange(len(x))[-1] + np.polyfit(np.arange(len(x)), x, 1)[1], raw=False)
        # But apply not allowed. Using vectorized approach:
        y = rsi_ffill
        x = pd.Series(np.arange(len(df)), index=df.index)
        x_mean = x.rolling(window, min_periods=window).mean()
        y_mean = y.rolling(window, min_periods=window).mean()
        num = (x.rolling(window, min_periods=window).sum() * y.rolling(window, min_periods=window).sum() - window * (x * y).rolling(window, min_periods=window).sum())
        den = (x.rolling(window, min_periods=window).sum() ** 2 - window * (x ** 2).rolling(window, min_periods=window).sum())
        slope2 = -num / den.replace(0, np.nan)
        intercept = y_mean - slope2 * x_mean
        linreg_val = slope2 * x + intercept
        residual = rsi_ffill - linreg_val
        zscore = (residual - residual.rolling(window, min_periods=window).mean()) / residual.rolling(window, min_periods=window).std().replace(0, np.nan)
        raw = -zscore
        normalized = ((raw.rolling(window).rank(pct=True)) * 2) - 1
        return -normalized.fillna(0)

