    @staticmethod
    def alpha_factorminer_vn_465_rank(df, window=80, delta=2):
        close = df.get('close')
        amt = df.get('amount', close * df.get('matchingVolume', df.get('volume', 1)))
        returns = close.pct_change().fillna(0)
        mean = returns.rolling(window).mean()
        std = returns.rolling(window).std().replace(0, np.nan)
        kurt = ((returns - mean) * 4).rolling(window).mean() / std ** 4 - 3
        kurt = kurt.fillna(0)
        cond = kurt > 1.5
        neg_returns = -returns
        neg_returns_zscore = (neg_returns - neg_returns.rolling(window).mean()) / neg_returns.rolling(window).std().replace(0, np.nan)
        delta_amt = amt - amt.shift(delta)
        delta_amt_zscore = (delta_amt - delta_amt.rolling(window).mean()) / delta_amt.rolling(window).std().replace(0, np.nan)
        signal = pd.Series(np.where(cond, neg_returns_zscore.fillna(0), delta_amt_zscore.fillna(0)), index=df.index)
        return -((signal.rolling(window).rank(pct=True)) * 2 - 1).fillna(0)

