    @staticmethod
    def alpha_factorminer_vn_468_rank(df, window_rank=15):
        high = df['high']
        low = df['low']
        close = df['close']
        atr = ((high - low).rolling(window_rank).mean() + (high - close).abs().rolling(window_rank).mean() + (low - close).abs().rolling(window_rank).mean()) / 3
        atr_mean = atr.rolling(window_rank).mean()
