    @staticmethod
    def alpha_factorminer_vn_471_wf(df, window=50, percentile=0.1):
        # Tính toán raw signal
        high_max = df['high'].rolling(window=5).max()
        ret_1 = df['close'].pct_change(periods=1)
        raw = pd.Series(np.where(df['close'] > high_max, -ret_1, ret_1), index=df.index)
        # Xử lý NaN
        raw = raw.fillna(0)
        # Chuẩn hóa Winsorized Fisher (Trường hợp E)
        p = percentile
        low = raw.rolling(window).quantile(p)
        high = raw.rolling(window).quantile(1 - p)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        # Fisher Transform
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        # Xử lý NaN/Inf do Arctanh
        normalized = normalized.replace([np.inf, -np.inf], np.nan).ffill().fillna(0)
        signal = normalized.clip(-1, 1)
        return signal

    @staticmethod
    def alpha_factorminer_vn_472_rank(df, window=40):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        returns = close.pct_change().fillna(0)
        std_returns = returns.rolling(window).std().replace(0, np.nan).fillna(0)
        std_returns_day = pd.Series(np.arange(len(df)), index=df.index)
        # Calculate rolling correlation: Corr(volume, std_returns, window)
        vol_mean = volume.rolling(window).mean()
        std_mean = std_returns.rolling(window).mean()
        cov = (volume * std_returns).rolling(window).mean() - vol_mean * std_mean
        vol_std = volume.rolling(window).std().replace(0, np.nan).fillna(1)
        std_std = std_returns.rolling(window).std().replace(0, np.nan).fillna(1)
        corr = cov / (vol_std * std_std)
        corr = corr.fillna(0)
        neg_corr = -corr
        # Z-score normalization
        mean_neg = neg_corr.rolling(window).mean()
        std_neg = neg_corr.rolling(window).std().replace(0, np.nan).fillna(1)
        raw = (neg_corr - mean_neg) / std_neg
        return raw.clip(-1, 1)

