    @staticmethod
    def alpha_factorminer_vn_474_rank(df, window=30, sub_window=7):
        returns = df['close'].pct_change().fillna(0)
        var_window = window
        quantile = 0.05
        sorted_returns = returns.rolling(var_window).apply(lambda x: np.sort(x)[max(0, int(len(x) * quantile) - 1)] if len(x) > 0 else np.nan, raw=True)
        var = -sorted_returns
        mean_var = var.rolling(sub_window).mean()
        condition = var > mean_var
        neg_returns = -returns
        cs_zscore_neg = (neg_returns - neg_returns.rolling(sub_window).mean()) / neg_returns.rolling(sub_window).std().replace(0, np.nan)
        cs_zscore_ret = (returns - returns.rolling(sub_window).mean()) / returns.rolling(sub_window).std().replace(0, np.nan)
        signal = pd.Series(np.where(condition, cs_zscore_neg, cs_zscore_ret), index=df.index).fillna(0)
        normalized = (signal.rolling(sub_window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

