    @staticmethod
    def alpha_factorminer_vn_475_rank(df, window=10):
        returns = df['close'].pct_change()
        volume = df['matchingVolume']
        valid = returns.notna() & volume.notna() & (volume > 0)
        days = pd.Series(np.arange(len(df)), index=df.index)
        x = days
        y = volume
        cov = y.rolling(window).cov(x)
        var_x = x.rolling(window).var().replace(0, np.nan)
        slope = cov / var_x
        x_vol = volume
        y_vol = returns
        cov_vol = x_vol.rolling(window).cov(y_vol)
        var_vol = x_vol.rolling(window).var().replace(0, np.nan)
        reg_beta = cov_vol / var_vol
        raw = reg_beta * slope
        raw = raw.fillna(0)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        normalized = normalized.fillna(0)
        return normalized

