    @staticmethod
    def alpha_factorminer_vn_477_rank(df, window=100, sub_window=40):
        close = df['close']
        volume = df['matchingVolume']
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        returns = close.pct_change()
        # RegBeta returns ~ volume
        y = returns
        x = volume
        cov = y.rolling(window).cov(x)
        var_x = x.rolling(window).var().replace(0, np.nan)
        beta = cov / var_x
        # RegResi close ~ vwap
        y2 = close
        x2 = vwap
        cov2 = y2.rolling(sub_window).cov(x2)
        var_x2 = x2.rolling(sub_window).var().replace(0, np.nan)
        slope = cov2 / var_x2
        intercept = y2.rolling(sub_window).mean() - slope * x2.rolling(sub_window).mean()
        resi = y2 - (slope * x2 + intercept)
        raw = beta * resi
        # CsZScore (rolling rank pct)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        signal = -normalized
        signal = signal.ffill().fillna(0)
        return signal

