    @staticmethod
    def alpha_factorminer_vn_479_rank(df, window_1=40, window_2=40):
        returns = df['close'].pct_change()
        std_5 = returns.rolling(window_1).std()
        std_10 = returns.rolling(window_2).std()
        # if std_5 < std_10 -> use TsZscore(returns, 3) * -1, else use TsZscore(returns, 3)
        cond = std_5 < std_10
        # compute TsZscore(returns, 3) = (returns - returns.rolling(3).mean()) / returns.rolling(3).std()
        ts_roll = returns.rolling(3)
        ts_z = (returns - ts_roll.mean()) / ts_roll.std().replace(0, np.nan)
        raw = pd.Series(np.where(cond, -ts_z, ts_z), index=df.index)
        # Neg(CsZScore(...))
        raw = -raw
        # normalize A
        result = (raw.rolling(window_1).rank(pct=True) * 2) - 1
        result = result.fillna(0)
        return -result

