    @staticmethod
    def alpha_factorminer_vn_481_wf(df, window=20, winsor_quantile=0.1):
        close = df['close']
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        max_close = close.rolling(window).max()
        pct_dd = (close - max_close) / max_close
        ulcer = (pct_dd ** 2).rolling(window).mean() ** 0.5
        ulcer_z = (ulcer - ulcer.rolling(window).mean()) / ulcer.rolling(window).std()
        neg_ulcer_z = -ulcer_z
        signal = pd.Series(np.where(close > vwap, neg_ulcer_z, ulcer_z), index=df.index)
        raw = -signal
        # Normalization Case E: Winsorized Fisher
        low = raw.rolling(window*2).quantile(winsor_quantile)
        high = raw.rolling(window*2).quantile(1 - winsor_quantile)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        norm = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return norm.fillna(0)

