        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        raw = (df['close'] - vwap) / (vwap + 1e-9)
        skew = raw.rolling(window).skew()
        result = np.tanh(skew / (skew.rolling(window).std() + 1e-9))
        result = result.ffill().fillna(0)
