    @staticmethod
    def alpha_factorminer_vn_484_wf(df, window=80, winsor_quantile=0.7):
        # Logic gốc: CsZScore(Skew(Div(Sub($close, $vwap), $vwap), 17))
        # Winsorized Fisher cho heavy tails
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        raw = (df['close'] - vwap) / (vwap + 1e-9)
        skew = raw.rolling(window).skew()

        low = skew.rolling(window).quantile(winsor_quantile)
        high = skew.rolling(window).quantile(1 - winsor_quantile)
        winsorized = skew.clip(lower=low, upper=high, axis=0)

        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        result = pd.Series(normalized, index=df.index).ffill().fillna(0)
        return -result

    @staticmethod
    def alpha_factorminer_vn_485_rank(df, window_1=30, window_2=4):
        volume_delta = df['matchingVolume'].diff(window_2)
        raw_returns = df['close'].pct_change()
        tsz_returns = (raw_returns - raw_returns.rolling(window_1).mean()) / raw_returns.rolling(window_1).std()
        neg_tsz = -tsz_returns
        mean_neg = neg_tsz.rolling(len(df)).mean()
        std_neg = neg_tsz.rolling(len(df)).std()
        csz_neg = (neg_tsz - mean_neg) / std_neg.replace(0, np.nan)
        mean_tsz = tsz_returns.rolling(len(df)).mean()
        std_tsz = tsz_returns.rolling(len(df)).std()
        csz_pos = (tsz_returns - mean_tsz) / std_tsz.replace(0, np.nan)
        signal = pd.Series(np.where(volume_delta > 0, csz_neg, csz_pos), index=df.index)
        signal = signal.ffill().fillna(0)
        rank_norm = (signal.rolling(window_1).rank(pct=True) * 2) - 1
        return rank_norm

