    @staticmethod
    def alpha_factorminer_vn_487_rank(df, window=40):
        returns = df['close'].pct_change()
        vol = df.get('matchingVolume', df.get('volume', 1))
        # Corr(returns, vol, 5)
        corr = returns.rolling(window).corr(vol).fillna(0)
        # TsLinRegSlope(returns, 11)
        y = returns
        days = pd.Series(np.arange(len(df)), index=df.index)
        x = days
        x_mean = x.rolling(11).mean()
        y_mean = y.rolling(11).mean()
        cov = (x - x_mean) * (y - y_mean)
        var_x = (x - x_mean) ** 2
        slope = (cov.rolling(11).sum() / var_x.rolling(11).sum().replace(0, np.nan)).fillna(0)
        neg_slope = -slope
        # CsZScore for slope and neg_slope (cross-sectional normalize)
        # Since no cross-section, use rolling z-score
        z_neg = ((neg_slope - neg_slope.rolling(100).mean()) / neg_slope.rolling(100).std().replace(0, np.nan)).fillna(0)
        z_slope = ((slope - slope.rolling(100).mean()) / slope.rolling(100).std().replace(0, np.nan)).fillna(0)
        raw = np.where(corr > 0, z_neg, z_slope)
        raw = pd.Series(raw, index=df.index)
        # Normalize A: rolling rank
        normalized = (raw.rolling(100).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_487_tanh(df, window=40):
        returns = df['close'].pct_change()
        vol = df.get('matchingVolume', df.get('volume', 1))
        corr = returns.rolling(window).corr(vol).fillna(0)
        y = returns
        days = pd.Series(np.arange(len(df)), index=df.index)
        x = days
        x_mean = x.rolling(11).mean()
        y_mean = y.rolling(11).mean()
        cov = (x - x_mean) * (y - y_mean)
        var_x = (x - x_mean) ** 2
        slope = (cov.rolling(11).sum() / var_x.rolling(11).sum().replace(0, np.nan)).fillna(0)
        neg_slope = -slope
        z_neg = ((neg_slope - neg_slope.rolling(100).mean()) / neg_slope.rolling(100).std().replace(0, np.nan)).fillna(0)
        z_slope = ((slope - slope.rolling(100).mean()) / slope.rolling(100).std().replace(0, np.nan)).fillna(0)
        raw = np.where(corr > 0, z_neg, z_slope)
        raw = pd.Series(raw, index=df.index)
        # Normalize B: dynamic tanh
        std = raw.rolling(100).std().replace(0, np.nan)
        normalized = np.tanh(raw / std)
        return normalized.fillna(0)

