    def alpha_factorminer_vn_489_rank(df, window_skew=40, window_slope=30):
        returns = df['close'].pct_change()
        skew = returns.rolling(window_skew).skew()
        slope = returns.rolling(window_slope).cov(pd.Series(np.arange(window_slope), index=returns.index[:window_slope])) / returns.rolling(window_slope).var().replace(0, np.nan)
        days = pd.Series(np.arange(len(df)), index=df.index)
