        slope_ts = returns.rolling(window_slope).apply(lambda x: np.polyfit(np.arange(len(x)), x, 1)[0], raw=True) if False else slope_corrected
        neg_slope = -slope_ts
        zscore_pos = ((slope_ts - slope_ts.rolling(window_slope).mean()) / slope_ts.rolling(window_slope).std()).clip(-1, 1)
        zscore_neg = ((neg_slope - neg_slope.rolling(window_slope).mean()) / neg_slope.rolling(window_slope).std()).clip(-1, 1)
        result = pd.Series(np.where(skew > 0, zscore_pos, zscore_neg), index=df.index)
        result = -result
        result = (result.rolling(window_slope).rank(pct=True) * 2) - 1
        return result.ffill().fillna(0)

