    @staticmethod
    def alpha_factorminer_vn_494_rank(df, window=100):
        close = df['close']
        high = df['high']
        low = df['low']
        returns = close.pct_change()

        ts_min_low = low.rolling(window=window, min_periods=2).min()
        ts_max_high = high.rolling(window=window, min_periods=2).max()

        denominator = (ts_max_high - ts_min_low).replace(0, np.nan)
        raw_ratio = (close - ts_min_low) / denominator

        condition = raw_ratio > 0.8
        ts_zscore = (returns - returns.rolling(window=3, min_periods=2).mean()) / returns.rolling(window=3, min_periods=2).std().replace(0, np.nan)

        raw_signal = pd.Series(np.where(condition, ts_zscore, 0), index=df.index)
        raw_signal = -raw_signal

        cs_rank = raw_signal.rolling(window=window, min_periods=2).rank(pct=True)
        normalized = (cs_rank * 2) - 1
        return -normalized.fillna(0)

