    @staticmethod
    def alpha_factorminer_vn_501_rank(df, window=7):
        volume = df['matchingVolume']
        ret = df['close'].pct_change()
        vol_z = (volume - volume.rolling(window).mean()) / volume.rolling(window).std()
        ret_z = (ret - ret.rolling(2).mean()) / ret.rolling(2).std()
        raw = -(np.where(vol_z > 2, ret_z, 0))
        # Chuẩn hóa Rolling Rank
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        return signal.fillna(0).replace([np.inf, -np.inf], 0)

