    @staticmethod
    def alpha_factorminer_vn_502_rank(df, window=95):
        close = df['close']
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        days = pd.Series(np.arange(len(df)), index=df.index)
        slope_resi = close.rolling(window).cov(days) / days.rolling(window).var().replace(0, np.nan)
        intercept_resi = close - slope_resi * days
        resid = close - (slope_resi * days + intercept_resi)
        slope_beta = vwap.rolling(window).cov(days) / days.rolling(window).var().replace(0, np.nan)
        intercept_beta = vwap - slope_beta * days
        beta = vwap.rolling(window).cov(close) / close.rolling(window).var().replace(0, np.nan)
        raw = resid - beta
        rank_raw = raw.rolling(window).rank(pct=True) * 2 - 1
        return rank_raw.fillna(0)

