    @staticmethod
    def alpha_factorminer_vn_505_rank(df, window_std=30, window_mean=90):
        returns = df['close'].pct_change()
        std_5 = returns.rolling(window_std).std()
        mean_std_20 = std_5.rolling(window_mean).mean()
        condition = std_5 > mean_std_20
        ts_zscore = (returns - returns.rolling(3).mean()) / returns.rolling(3).std()
        raw = -pd.Series(np.where(condition, ts_zscore, 0), index=df.index)
        # Chuẩn hóa A: Rolling Rank
        ranked = raw.rolling(window_mean).rank(pct=True) * 2 - 1
        signal = ranked.fillna(0)
        return -signal

    @staticmethod
    def alpha_factorminer_vn_505_tanh(df, window_std=7, window_mean=10):
        returns = df['close'].pct_change()
        std_5 = returns.rolling(window_std).std()
        mean_std_20 = std_5.rolling(window_mean).mean()
        condition = std_5 > mean_std_20
        ts_zscore = (returns - returns.rolling(3).mean()) / returns.rolling(3).std()
        raw = -pd.Series(np.where(condition, ts_zscore, 0), index=df.index)
