        std_5 = returns.rolling(window_std).std()
        mean_std_20 = std_5.rolling(window_mean).mean()
        condition = std_5 > mean_std_20
        ts_zscore = (returns - returns.rolling(3).mean()) / returns.rolling(3).std()
        raw = -pd.Series(np.where(condition, ts_zscore, 0), index=df.index)
        # Chuẩn hóa E: Winsorized Fisher
        p2 = window_mean
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        signal = normalized.fillna(0)
