    @staticmethod
    def alpha_factorminer_vn_506_rank(df, window=10, sub_window=40):
        close = df['close']
        returns = close.pct_change().fillna(0)
        cum_returns = returns.cumsum()
        z_cum = (cum_returns - cum_returns.rolling(window).mean()) / cum_returns.rolling(window).std().replace(0, np.nan)
        z_returns = (returns - returns.rolling(sub_window).mean()) / returns.rolling(sub_window).std().replace(0, np.nan)
        condition = pd.Series(np.where(z_cum > 1.5, 1, 0), index=df.index)
        result = pd.Series(np.where(condition == 1, z_returns, 0), index=df.index)
        neg_result = -result
        final = (neg_result.rolling(window).rank(pct=True) * 2) - 1
        return -final.fillna(0)

