    @staticmethod
    def alpha_factorminer_vn_510_rank(df, window=10, sub_window=40):
        # Calculate returns
        returns = df['close'].pct_change().replace([np.inf, -np.inf], np.nan)
        # Std of returns over 5 periods
        std_5 = returns.rolling(5).std().replace(0, np.nan)
        # Multiply std by volume
        mul = std_5 * df['matchingVolume']
        # TsZScore of mul over window=7
        mean_mul = mul.rolling(window).mean()
        std_mul = mul.rolling(window).std().replace(0, np.nan)
        ts_z_mul = (mul - mean_mul) / std_mul
        # If condition: ts_z_mul > 1.5 (Greater)
        condition = ts_z_mul > 1.5
        # IfElse: if condition true, TsZScore(returns, sub_window=3), else 0
        mean_ret = returns.rolling(sub_window).mean()
        std_ret = returns.rolling(sub_window).std().replace(0, np.nan)
        ts_z_ret = (returns - mean_ret) / std_ret
        if_else_result = pd.Series(np.where(condition, ts_z_ret, 0.0), index=df.index)
        # Neg: multiply by -1
        raw = -if_else_result
        # Normalization: Rolling Rank (Case A)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        normalized = normalized.fillna(0)
        return -normalized

