    @staticmethod
    def alpha_factorminer_vn_512_rank(df, window=90):
        # Calculate amount and returns
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        returns = df['close'].pct_change()

        # TsZScore(amount, 5)
        amt_z5 = (amount - amount.rolling(5).mean()) / amount.rolling(5).std().replace(0, np.nan)
        # TsZScore(returns, 3)
        ret_z3 = (returns - returns.rolling(3).mean()) / returns.rolling(3).std().replace(0, np.nan)

        # IfElse: if amt_z5 > 1.5 then ret_z3 else 0
        signal = pd.Series(np.where(amt_z5 > 1.5, ret_z3, 0), index=df.index).ffill().fillna(0)

        # Negate and Z-Score then normalize to [-1,1]
        raw = -signal
        # Rolling Rank
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -result.fillna(0)

