    @staticmethod
    def alpha_factorminer_vn_512_sign(df, window=45):
        # Calculate amount and returns
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        returns = df['close'].pct_change()

        # TsZScore(amount, 5)
