        # IfElse: if amt_z5 > 1.5 then ret_z3 else 0
        signal = pd.Series(np.where(amt_z5 > 1.5, ret_z3, 0), index=df.index).ffill().fillna(0)

        # Negate and Z-Score
        raw = -signal
        # Sign/Binary Soft - use sign of rolling rank to avoid noise
        tmp = (raw.rolling(window).rank(pct=True) * 2) - 1
