    @staticmethod
    def alpha_factorminer_vn_512_wf(df, p1=0.1, p2=10):
        # Calculate amount and returns
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        returns = df['close'].pct_change()

        # TsZScore(amount, 5)
        amt_z5 = (amount - amount.rolling(5).mean()) / amount.rolling(5).std().replace(0, np.nan)
        # TsZScore(returns, 3)
        ret_z3 = (returns - returns.rolling(3).mean()) / returns.rolling(3).std().replace(0, np.nan)

        # IfElse: if amt_z5 > 1.5 then ret_z3 else 0
        signal = pd.Series(np.where(amt_z5 > 1.5, ret_z3, 0), index=df.index).ffill().fillna(0)

        # Negate and Z-Score
        raw = -signal
        # Winsorized Fisher Transform
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        result = normalized.replace([np.inf, -np.inf], np.nan).fillna(0)
        return -result

    @staticmethod
    def alpha_factorminer_vn_513_rank(df, window=10):
        close = df['close']
        mid = close.rolling(window).mean()
        std = close.rolling(window).std()
        bb_upper = mid + 2 * std
        bb_lower = mid - 2 * std
        delta = close.diff()
        cond1 = close > bb_upper
        cond2 = close < bb_lower
        raw = pd.Series(np.where(cond1, delta, np.where(cond2, delta, 0)), index=df.index)
        raw = -raw
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -result

