    @staticmethod
    def alpha_factorminer_vn_514_wf(df, window=30, factor=0.9):
        raw = -((df['close'] - df['low']) / (df['high'] - df['low']).rolling(window).max())
        low = raw.rolling(window).quantile(factor)
        high = raw.rolling(window).quantile(1 - factor)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        denom = (high - low).replace(0, np.nan)
        normalized = np.arctanh(((winsorized - low) / denom) * 1.98 - 0.99)
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_515_k(df, window=75):
        # Calculate high - low spread
        hl = df['high'] - df['low']
        # Mean of high - low over window
        mean_hl = hl.rolling(window=window).mean()
        # Condition: (high - low) > 1.5 * mean(high-low, 11)
        cond = hl > 1.5 * mean_hl
        # Return of close (1 period)
        ret = df['close'].pct_change()
        # IfElse: cond -> -ret, else 0
        raw = pd.Series(np.where(cond, -ret, 0), index=df.index)
        # Rolling Z-score of raw
        roll_mean = raw.rolling(window=window).mean()
        roll_std = raw.rolling(window=window).std().replace(0, np.nan)
        zscore = (raw - roll_mean) / roll_std
        # Negate CsZScore (already negated in formula)
        signal = -zscore
        # Fill NaN and normalize via rolling rank to [-1,1]
        signal = signal.fillna(0)
        rank = signal.rolling(window=window).rank(pct=True)
        output = rank * 2 - 1
        return output.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_515_h(df, window=15):
        hl = df['high'] - df['low']
        mean_hl = hl.rolling(window=window).mean()
        cond = hl > 1.5 * mean_hl
        ret = df['close'].pct_change()
        raw = pd.Series(np.where(cond, -ret, 0), index=df.index)
        # Dynamic tanh normalization
        raw_std = raw.rolling(window=window).std().replace(0, np.nan)
        signal = np.tanh(raw / raw_std)
        signal = -signal  # apply Neg
        return signal.fillna(0)

