    @staticmethod
    def alpha_factorminer_vn_516_rank(df, window_rank=95):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        ema_vwap_5 = vwap.ewm(span=5, adjust=False).mean()
        sub = df['close'] - ema_vwap_5
