        mean_std = std_returns.rolling(window).mean()
        x = pd.Series(np.arange(len(df)), index=df.index)
        slope_9 = returns.rolling(9).cov(x) / x.rolling(9).var().replace(0, np.nan)
        condition = std_returns > mean_std
        raw = pd.Series(np.where(condition, slope_9, -slope_9), index=df.index)
        raw = raw.rolling(window).mean().fillna(0)
        # Rolling Rank (A)
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -signal.fillna(0)

