    @staticmethod
    def alpha_factorminer_vn_521_wf(df, window=30, quantile=0.3):
        returns = df['close'].pct_change().fillna(0)
        std_returns = returns.rolling(window).std()
        mean_std = std_returns.rolling(window).mean()
        x = pd.Series(np.arange(len(df)), index=df.index)
        slope_9 = returns.rolling(9).cov(x) / x.rolling(9).var().replace(0, np.nan)
        condition = std_returns > mean_std
        raw = pd.Series(np.where(condition, slope_9, -slope_9), index=df.index)
        raw = raw.rolling(window).mean().fillna(0)
        # Winsorized Fisher (E)
        param1 = quantile
        param2 = window
        low = raw.rolling(param2).quantile(param1)
        high = raw.rolling(param2).quantile(1 - param1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_522_rank(df, window=70):
        returns = df['close'].pct_change()
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        skew_returns = returns.rolling(window).skew()
        skew_amt = amount.rolling(window).skew()
        # IfElse: if skew_returns > 0 then skew_amt else -skew_amt
        signal = -pd.Series(np.where(skew_returns > 0, skew_amt, -skew_amt), index=df.index)
        # CsZScore: cross-sectional z-score -> rolling rank normalization A
        raw = (signal - signal.rolling(window).mean()) / signal.rolling(window).std().replace(0, np.nan)
        # Rolling rank to [-1, 1]
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -result.fillna(0)

