    @staticmethod
    def alpha_factorminer_vn_528_rank(df, window1=80, window2=10):
        close = df['close']
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        returns = close.pct_change()
        x = close - vwap
        # RegBeta(x, returns, window1): slope of returns vs x
        cov = returns.rolling(window1).cov(x)
        var_x = x.rolling(window1).var().replace(0, np.nan)
        beta = cov / var_x
        # TsLinRegSlope(returns, window2): slope of returns vs time
        days = pd.Series(np.arange(len(df)), index=df.index)
        cov2 = returns.rolling(window2).cov(days)
        var_days = days.rolling(window2).var().replace(0, np.nan)
        slope = cov2 / var_days
        raw = beta * slope
        cs_rank = raw.rolling(window1).rank(pct=True) * 2 - 1
        return cs_rank.fillna(0)

