        cov2 = returns.rolling(window2).cov(days)
        var_days = days.rolling(window2).var().replace(0, np.nan)
        slope = cov2 / var_days
        raw = beta * slope
        std_raw = raw.rolling(window1).std().replace(0, np.nan)
        normalized = np.tanh(raw / std_raw)
        return normalized.fillna(0)

