    @staticmethod
    def alpha_factorminer_vn_529_rank(df, window=5):
        # Parameters for the sub-components
        sub_window = 9  # fixed for TsZScore
        # Calculate returns
        returns = df['close'].pct_change()
        # Calculate rolling std of returns with window
        std_returns = returns.rolling(window).std()
        # Mean of std_returns over same window
        mean_std = std_returns.rolling(window).mean()
        # Condition: std_returns > mean_std
        condition = std_returns > mean_std
        # Calculate TsZScore of returns with sub_window
        zscore_returns = (returns - returns.rolling(sub_window).mean()) / returns.rolling(sub_window).std()
        # Apply if-else: if condition true -> -zscore, else -> zscore
        raw = pd.Series(np.where(condition, -zscore_returns, zscore_returns), index=df.index)
        # Normalize using Rolling Rank (Case A)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        # Fill NaN at start with 0
        normalized = normalized.fillna(0)
        return -normalized

