    @staticmethod
    def alpha_factorminer_vn_531_wf(df, window=30, quantile_factor=0.3):
        close = df['close']
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        ret = close.pct_change().fillna(0)
