        amt_log = np.log1p(amt)
        amt_std = amt_log.rolling(3).std().replace(0, np.nan)
        amt_z = (amt_log - amt_log.rolling(3).mean()) / amt_std
        corr = ret_z.rolling(window).corr(amt_z).fillna(0)
