    @staticmethod
    def alpha_factorminer_vn_532_wf(df, p1=0.9):
        # Calculate true range and ATR
        high_low = df['high'] - df['low']
        high_close = (df['high'] - df['close'].shift(1)).abs()
        low_close = (df['low'] - df['close'].shift(1)).abs()
        tr = pd.concat([high_low, high_close, low_close], axis=1).max(axis=1)
        atr_14 = tr.rolling(14).mean()
        # Condition: high - low > 1.5 * ATR
        condition = high_low > (atr_14 * 1.5)
        # Calculate returns
        returns = df['close'].pct_change()
        # TsZScore(returns, 2): rolling z-score of returns over 2 periods
        rolling_mean = returns.rolling(2).mean()
        rolling_std = returns.rolling(2).std().replace(0, np.nan)
        ts_zscore_returns = (returns - rolling_mean) / rolling_std
        # IfElse: if condition true -> -ts_zscore, else 0
        raw_signal = pd.Series(np.where(condition, -ts_zscore_returns, 0), index=df.index)
        # Winsorized Fisher normalization with hardcoded window for winsorization
        window_fisher = 20
        quantile_low = raw_signal.rolling(window_fisher).quantile(p1, interpolation='linear')
        quantile_high = raw_signal.rolling(window_fisher).quantile(1 - p1, interpolation='linear')
        winsorized = raw_signal.clip(lower=quantile_low, upper=quantile_high, axis=0)
        # Fisher Transform
        low_bound = quantile_low
        high_bound = quantile_high
        normalized_scaled = (winsorized - low_bound) / (high_bound - low_bound + 1e-9) * 1.98 - 0.99
        normalized_scaled = normalized_scaled.clip(-0.9999, 0.9999)
        normalized = np.arctanh(normalized_scaled)
        return -pd.Series(normalized.fillna(0), index=df.index)

    @staticmethod
    def alpha_factorminer_vn_533_rank(df, window=19):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        raw = df['close'] - vwap
        days = pd.Series(np.arange(len(df)), index=df.index)
        y = raw.rolling(window=window)
        x = days.rolling(window=window)
        slope = y.cov(x) / x.var().replace(0, np.nan)
        resid = raw - slope * days
        zscore = (resid - resid.rolling(window=window).mean()) / resid.rolling(window=window).std()
        result = -zscore
        normalized = (result.rolling(window=window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

