    @staticmethod
    def alpha_factorminer_vn_534_rank(df, window=100):
        close = df['close'].astype(float)
        volume = df['matchingVolume'].astype(float)
        returns = close.pct_change()

        # TsLinRegSlope cho volume và returns
        days = pd.Series(np.arange(len(df)), index=df.index)
        vol_slope = days.rolling(window).cov(volume) / volume.rolling(window).var().replace(0, np.nan)
        ret_slope = days.rolling(window).cov(returns) / returns.rolling(window).var().replace(0, np.nan)

        # IfElse logic
        cond = vol_slope > 0
        raw = pd.Series(np.where(cond, ret_slope, -ret_slope), index=df.index)

        # Neg = đảo dấu
        raw = -raw

        # Chuẩn hóa Rolling Rank (Loại A)
        signal = raw.rolling(window).rank(pct=True) * 2 - 1
        return signal.fillna(0)

