    @staticmethod
    def alpha_factorminer_vn_535_rank(df, window=15):
        close = df['close']
        delta = close.diff()
        gain = delta.clip(lower=0)
        loss = -delta.clip(upper=0)
        avg_gain = gain.ewm(span=7, min_periods=7).mean()
        avg_loss = loss.ewm(span=7, min_periods=7).mean()
        rs = avg_gain / avg_loss.replace(0, np.nan)
        rsi = 100 - (100 / (1 + rs))
        condition_gt_70 = rsi > 70
        condition_lt_30 = rsi < 30
        alpha_raw = pd.Series(np.where(condition_gt_70, rsi, np.where(condition_lt_30, -rsi, 0)), index=df.index)
        alpha_raw = -alpha_raw
        z_scores = (alpha_raw - alpha_raw.rolling(window=window, min_periods=1).mean()) / alpha_raw.rolling(window=window, min_periods=1).std().replace(0, np.nan)
        z_scores = z_scores.ffill().fillna(0)
        normalized = (z_scores.rolling(window=window).rank(pct=True) * 2) - 1
        return -normalized.ffill().fillna(0)

