    @staticmethod
    def alpha_factorminer_vn_537_wf(df, window=30, quantile_factor=0.9):
        high = df['high']
        low = df['low']
        close = df['close']
        volume = df['matchingVolume']
        cond = (high - low) / close > 0.02
        corr = close.rolling(window).corr(volume)
        raw = pd.Series(np.where(cond, corr, -corr), index=df.index)
        p2 = window
        p1 = quantile_factor
        low_q = raw.rolling(p2).quantile(p1)
        high_q = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low_q, upper=high_q, axis=0)
