    @staticmethod
    def alpha_factorminer_vn_538_rank(df, window=10):
        close = df['close']
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        returns = (df['close'] - df['close'].shift(1)) / df['close'].shift(1)
        volume = df['matchingVolume']
        # RegBeta(close, vwap, window)
        cov1 = close.rolling(window).cov(vwap)
        var1 = vwap.rolling(window).var().replace(0, np.nan)
        beta1 = cov1 / var1
        # RegBeta(returns, volume, window)
        cov2 = returns.rolling(window).cov(volume)
        var2 = volume.rolling(window).var().replace(0, np.nan)
        beta2 = cov2 / var2
        raw = beta1 * (-beta2)
        # Normalization C: Rolling Z-Score
        mean_raw = raw.rolling(window).mean()
        std_raw = raw.rolling(window).std().replace(0, np.nan)
        z = (raw - mean_raw) / std_raw
        signal = z.clip(-1, 1)
        signal = signal.ffill().fillna(0)
        return -signal

