    @staticmethod
    def alpha_factorminer_vn_541_rank(df, window=100, rank_window=40):
        close = df['close']
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        returns = close.pct_change().ffill().fillna(0)
        abs_diff = (close - vwap).abs()
        mean_abs_diff = abs_diff.rolling(window).mean()
        condition = abs_diff < mean_abs_diff
        # TsZScore equivalent
        ts_mean = returns.rolling(rank_window).mean().ffill().fillna(0)
        ts_std = returns.rolling(rank_window).std().ffill().fillna(1).replace(0, 1)
        ts_zscore = (returns - ts_mean) / ts_std
        raw = np.where(condition, -ts_zscore, 0)
        raw = pd.Series(raw, index=df.index)
        # Rolling Rank normalization
        result = raw.rolling(window).rank(pct=True) * 2 - 1
        return -result.ffill().fillna(0)

