    @staticmethod
    def alpha_factorminer_vn_541_wf(df, window=100, rank_window=30, winsor_quantile=0.05):
        close = df['close']
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        returns = close.pct_change().ffill().fillna(0)
