        slope_ret = returns.rolling(window).cov(x) / x.rolling(window).var().replace(0, np.nan)
        # Correlation giữa 2 slope
        corr = slope_vol.rolling(sub_window).corr(slope_ret)
        # CsZScore trên cross-section - nhưng ở đây là time series
        raw = -corr
        # Dynamic Tanh normalization
        std = raw.rolling(sub_window).std().replace(0, np.nan)
        signal = np.tanh(raw / std)
        return -signal.fillna(0)

