    @staticmethod
    def alpha_factorminer_vn_543_rank(df, window=60):
        close = df['close']
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        returns = close.pct_change()
        delta_close = close.diff(3)
        delta_amt = amount.diff(3)
        # Corr(Delta($close,3), Delta($amt,3), 7)
        corr_val = delta_close.rolling(window).corr(delta_amt)
        # TsLinRegSlope($returns, 7)
        # slope = Cov(y, x) / Var(x), with x = days
        days = pd.Series(np.arange(len(df)), index=df.index)
        y = returns
        x = days
        slope = y.rolling(window).cov(x) / x.rolling(window).var().replace(0, np.nan)
        raw = corr_val * slope
        raw = -raw
        # Chuẩn hóa Rolling Rank
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        result = result.ffill().fillna(0)
        return result

