        skew_returns = returns.rolling(window).skew().fillna(0)
        corr_close_volume = close.rolling(sub_window).corr(volume).fillna(0)
        condition = skew_returns > 0
        raw = pd.Series(np.where(condition, -corr_close_volume, corr_close_volume), index=df.index)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

