    @staticmethod
    def alpha_factorminer_vn_546_rank(df, window=15):
        """
        Phiên bản A: Rolling Rank
        - Chuyển đổi: Corr(returns, vwap, window) và Corr(returns, volume, window)
        - Nếu Corr(ret, vwap) > 0 thì giữ Corr(ret, volume), nếu không thì lấy âm của nó
        - Cuối cùng lấy âm (Neg) và chuẩn hóa bằng rank với window=window
        """
        returns = df['close'].pct_change().fillna(0)
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        volume = df.get('matchingVolume', df.get('volume', 1))

        # Tính correlation
        corr_ret_vwap = returns.rolling(window).corr(vwap)
        corr_ret_vol = returns.rolling(window).corr(volume)

        # Điều kiện: nếu corr_ret_vwap > 0, giữ corr_ret_vol; ngược lại lấy -corr_ret_vol
        # Sử dụng pd.Series(np.where(...)) với index từ df
        raw = pd.Series(np.where(corr_ret_vwap > 0, corr_ret_vol, -corr_ret_vol), index=df.index)

        # Chụp âm (Neg) sau đó rank để chuẩn hóa về [-1,1]
        raw_neg = -raw
        signal = (raw_neg.rolling(window).rank(pct=True) * 2) - 1
        return -signal.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_546_tanh(df, window=20):
        """
        Phiên bản B: Dynamic Tanh
        - Giữ cường độ (magnitude) của tín hiệu
        - Áp dụng np.tanh(raw / rolling std)
        """
        returns = df['close'].pct_change().fillna(0)
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        volume = df.get('matchingVolume', df.get('volume', 1))

        corr_ret_vwap = returns.rolling(window).corr(vwap)
        corr_ret_vol = returns.rolling(window).corr(volume)

        raw = pd.Series(np.where(corr_ret_vwap > 0, corr_ret_vol, -corr_ret_vol), index=df.index)
        raw_neg = -raw

        std = raw_neg.rolling(window).std().replace(0, np.nan)
        signal = np.tanh(raw_neg / std)
        return -signal.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_546_zscore(df, window=25):
        """
        Phiên bản C: Rolling Z-Score/Clip
        - Dùng cho dạng spread/oscillator
        - Chuẩn hóa: (raw - rolling mean) / rolling std, clip về [-1,1]
        """
        returns = df['close'].pct_change().fillna(0)
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        volume = df.get('matchingVolume', df.get('volume', 1))

        corr_ret_vwap = returns.rolling(window).corr(vwap)
        corr_ret_vol = returns.rolling(window).corr(volume)

        raw = pd.Series(np.where(corr_ret_vwap > 0, corr_ret_vol, -corr_ret_vol), index=df.index)
        raw_neg = -raw

        mean = raw_neg.rolling(window).mean()
        std = raw_neg.rolling(window).std().replace(0, np.nan)
        signal = ((raw_neg - mean) / std).clip(-1, 1)
        return -signal.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_546_sign(df, window=85):
        """
        Phiên bản D: Sign/Binary Soft
        - Dùng cho Breakout/Trend Follow: lấy dấu của tín hiệu
        - Giữ -1, 0, 1
        """
        returns = df['close'].pct_change().fillna(0)
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        volume = df.get('matchingVolume', df.get('volume', 1))

        corr_ret_vwap = returns.rolling(window).corr(vwap)
        corr_ret_vol = returns.rolling(window).corr(volume)

        raw = pd.Series(np.where(corr_ret_vwap > 0, corr_ret_vol, -corr_ret_vol), index=df.index)
        raw_neg = -raw

        signal = np.sign(raw_neg)
        return -signal.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_546_wf(df, window=10, quantile=0.1):
        """
        Phiên bản E: Winsorized Fisher Transform
        - Dùng cho dữ liệu heavy tails: winsorize các outlier rồi Fisher Transform
        - Tham số: window (rolling window cho quantile), quantile (tỷ lệ winsorize, mặc định 5%)
        """
        returns = df['close'].pct_change().fillna(0)
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        volume = df.get('matchingVolume', df.get('volume', 1))

        corr_ret_vwap = returns.rolling(window).corr(vwap)
        corr_ret_vol = returns.rolling(window).corr(volume)

        raw = pd.Series(np.where(corr_ret_vwap > 0, corr_ret_vol, -corr_ret_vol), index=df.index)
        raw_neg = -raw

        # Winsorize: tính low và high quantile, clip
        low = raw_neg.rolling(window).quantile(quantile)
        high = raw_neg.rolling(window).quantile(1 - quantile)
        winsorized = raw_neg.clip(lower=low, upper=high)

        # Fisher Transform: chuẩn hóa về [-1,1]
        eps = 1e-9
        norm_val = (winsorized - low) / (high - low + eps)
        fisher = np.arctanh(norm_val * 1.98 - 0.99)
        signal = fisher.clip(-1, 1)
        return -signal.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_547_rank(df, window=5):
        volume = np.log1p(df['matchingVolume'])
        returns = df['close'].pct_change().fillna(0)
        days = pd.Series(np.arange(len(df)), index=df.index)
        cov = volume.rolling(window).cov(returns)
        var = returns.rolling(window).var().replace(0, np.nan)
        beta = cov / var
        beta = beta.fillna(0)
        ma5 = returns.rolling(5).mean().fillna(0)
        ma21 = returns.rolling(21).mean().fillna(0)
        sign = np.sign(ma5 - ma21)
        raw = -(beta * sign)
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -result.fillna(0)

