    @staticmethod
    def alpha_factorminer_vn_549_rank(df, window_rank=5):
        ret = df['close'].pct_change()
        vol = df.get('matchingVolume', df.get('volume', 1)).astype(float)
        close = df['close']
        amt = df.get('amount', close * vol)

        std_ret = ret.rolling(5).std()
        median_std_ret = std_ret.rolling(5).median()

        days = pd.Series(np.arange(len(df)), index=df.index)

        cov_ret_vol = ret.rolling(43).cov(vol)
        var_vol = vol.rolling(43).var().replace(0, np.nan)
        beta_ret_vol = cov_ret_vol / var_vol

        cov_close_amt = close.rolling(43).cov(amt)
        var_amt = amt.rolling(43).var().replace(0, np.nan)
        beta_close_amt = cov_close_amt / var_amt

        condition = (std_ret > median_std_ret).astype(float)
        raw = -(condition * beta_ret_vol.fillna(0) + (1 - condition) * beta_close_amt.fillna(0))

        raw = raw.replace([np.inf, -np.inf], np.nan).ffill().fillna(0)
        signal = (raw.rolling(window_rank).rank(pct=True) * 2) - 1
        return -signal.fillna(0).replace([np.inf, -np.inf], 0)

