    @staticmethod
    def alpha_factorminer_vn_550_tanh(df, window_std=85):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        close = df['close']
        ts_z = (close - close.rolling(window=5).mean()) / close.rolling(window=5).std().replace(0, np.nan)
        raw = np.where((((close - vwap) / vwap).rolling(window=window_std).mean() > 1), -ts_z, ts_z)
        raw = pd.Series(raw, index=df.index)
        signal = np.tanh(raw / raw.rolling(window=window_std).std().replace(0, np.nan))
        return signal.fillna(0)

