        z_vwap_z = (z_vwap - z_vwap.rolling(window=window_z).mean()) / z_vwap.rolling(window=window_z).std().replace(0, np.nan)
        ts_z = (close - close.rolling(window=5).mean()) / close.rolling(window=5).std().replace(0, np.nan)
        raw = np.where(z_vwap_z > 1, -ts_z, ts_z)
        raw = pd.Series(raw, index=df.index)
