    @staticmethod
    def alpha_factorminer_vn_551_wf(df, window=10):
        ret = df['close'].pct_change().fillna(0)
        volume = df.get('matchingVolume', df.get('volume', 1))
        raw = volume.rolling(window).mean()
        std = volume.rolling(window).std().replace(0, np.nan)
        ts_zscore_vol = (volume - raw) / std
        neg_ts_zscore_ret = -((ret - ret.rolling(5).mean()) / ret.rolling(5).std().replace(0, np.nan))
        signal = pd.Series(np.where(ts_zscore_vol > 1, neg_ts_zscore_ret, 0), index=df.index).ffill().fillna(0)
        p1 = 0.1
        low = signal.rolling(window).quantile(p1)
        high = signal.rolling(window).quantile(1 - p1)
        winsorized = signal.clip(lower=low, upper=high, axis=0)
        normalized_low = low
        normalized_high = high
        normalized = np.arctanh(((winsorized - normalized_low) / (normalized_high - normalized_low + 1e-9)) * 1.98 - 0.99)
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_552_rank(df, window=10, sub_window=10):
        high_low = df['high'] - df['low']
        avg_high_low = high_low.rolling(window=window).mean()
        ratio = high_low / avg_high_low.replace(0, np.nan)
        returns = df['close'].pct_change()
        condition = ratio > 1.5
        # Calculate TsZScore(returns, 5) using rolling z-score
        roll_mean = returns.rolling(sub_window).mean()
        roll_std = returns.rolling(sub_window).std().replace(0, np.nan)
        ts_zscore = (returns - roll_mean) / roll_std
        # IfElse logic: where condition is True, use ts_zscore, else 0
        raw = pd.Series(np.where(condition, ts_zscore, 0), index=df.index)
        # CsZScore: cross-sectional z-score (currently single series, so negate and normalize)
        # Since cross-sectional is not meaningful on single series, we normalize to [-1,1] via dynamic tanh
        raw_neg = -raw
        result = np.tanh(raw_neg / raw_neg.rolling(sub_window).std().replace(0, np.nan))
        return -result.fillna(0)

