    def alpha_factorminer_vn_552_zscore(df, window=10, sub_window=10):
        high_low = df['high'] - df['low']
        avg_high_low = high_low.rolling(window=window).mean()
        ratio = high_low / avg_high_low.replace(0, np.nan)
