        raw = pd.Series(np.where(condition, ts_zscore, 0), index=df.index)
        # Negate
        raw_neg = -raw
        # Rolling Z-Score with clipping
        neg_roll_mean = raw_neg.rolling(sub_window).mean()
        neg_roll_std = raw_neg.rolling(sub_window).std().replace(0, np.nan)
        result = ((raw_neg - neg_roll_mean) / neg_roll_std).clip(-1, 1)
        return -result.fillna(0)

