        roll_mean = returns.rolling(sub_window).mean()
        roll_std = returns.rolling(sub_window).std().replace(0, np.nan)
        ts_zscore = (returns - roll_mean) / roll_std
        raw = pd.Series(np.where(condition, ts_zscore, 0), index=df.index)
        # Negate
        raw_neg = -raw
        # Winsorized Fisher Transform
        p1 = 0.05
        low = raw_neg.rolling(sub_window).quantile(p1)
        high = raw_neg.rolling(sub_window).quantile(1 - p1)
        winsorized = raw_neg.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return -normalized.fillna(0)

