    @staticmethod
    def alpha_factorminer_vn_557_rank(df, window_rank=25):
        # Tính toán raw signal
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        spread = (df['close'] - vwap) / vwap
        ts_z = (spread - spread.rolling(window_rank).mean()) / spread.rolling(window_rank).std()
        returns = df['close'].pct_change()
        # Xác định điều kiện: TsZScore(spread, 11) > 1.6
        condition = ts_z > 1.6
        # raw signal: nếu condition True -> TsZScore(returns, 5), else 0; sau đó lấy Neg (nhân -1)
        ts_z_ret = (returns - returns.rolling(5).mean()) / returns.rolling(5).std()
        raw_signal = -pd.Series(np.where(condition, ts_z_ret, 0), index=df.index)
        # CsZScore: Cross-sectional rank -> chuẩn hóa [0,1] -> [-1,1]
        rank_series = raw_signal.rolling(window_rank).rank(pct=True)
        signal = rank_series * 2 - 1
        return -signal.fillna(0)

