        high_p = raw.rolling(window).quantile(1 - per)
        winsorized = raw.clip(lower=low_p, upper=high_p, axis=0)
        normalized = np.arctanh(((winsorized - low_p) / (high_p - low_p + 1e-9)) * 1.98 - 0.99)
        return normalized.ffill().fillna(0)

