    @staticmethod
    def alpha_factorminer_vn_562_wf(df, window=10, sub_window=20):
        close = df['close']
        # TsZScore($close, 11)
        mean_11 = close.rolling(window).mean()
        std_11 = close.rolling(window).std().replace(0, np.nan)
        zscore_11 = (close - mean_11) / std_11
        # Less(TsZScore($close,11), -1.5)
        condition = zscore_11 < -1.5
        # IfElse: if condition true -> TsZScore($close,4), else 0
        mean_4 = close.rolling(4).mean()
        std_4 = close.rolling(4).std().replace(0, np.nan)
        zscore_4 = (close - mean_4) / std_4
        ifelse_result = pd.Series(np.where(condition, zscore_4, 0.0), index=df.index)
        # Neg
        neg_raw = -ifelse_result
        # Winsorized Fisher: use p1=0.05, p2=sub_window
        p1 = 0.05
        low = neg_raw.rolling(sub_window).quantile(p1)
        high = neg_raw.rolling(sub_window).quantile(1 - p1)
        winsorized = neg_raw.clip(lower=low, upper=high, axis=0)
        # Fisher transform to [-1,1]
        numerator = (winsorized - low) / (high - low + 1e-9)
        numerator_clipped = numerator.clip(0.001, 0.999)
        signal = np.arctanh(numerator_clipped * 1.98 - 0.99)
        signal = pd.Series(signal, index=df.index).ffill().fillna(0)
        return -signal

