    @staticmethod
    def alpha_factorminer_vn_565_rank(df, window=10, sub_window=3):
        raw_hl = df['high'] - df['low']
        z_hl = (raw_hl - raw_hl.rolling(window, min_periods=1).mean()) / raw_hl.rolling(window, min_periods=1).std().replace(0, np.nan)
        z_close = (df['close'] - df['close'].rolling(sub_window, min_periods=1).mean()) / df['close'].rolling(sub_window, min_periods=1).std().replace(0, np.nan)
        inner = np.where(z_hl > 2, z_close, 0)
        inner_series = pd.Series(inner, index=df.index)
