    @staticmethod
    def alpha_factorminer_vn_572_wf(df, window=90, quantile_factor=0.1):
        days_slope = pd.Series(np.arange(len(df)), index=df.index)
        p2 = int(window * 1.5) if window * 1.5 > 0 else 5
        p2 = max(p2, 20)
        close_slope_5 = df['close'].rolling(5).cov(days_slope) / days_slope.rolling(5).var().replace(0, np.nan)
        volume_slope_5 = df['matchingVolume'].rolling(5).cov(days_slope) / days_slope.rolling(5).var().replace(0, np.nan)
        corr_5 = close_slope_5.rolling(5).corr(volume_slope_5)
        zscore_num = corr_5 - corr_5.rolling(window).mean()
        zscore_denom = corr_5.rolling(window).std().replace(0, np.nan)
        raw = - (zscore_num / zscore_denom)
        low = raw.rolling(p2).quantile(quantile_factor / 2.0)
        high = raw.rolling(p2).quantile(1 - quantile_factor / 2.0)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        delta_range = high - low
        normalized = np.arctanh(((winsorized - low) / (delta_range + 1e-9)) * 1.98 - 0.99)
        return normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_573_rank(df, window=30):
        volume = df['matchingVolume']
        close = df['close']
        mean_vol_20 = volume.rolling(window).mean()
        ratio = volume / mean_vol_20
        # IfElse: if ratio > 2 then zscore(close,2) else 0
        zscore_close_2 = (close - close.rolling(2).mean()) / close.rolling(2).std().replace(0, np.nan)
        cond = ratio > 2
        raw = pd.Series(np.where(cond, zscore_close_2, 0), index=df.index)
        # Neg: multiply by -1
        raw = -raw
        # CsZScore: rolling z-score with window=20 for final normalization
        raw = (raw - raw.rolling(window).mean()) / raw.rolling(window).std()
        raw = raw.replace([np.inf, -np.inf], np.nan)
        # Rolling Rank normalization (Method A)
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        signal = signal.fillna(0)
        return -signal

