    @staticmethod
    def alpha_factorminer_vn_575_rank(df, window_rank=25):
        high = df['high']
        low = df['low']
        close = df['close']
        # Tính returns
        returns = close.pct_change().fillna(0)
        # Tính TsZScore của (high - low)
        hl_diff = high - low
        hl_zscore = (hl_diff - hl_diff.rolling(window=window_rank).mean()) / hl_diff.rolling(window=window_rank).std().replace(0, np.nan)
        hl_zscore = hl_zscore.fillna(0)
        # Tính TsZScore của returns
        ret_zscore = (returns - returns.rolling(5).mean()) / returns.rolling(5).std().replace(0, np.nan)
        ret_zscore = ret_zscore.fillna(0)
        # Áp dụng logic IfElse: nếu hl_zscore > 1.8 thì lấy ret_zscore, nếu không thì 0
        condition = hl_zscore > 1.8
        signal = np.where(condition, ret_zscore, 0.0)
        signal_series = pd.Series(signal, index=df.index)
        # Neg: đảo dấu
        raw = -signal_series
        # Normalize bằng Rolling Rank
        result = (raw.rolling(window_rank).rank(pct=True) * 2) - 1
        return -result.fillna(0).clip(-1, 1)

