    @staticmethod
    def alpha_factorminer_vn_576_rank(df, window=20, sub_window=10):
        close = df['close']
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        returns = close.pct_change().fillna(0)
        days = pd.Series(np.arange(len(df)), index=df.index)
        # RegBeta: Cov(returns, vwap, window) / Var(vwap, window)
        cov = returns.rolling(window).cov(vwap)
        var_vwap = vwap.rolling(window).var().replace(0, np.nan)
        beta = cov / var_vwap
        # TsLinRegSlope: Cov(returns, days, sub_window) / Var(days, sub_window)
        cov_ret = returns.rolling(sub_window).cov(days)
        var_days = days.rolling(sub_window).var().replace(0, np.nan)
        slope = cov_ret / var_days
        raw = -1.0 * (beta * slope)
        # Chuẩn hóa Rolling Rank: loại bỏ nhiễu
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        result = result.fillna(0)
        return -result

