        beta = cov / var_vwap
        # TsLinRegSlope
        cov_ret = returns.rolling(sub_window).cov(days)
        var_days = days.rolling(sub_window).var().replace(0, np.nan)
        slope = cov_ret / var_days
        raw = -1.0 * (beta * slope)
        # Chuẩn hóa Dynamic Tanh: giữ cường độ
        std_raw = raw.rolling(window).std().replace(0, np.nan)
        result = np.tanh(raw / std_raw)
        result = result.fillna(0)
        return -result

