        slope = returns.rolling(5).cov(days) / days.rolling(5).var().replace(0, np.nan)
        raw = corr * slope
        std = raw.rolling(window).std().replace(0, np.nan)
        normalized = np.tanh(raw / std)
        signal = -normalized
        return signal.fillna(0).clip(-1, 1)

