    @staticmethod
    def alpha_factorminer_vn_577_wf(df, window=70, winsor_percentile=0.7):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        returns = close.pct_change()
        corr = returns.rolling(window).corr(volume)
