    @staticmethod
    def alpha_factorminer_vn_578_k(df, window=40, sub_window=3):
        # Truy cập các cột với xử lý thiếu dữ liệu
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        returns = df['close'].pct_change()

        # TsZScore 1: TsZScore($amt, 13)
        mean_amt_13 = amt.rolling(window).mean()
        std_amt_13 = amt.rolling(window).std().replace(0, np.nan)
        z_amt_13 = (amt - mean_amt_13) / std_amt_13

        # Greater(TsZScore($amt, 13), 2.2)
        cond = z_amt_13 > 2.2

        # TsZScore($returns, 5)
        mean_ret_5 = returns.rolling(sub_window).mean()
        std_ret_5 = returns.rolling(sub_window).std().replace(0, np.nan)
        z_ret_5 = (returns - mean_ret_5) / std_ret_5

        # IfElse: nếu cond đúng thì z_ret_5, ngược lại 0
        ifelse_result = pd.Series(np.where(cond, z_ret_5, 0), index=df.index)

        # Neg: đổi dấu
        neg_result = -ifelse_result

        # CsZScore: Cross-sectional Z-score (rolling window size = len(df) để mô phỏng toàn bộ)
        # Sử dụng rolling với window length và xử lý NaN
        raw = neg_result
        mean_rolling = raw.rolling(window=len(df), min_periods=1).mean()
        std_rolling = raw.rolling(window=len(df), min_periods=1).std().replace(0, np.nan)
        cs_zscore = (raw - mean_rolling) / std_rolling

        # Chuẩn hóa Rolling Rank
        signal = cs_zscore.rolling(window).rank(pct=True) * 2 - 1
        signal = signal.fillna(0)
        return -signal

