        std_rolling = raw.rolling(window=len(df), min_periods=1).std().replace(0, np.nan)
        cs_zscore = (raw - mean_rolling) / std_rolling

        # Winsorized Fisher
        low = cs_zscore.rolling(p2).quantile(p1)
        high = cs_zscore.rolling(p2).quantile(1 - p1)
        winsorized = cs_zscore.clip(lower=low, upper=high, axis=0)
