    @staticmethod
    def alpha_factorminer_vn_579_rank(df, window=20, sub_window=60):
        close = df['close']
        returns = close.pct_change()
        # TsLinReg: Slope coef * time + intercept
        days = pd.Series(np.arange(len(df)), index=df.index)
        # Regression: slope = cov(x,y)/var(x)
        slope = days.rolling(window).cov(close) / days.rolling(window).var().replace(0, np.nan)
        resid = close - (slope * days + close.rolling(window).mean() - slope * days.rolling(window).mean())
        # Div resid / predicted (using slope alone as TsLinReg returns slope * days + intercept, but simpler: use resid/slope*days + intercept? Actually TsLinReg($close,29) is the fitted value)
        intercept = close.rolling(window).mean() - slope * days.rolling(window).mean()
        fitted = slope * days + intercept
        # TsLinRegResid is resid, TsLinReg is fitted
        ratio = resid / fitted.replace(0, np.nan)
        # CsRank along cross-section: use rolling rank (time series rank) - here CsRank means rank across stocks but we have one stock so time rank
        rank_ratio = ratio.rolling(window, min_periods=1).rank(pct=True)  # CsRank approximation
        # Mul with Neg(CsRank(Kurt(returns,47)))
        kurt = returns.rolling(sub_window, min_periods=1).kurt()
        rank_kurt = kurt.rolling(sub_window, min_periods=1).rank(pct=True)
        neg_rank_kurt = -rank_kurt
        mul = rank_ratio * neg_rank_kurt
        # CsZScore: rolling z-score
        zscore = (mul - mul.rolling(window).mean()) / mul.rolling(window).std().replace(0, np.nan)
        raw = -zscore
        # Normalize A: Rolling Rank
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        return signal.ffill().fillna(0).clip(-1, 1)

