    @staticmethod
    def alpha_factorminer_vn_580_zscore(df, window=70, sub_window=5):
        # Calculate returns
        returns = df['close'].pct_change().fillna(0)
        # Amount calculation with fallback
        amount = df.get('amount', df['close'] * df['matchingVolume'])
        # Rolling regression beta: Beta = cov(returns, amount) / var(amount)
        cov = returns.rolling(window).cov(amount).fillna(0)
        var_amt = amount.rolling(window).var().replace(0, np.nan).fillna(0)
        beta = cov / var_amt
        # TsZscore for close
        close_z = (df['close'] - df['close'].rolling(sub_window).mean()) / df['close'].rolling(sub_window).std().replace(0, np.nan)
        # Multiply beta with negative zscore
        raw = beta * (-close_z)
        # Chuẩn hóa TRƯỜNG HỢP C: Rolling Z-Score/Clip (phù hợp với spread/basis/oscillator - beta là dạng spread)
        raw = raw.fillna(0)
        sigma = raw.rolling(window).std().replace(0, np.nan).fillna(0)
        result = ((raw - raw.rolling(window).mean()) / sigma).clip(-1, 1)
        return result.fillna(0)

