        z_hl = (hl_range - hl_range.rolling(window).mean()) / hl_range.rolling(window).std()
        ret = close.pct_change()
        z_ret = (ret - ret.rolling(5).mean()) / ret.rolling(5).std()
        condition = hl_range > z_hl
        raw = np.where(condition, z_ret, 0)
        raw = pd.Series(raw, index=df.index) * -1
        raw = (raw - raw.rolling(window).mean()) / raw.rolling(window).std()
        raw = raw.clip(-1, 1)
        raw = raw.fillna(0).replace([np.inf, -np.inf], 0)
        return -raw

