    @staticmethod
    def alpha_factorminer_vn_584_rank(df, window=25):
        close = df['close']
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        ret = close.pct_change()
        spread = (close - vwap) / vwap
        spread_bin = (spread > 0.02).astype(int)
        zscore_ret = (ret - ret.rolling(window).mean()) / ret.rolling(window).std()
        # IfElse: if spread > 0.02 -> -zscore_ret else zscore_ret -> Neg(...)
        # Neg() -> invert sign: if spread>0.02 then zscore_ret else -zscore_ret
        signal = pd.Series(np.where(spread_bin == 1, zscore_ret, -zscore_ret), index=df.index)
        # CsZScore -> cross-sectional? For single stock, apply rolling rank normalization
        ranked = signal.rolling(window).rank(pct=True) * 2 - 1
        # Neg outside: invert final sign (already done in logic?)
        # Original has double neg? Let's check: Neg(CsZScore(IfElse(...)))?
        # Actually original Neg(CsZScore(IfElse(Greater(...), Neg(TsZScore()), TsZScore())))
        # Wait: The formula shows Neg(CsZScore(IfElse(Greater(spread,0.02), Neg(TsZScore(ret,4)), TsZScore(ret,4))))
        # So final should be: if spread>0.02 then -Neg(TsZScore) -> TsZScore, else -TsZScore (because Neg outside)
        # Let me recompute:
        # IfElse: if cond True -> Neg(TsZScore), else TsZScore
        # Neg outside applies: - (result) -> if cond True: -Neg(TsZScore)=TsZScore, else: -TsZScore
        # So: signal = np.where(cond, zscore_ret, -zscore_ret)
        # This matches current logic, negatives are correct
        return -ranked.fillna(0)

