        signal = pd.Series(np.where(spread_bin == 1, zscore_ret, -zscore_ret), index=df.index)
        # Dynamic Tanh normalization
        std_signal = signal.rolling(window).std().replace(0, np.nan)
        raw_norm = signal / std_signal
