    @staticmethod
    def alpha_factorminer_vn_590_rank(df, window=25):
        # Compute returns
        returns = df['close'].pct_change()
        # Compute amount
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        # Compute RegBeta: slope of returns vs amount
        days = pd.Series(np.arange(len(df)), index=df.index)
        # For RegBeta, we use returns as y and amount as x
        # Compute covariance and variance
        cov_beta = returns.rolling(window).cov(amount)
        var_beta = amount.rolling(window).var().replace(0, np.nan)
        regbeta = cov_beta / var_beta
        # Compute TsZScore of RegResi: residual = close - beta * vwap? Wait: RegResi($close, $vwap, 37) means residual of close vs vwap
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        # RegResi: slope of close vs vwap
        cov_resi = df['close'].rolling(window).cov(vwap)
        var_resi = vwap.rolling(window).var().replace(0, np.nan)
        slope_resi = cov_resi / var_resi
        # Predicted close
        predicted = slope_resi * vwap
        residual = df['close'] - predicted
        # TsZScore of residual
        tsz_resi = (residual - residual.rolling(window).mean()) / residual.rolling(window).std().replace(0, np.nan)
        # Multiply regbeta and tsz_resi
        prod = regbeta * tsz_resi
        # Neg and CsZScore: use rolling rank
        raw = -prod
        # Rolling Rank normalization to [-1, 1]
        normalized = (raw.rolling(window).rank(pct=True) * 2.0) - 1.0
        return normalized.fillna(0).replace([np.inf, -np.inf], 0)

