    @staticmethod
    def alpha_factorminer_vn_590_wf(df, window=20, quantile=0.9):
        # Compute returns
        returns = df['close'].pct_change()
        # Compute amount
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        # Compute RegBeta
        days = pd.Series(np.arange(len(df)), index=df.index)
        cov_beta = returns.rolling(window).cov(amount)
        var_beta = amount.rolling(window).var().replace(0, np.nan)
        regbeta = cov_beta / var_beta
        # Compute RegResi for close vs vwap
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        cov_resi = df['close'].rolling(window).cov(vwap)
        var_resi = vwap.rolling(window).var().replace(0, np.nan)
        slope_resi = cov_resi / var_resi
        predicted = slope_resi * vwap
        residual = df['close'] - predicted
        tsz_resi = (residual - residual.rolling(window).mean()) / residual.rolling(window).std().replace(0, np.nan)
        prod = regbeta * tsz_resi
        raw = -prod
        # Winsorized Fisher normalization
        p1 = quantile
        p2 = window
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        numerator = (winsorized - low)
        denominator = (high - low + 1e-9)
        ratio = numerator / denominator
        # Scale to [-0.99, 0.99] for arctanh
        scaled = ratio * 1.98 - 0.99
        # Fisher transform
        normalized = np.arctanh(scaled)
        # Clip to [-1,1]
        normalized = normalized.clip(-1, 1)
        return normalized.fillna(0).replace([np.inf, -np.inf], 0)

    @staticmethod
    def alpha_factorminer_vn_591_rank(df, window=85):
        open_delta = df['open'].diff(1)
        returns = df['close'].pct_change()
        z_open = (open_delta - open_delta.rolling(window).mean()) / open_delta.rolling(window).std()
        z_returns = (returns - returns.rolling(3).mean()) / returns.rolling(3).std()
        raw = -(z_open * z_returns)
        raw_roll_std = raw.rolling(window).std().replace(0, np.nan)
        z_raw = (raw - raw.rolling(window).mean()) / raw_roll_std
        signal = -z_raw
        signal_norm = (signal.rolling(window).rank(pct=True) * 2) - 1
        return -signal_norm

