    @staticmethod
    def alpha_factorminer_vn_596_rank(df, window=25):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        raw = pd.Series(np.where(df['close'] < vwap, -(vwap - df['close']).rolling(window).apply(lambda x: (x[-1] - x.mean()) / x.std()), (vwap - df['close']).rolling(window).apply(lambda x: (x[-1] - x.mean()) / x.std())), index=df.index)
