    @staticmethod
    def alpha_factorminer_vn_600_wf(df, p1=0.05, p2=20):
        volume = df.get('matchingVolume', 1)
        ret = df['close'].pct_change()
        raw = - (volume.rolling(5).apply(lambda x: (x - x.mean()) / x.std(), raw=True) * ret.abs().rolling(5).apply(lambda x: (x - x.mean()) / x.std(), raw=True))
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return normalized.fillna(0).replace([np.inf, -np.inf], 0)

    @staticmethod
    def alpha_factorminer_vn_601_rank(df, window=10, slope_window=10):
        close = df['close']
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        returns = close.pct_change().fillna(0)
        # RegBeta: rolling covariance of returns and amount / variance of amount
        cov = returns.rolling(window).cov(amount)
        var_amt = amount.rolling(window).var().replace(0, np.nan)
        beta = cov / var_amt
        # TsLinRegSlope of amount over slope_window
        days = pd.Series(np.arange(len(df)), index=df.index)
        slope = amount.rolling(slope_window).cov(days) / days.rolling(slope_window).var().replace(0, np.nan)
        # Mul
        raw = beta * slope
        # CsZScore (cross-sectional z-score, here we do rolling z-score as equivalent)
        raw_mean = raw.rolling(window).mean()
        raw_std = raw.rolling(window).std().replace(0, np.nan)
        zscore = (raw - raw_mean) / raw_std
        # Neg
        result = -zscore
        # Normalize to [-1,1] via rolling rank
        normalized = (result.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_601_tanh(df, window=10, slope_window=5):
        close = df['close']
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        returns = close.pct_change().fillna(0)
        cov = returns.rolling(window).cov(amount)
        var_amt = amount.rolling(window).var().replace(0, np.nan)
        beta = cov / var_amt
        days = pd.Series(np.arange(len(df)), index=df.index)
        slope = amount.rolling(slope_window).cov(days) / days.rolling(slope_window).var().replace(0, np.nan)
        raw = beta * slope
        # Neg
        result = -raw
        # Normalize to [-1,1] via dynamic tanh
        normalized = np.tanh(result / result.rolling(window).std().replace(0, np.nan))
        return -normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_601_zscore(df, window=10, slope_window=10):
        close = df['close']
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        returns = close.pct_change().fillna(0)
        cov = returns.rolling(window).cov(amount)
        var_amt = amount.rolling(window).var().replace(0, np.nan)
        beta = cov / var_amt
        days = pd.Series(np.arange(len(df)), index=df.index)
        slope = amount.rolling(slope_window).cov(days) / days.rolling(slope_window).var().replace(0, np.nan)
        raw = beta * slope
        # CsZScore (rolling z-score)
        raw_mean = raw.rolling(window).mean()
        raw_std = raw.rolling(window).std().replace(0, np.nan)
        zscore = (raw - raw_mean) / raw_std
        # Neg
        result = -zscore
        # Normalize to [-1,1] via rolling z-score clip
        mean_r = result.rolling(window).mean()
        std_r = result.rolling(window).std().replace(0, np.nan)
        normalized = ((result - mean_r) / std_r).clip(-1, 1)
        return -normalized.fillna(0)

