        raw = pd.Series(np.where(corr_close_vol > 0, -max_drawdown, max_drawdown), index=df.index)
        # Dynamic Tanh Normalization (Case B)
        norm = np.tanh(raw / (raw.rolling(sub_window).std() + 1e-9))
        signal = norm.fillna(0)
        return -signal

