        # Z-Score Clip Normalization (Case C)
        mean_ = raw.rolling(sub_window).mean()
        std_ = raw.rolling(sub_window).std()
        norm = ((raw - mean_) / (std_ + 1e-9)).clip(-1, 1)
        signal = norm.fillna(0)
