    @staticmethod
    def alpha_factorminer_vn_605_wf(df, window_rank=100, window_zscore=40, p1=0.05, p2=20):
        returns = df['close'].pct_change().replace([np.inf, -np.inf], np.nan)
        raw = returns.copy()
        abs_returns = raw.abs()
        quantile_threshold = abs_returns.rolling(window=window_rank).quantile(0.9)
        condition = abs_returns > quantile_threshold
        ts_zscore = (raw - raw.rolling(window=window_zscore).mean()) / raw.rolling(window=window_zscore).std().replace(0, np.nan)
        neg_ts_zscore = -ts_zscore
        signal = pd.Series(np.where(condition, neg_ts_zscore, 0.0), index=df.index)
        low = signal.rolling(window=p2).quantile(p1)
        high = signal.rolling(window=p2).quantile(1 - p1)
        winsorized = signal.clip(lower=low, upper=high, axis=0)
        numerator = winsorized - low
        denominator = (high - low).replace(0, np.nan)
        normalized = np.arctanh((numerator / (denominator + 1e-9)) * 1.98 - 0.99)
        return -normalized.fillna(0.0).replace([np.inf, -np.inf], 0.0)

