    def alpha_factorminer_vn_606_6(df, window=23, lr_window=11):
        # Tính returns
        returns = df['close'].pct_change()
        # Tính co-skewness giữa close và volume
        close_ts = df['close']
        vol_ts = df.get('matchingVolume', df.get('volume', 1))
        mean_c = close_ts.rolling(window).mean()
        mean_v = vol_ts.rolling(window).mean()
        # Tránh division by zero
        denom_c = close_ts.rolling(window).std().replace(0, np.nan)
        denom_v = vol_ts.rolling(window).std().replace(0, np.nan)
        std_c = denom_c.fillna(1)
        std_v = denom_v.fillna(1)
        z_c = (close_ts - mean_c) / std_c
        z_v = (vol_ts - mean_v) / std_v
        # CoSkew: E[Z_c^2 * Z_v] / sqrt(E[Z_c^4] * E[Z_v^2]) khá phức tạp
        # Dùng công thức xấp xỉ: CoSkew = E[(c - mean_c) * (v - mean_v)^2] / (std_c * std_v^2)
        # Do yêu cầu đơn giản, dùng product của z_c và z_v^2
        coskew = (z_c * z_v**2).rolling(window).mean()
        # Cross-sectional Z-score (CsZScore): mean và std trên các symbol
        def alpha_factorminer_vn_606_6(series):
            mean = series.mean()
            std = series.std()
            return (series - mean) / std.replace(0, np.nan)
        # Tính slope của returns theo time
        days = pd.Series(np.arange(len(df)), index=df.index)
        def alpha_factorminer_vn_606_6(series, w):
            x_mean = days.rolling(w).mean()
            y_mean = series.rolling(w).mean()
            cov = ((days - x_mean) * (series - y_mean)).rolling(w).mean()
            var_x = ((days - x_mean)**2).rolling(w).mean().replace(0, np.nan)
            return cov / var_x
        slopes = slope(returns, lr_window)
        neg_slopes = -slopes
        # Tạo điều kiện
        condition = coskew > 0
        # IfElse: nếu True thì CsZScore(neg_slopes), False thì CsZScore(slopes)
        raw = pd.Series(np.where(condition, cs_zscore(neg_slopes), cs_zscore(slopes)), index=df.index)
        # Forward fill NaN
        raw = raw.ffill().fillna(0)
        # Chuẩn hóa về [-1, 1] bằng Winsorized Fisher (heavy tails có thể có)
        # Dùng rolling quantile với window = 100 (hardcode do chỉ tối đa 2 param)
        p1 = 0.05
        p2 = 100
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        # Xử lý NaN từ arctanh nếu giá trị ngoài (-1,1)
        normalized = normalized.fillna(0).clip(-1, 1)
        return normalized

    @staticmethod
    def alpha_factorminer_vn_606_rank(df, window=23, reg_window=11):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        returns = close.pct_change()
        # Calculate CoSkew(close, volume, 23)
        close_std = close.rolling(window).std()
        vol_std = volume.rolling(window).std()
        coskew = ((close - close.rolling(window).mean()) ** 2 * (volume - volume.rolling(window).mean()) / (close_std ** 2 * vol_std)).rolling(window).mean()
        # TsLinRegSlope(returns, 11)
        x = pd.Series(np.arange(len(df)), index=df.index)
        slope = returns.rolling(reg_window).cov(x) / x.rolling(reg_window).var().replace(0, np.nan)
        # Negate slope
        neg_slope = -slope
        # Condition: coskew > 0
        cond = coskew > 0
        # CsZScore on each condition
        def alpha_factorminer_vn_606_rank(series):
            mu = series.mean()
            sigma = series.std()
            return (series - mu) / sigma
        positive_part = cs_zscore(neg_slope)
        negative_part = cs_zscore(slope)
        raw = pd.Series(np.where(cond, positive_part, negative_part), index=df.index).fillna(0)
        # Normalization (Rolling Rank - A)
        normalized = (raw.rolling(window).rank(pct=True) * 2 - 1).fillna(0)
        return normalized

