    @staticmethod
    def alpha_factorminer_vn_608_k(df, window_rank=50):
        close = df['close'].values
        amount = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1))).values
        returns = pd.Series(np.diff(close, prepend=close[0]) / close.clip(1e-9)).fillna(0)
        amounts = pd.Series(amount).ffill().fillna(0)
        # TsZScore của amount với window=9
        amt_mean = amounts.rolling(9).mean()
        amt_std = amounts.rolling(9).std(ddof=0).replace(0, np.nan)
        amt_z = (amounts - amt_mean) / amt_std
        # TsZScore của returns với window=2
        ret_mean = returns.rolling(2).mean()
        ret_std = returns.rolling(2).std(ddof=0).replace(0, np.nan)
        ret_z = (returns - ret_mean) / ret_std
        # IfElse: if amt_z > 1.5 then -ret_z else 0
        raw = pd.Series(np.where(amt_z > 1.5, -ret_z, 0), index=df.index)
        # Roll rank normalization
        signal = (raw.rolling(window_rank).rank(pct=True) * 2) - 1
        return -signal.fillna(0)

