        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        ret = close.pct_change(fill_method=None).fillna(0)
        amt = df.get('amount', close * df.get('matchingVolume', df.get('volume', 1)))
        # Corr(close, volume, window)
        corr_close_vol = close.rolling(window).corr(volume).fillna(0)
        # RegBeta(ret, amt, beta_window)
        cov = ret.rolling(beta_window).cov(amt)
        var_amt = amt.rolling(beta_window).var().replace(0, np.nan)
        beta = cov / var_amt
        beta = beta.fillna(0).replace([np.inf, -np.inf], 0)
        z_beta = (beta - beta.rolling(beta_window).mean()) / beta.rolling(beta_window).std().replace(0, np.nan)
        z_beta = z_beta.fillna(0).replace([np.inf, -np.inf], 0)
        neg_z_beta = -z_beta
        cond = corr_close_vol > 0
        raw = pd.Series(np.where(cond, z_beta, neg_z_beta), index=df.index)
        # Apply Neg: -raw
        result = -raw
        # Winsorized Fisher Transform (E)
        low = result.rolling(window).quantile(quantile)
        high = result.rolling(window).quantile(1 - quantile)
        winsorized = result.clip(lower=low, upper=high, axis=0)
        denominator = (high - low + 1e-9)
        scaled = ((winsorized - low) / denominator) * 1.98 - 0.99
        # Clip scaled to avoid tanh domain errors (arctanh domain (-1,1))
        scaled = scaled.clip(-0.9999, 0.9999)
        normalized = np.arctanh(scaled)
        return normalized.fillna(0)

