    def alpha_factorminer_vn_614_rank(df, window=50, sub_window=40):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        ret = close.pct_change()
        corr_vol = close.rolling(window).corr(volume)
        # RegBeta: covariance/variance
        cov = ret.rolling(sub_window).cov(vwap)
        var_vwap = vwap.rolling(sub_window).var().replace(0, np.nan)
        beta_raw = cov / var_vwap
        # CsZScore: rolling z-score
        beta_z = (beta_raw - beta_raw.rolling(sub_window).mean()) / beta_raw.rolling(sub_window).std()
        # Conditional: if corr > 0 use positive beta z, else use negative beta z
        cond = corr_vol > 0
        raw = pd.Series(np.where(cond, beta_z, -beta_z), index=df.index)
        raw = raw.ffill().fillna(0)
        # Normalize: Rolling Rank (A)
        result = (raw.rolling(sub_window).rank(pct=True) * 2) - 1
        return pd.Series(result, index=df.index).fillna(0)

