    @staticmethod
    def alpha_factorminer_vn_617_wf(df, window=90, quantile_param=0.1):
        returns = df['close'].pct_change().fillna(0)
        slope = returns.rolling(window).cov(pd.Series(np.arange(len(df)), index=df.index)) / pd.Series(np.arange(len(df)), index=df.index).rolling(window).var().replace(0, np.nan)
        skew = returns.rolling(window).skew().fillna(0)
        raw = -1.0 * (slope * skew)
        low = raw.rolling(window).quantile(quantile_param)
        high = raw.rolling(window).quantile(1 - quantile_param)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        numerator = (winsorized - low)
        denominator = (high - low + 1e-9)
        normalized = np.arctanh((numerator / denominator) * 1.98 - 0.99)
        return normalized.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_618_rank(df, window=60):
        close = df['close']
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        days = pd.Series(np.arange(len(df)), index=df.index)
        slope_close = days.rolling(13).cov(close) / close.rolling(13).var().replace(0, np.nan)
        slope_vwap = days.rolling(13).cov(vwap) / vwap.rolling(13).var().replace(0, np.nan)
        # Tính RegResi: residual của slope_vwap ~ slope_close trên cửa sổ 9
        slope_close_roll = slope_close.rolling(window)
        slope_vwap_roll = slope_vwap.rolling(window)
        cov = slope_close_roll.cov(slope_vwap)
        var_slope_close = slope_close.rolling(window).var().replace(0, np.nan)
        beta = cov / var_slope_close
        residual = slope_vwap - beta * slope_close
        # CsZScore: rolling zscore của residual trên cùng window
        mean_res = residual.rolling(window).mean()
        std_res = residual.rolling(window).std().replace(0, np.nan)
        raw = (residual - mean_res) / std_res
        normalized = ((raw - raw.rolling(window).mean()) / raw.rolling(window).std()).clip(-1, 1)
        result = -normalized
        return result.fillna(0)

