    @staticmethod
    def alpha_factorminer_vn_619_rank(df, window=45):
        high = df['high']
        low = df['low']
        close = df['close']
        ret = close.diff() / close.shift()
        # Calculate raw alpha: Neg(CsZScore(Neg(Mul(TsZScore(Div(Sub($high, $low), $close), 3), TsZScore($returns, 3)))))
        # Step inside: Div(Sub($high, $low), $close)
        h_l_div_c = (high - low) / close
        # TsZScore(h_l_div_c, 3)
        raw_h_l = (h_l_div_c - h_l_div_c.rolling(3).mean()) / h_l_div_c.rolling(3).std()
        # TsZScore($returns, 3)
        raw_ret = (ret - ret.rolling(3).mean()) / ret.rolling(3).std()
        # Mul
        mul_raw = raw_h_l * raw_ret
        # Neg(Mul) => -mul_raw
        neg_mul = -mul_raw
        # CsZScore on neg_mul (cross-sectional Z-score - but since it's time series, we treat as simple standardization over full series)
        # Since it's a single stock, CsZScore = z-score over whole series = (neg_mul - mean)/std
        raw = (neg_mul - neg_mul.mean()) / neg_mul.std()
        # Neg again => -raw
        raw = -raw
        # Normalize by rolling rank (A)
        norm = (raw.rolling(window).rank(pct=True) * 2) - 1
        return norm.fillna(0)

    @staticmethod
    def alpha_factorminer_vn_619_tanh(df, factor=5):
        high = df['high']
        low = df['low']
        close = df['close']
        ret = close.diff() / close.shift()
        h_l_div_c = (high - low) / close
        raw_h_l = (h_l_div_c - h_l_div_c.rolling(3).mean()) / h_l_div_c.rolling(3).std()
        raw_ret = (ret - ret.rolling(3).mean()) / ret.rolling(3).std()
        mul_raw = raw_h_l * raw_ret
        neg_mul = -mul_raw
        raw = (neg_mul - neg_mul.mean()) / neg_mul.std()
        raw = -raw
        # Normalize by dynamic tanh with factor as scaling window (using rolling std for magnitude)
        window = max(20, int(abs(factor) * 10))
        norm = np.tanh(raw / raw.rolling(window).std())
        return norm.fillna(0)

