        # Chuan hoa lai std_neg de CsZScore
        std_neg_mean = std_neg.rolling(sub_window).mean()
        std_neg_std = std_neg.rolling(sub_window).std().replace(0, np.nan)
        std_neg_z = (std_neg - std_neg_mean) / std_neg_std
        std_pos_mean = std_pos.rolling(sub_window).mean()
        std_pos_std = std_pos.rolling(sub_window).std().replace(0, np.nan)
        std_pos_z = (std_pos - std_pos_mean) / std_pos_std
        condition = skew > 0
        raw = pd.Series(np.where(condition, std_pos_z, std_neg_z), index=df.index)
        raw = -raw
        raw = raw.ffill().fillna(0)
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -result

