    @staticmethod
    def alpha_factorminer_vn_622_rank(df, window_rank=30):
        ret = df['close'].pct_change()
        delta_ret = ret.diff(1)
        ts_z_delta = (delta_ret - delta_ret.rolling(window=window_rank).mean()) / delta_ret.rolling(window=window_rank).std()
        ts_z_ret = (ret - ret.rolling(window=3).mean()) / ret.rolling(window=3).std()
        mul = ts_z_delta * ts_z_ret
        neg = -mul
        raw = neg
        # Normalize A: Rolling Rank
        normalized = (raw.rolling(window=window_rank).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

