    @staticmethod
    def alpha_factorminer_vn_623_rank(df, window=31):
        close = df['close']
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        amt = df.get('amount', df['close'] * df.get('matchingVolume', df.get('volume', 1)))
        ret = close.pct_change()
        amt_rank = amt.rank(pct=True)
        # Calculate correlation between returns and amount dynamically using rolling rank
        days = pd.Series(np.arange(len(df)), index=df.index)
        # Use vectorized rolling covariance and variance
        ret_rolling = ret.rolling(window)
        amt_rolling = amt_rank.rolling(window)
        cov = ret_rolling.cov(amt_rolling)
        var_ret = ret.rolling(window).var().replace(0, np.nan)
        var_amt = amt_rolling.var().replace(0, np.nan)
        corr = cov / np.sqrt(var_ret * var_amt)
        # RegResi: regression residual of returns vs vwap using sliding window feature
        # Simplified: residual = returns - beta * vwap_change, where beta = covariance(ret, vwap_ch) / var(vwap_ch)
        vwap_ch = vwap.pct_change()
        cov_rv = ret.rolling(13).cov(vwap_ch)
        var_vw = vwap_ch.rolling(13).var().replace(0, np.nan)
        beta = cov_rv / var_vw
        resi = ret - beta * vwap_ch
        # CsZScore for resi and negative resi
        def alpha_factorminer_vn_623_rank(series):
            mu = series.mean()
            sigma = series.std()
            return (series - mu) / sigma.replace(0, np.nan)
        raw = np.where(corr > 0, cs_zscore(resi), cs_zscore(-resi))
        raw = pd.Series(raw, index=df.index)
        # Normalization A: Rolling Rank
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return normalized.ffill().fillna(0)

