    def alpha_factorminer_vn_624_rank(df, window=60, sub_window=5):
        close = df['close']
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        returns = (close - close.shift(1)) / close.shift(1).replace(0, np.nan)
        days = pd.Series(np.arange(len(df)), index=df.index)
        slope1 = returns.rolling(window).corr(days) * returns.rolling(window).std() / days.rolling(window).std().replace(0, np.nan)
