        zscore_resid = (resid - resid.rolling(sub_window).mean()) / resid.rolling(sub_window).std().replace(0, np.nan)
        raw = -zscore_resid
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        return signal.fillna(0)

